/* AUTO-GENERATED — Kentucky Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["KY"] = {"code":"KY","name":"Kentucky","agency":"Kentucky KYTC","agencyShort":"KYTC","handbook":"https://drive.ky.gov/Drivers/Pages/CDL.aspx","links":{},"en":[{"q":"On Kentucky Interstate and designated highways, what is the maximum legal width of a commercial vehicle (excluding approved safety appurtenances such as mirrors)?","options":["8 feet 3 inches (99 inches)","8 feet 6 inches (102 inches)","8 feet 0 inches (96 inches)","9 feet 0 inches (108 inches)"],"answer":1,"explanation":"Kentucky limits vehicle width to 8 feet 6 inches (102 inches) on Interstate and designated highways, matching 23 CFR 658. Source: Kentucky DRIVE (KYTC) Legal Dimensions page; KRS 189.221/189.222.","handbook":"","hbref":""},{"q":"What is the maximum legal vehicle width on Kentucky state-maintained highways that are NOT Interstate or otherwise designated highways?","options":["8 feet (96 inches)","8 feet 6 inches (102 inches)","7 feet 6 inches (90 inches)","9 feet (108 inches)"],"answer":0,"explanation":"On non-designated state-maintained roads in Kentucky the legal width drops to 8 feet (96 inches); the 8'6\" allowance applies only to the Interstate and designated highway system. Source: Kentucky DRIVE (KYTC) Legal Dimensions page; KRS 189.221.","handbook":"","hbref":""},{"q":"What is the maximum legal vehicle height on Kentucky highways before an over-dimensional permit is required?","options":["14 feet 0 inches","14 feet 6 inches","13 feet 0 inches","13 feet 6 inches"],"answer":3,"explanation":"Kentucky sets the legal maximum vehicle and load height at 13 feet 6 inches; anything taller requires an over-dimensional permit. Source: Kentucky DRIVE (KYTC) Legal Dimensions page; KRS 189.222.","handbook":"","hbref":""},{"q":"What is the maximum legal length of a single semitrailer operating on Kentucky's Interstate and designated highway system?","options":["45 feet","57 feet","53 feet","48 feet"],"answer":2,"explanation":"A single semitrailer may be up to 53 feet long on Kentucky's Interstate and designated highways. Source: Kentucky DRIVE (KYTC) Legal Dimensions page; KRS 189.221/189.222.","handbook":"","hbref":""},{"q":"In a twin-trailer (double) combination operating in Kentucky, what is the maximum legal length of each individual trailer?","options":["26 feet each","28 feet each","30 feet each","32 feet each"],"answer":1,"explanation":"Kentucky permits twin/double trailers of up to 28 feet each, consistent with the federally protected double dimension. Source: Kentucky DRIVE (KYTC) Legal Dimensions page; KRS 189.222.","handbook":"","hbref":""},{"q":"What is the maximum legal length of a single-unit motor truck on Kentucky highways?","options":["45 feet","53 feet","48 feet","40 feet"],"answer":0,"explanation":"A single-unit motor truck is limited to 45 feet in length under Kentucky's dimension rules. Source: Kentucky DRIVE (KYTC) Legal Dimensions page; KRS 189.221.","handbook":"","hbref":""},{"q":"On Kentucky state-maintained highways that are NOT part of the designated system, what is the maximum overall length of a truck-tractor and trailer combination?","options":["75 feet","70 feet","60 feet","65 feet"],"answer":3,"explanation":"On non-designated state-maintained roads the overall combination length is capped at 65 feet, even though a 53-foot semitrailer is allowed on designated highways. Source: Kentucky DRIVE (KYTC) Legal Dimensions page; KRS 189.221.","handbook":"","hbref":""},{"q":"What is the maximum legal gross weight for a commercial vehicle and load on Kentucky highways without an overweight permit?","options":["84,000 pounds","88,000 pounds","80,000 pounds","73,280 pounds"],"answer":2,"explanation":"Kentucky caps total gross vehicle weight at 80,000 pounds, matching the federal Interstate standard. Source: KRS 189.222; 603 KAR 5:066; Kentucky DRIVE (KYTC).","handbook":"","hbref":""},{"q":"What is the maximum legal weight that may be carried on a single axle in Kentucky?","options":["22,400 pounds","20,000 pounds","18,000 pounds","24,000 pounds"],"answer":1,"explanation":"No single axle may exceed 20,000 pounds in Kentucky (or 700 pounds per inch of aggregate tire width, whichever is less). Source: KRS 189.222; 603 KAR 5:066.","handbook":"","hbref":""},{"q":"What is the maximum legal weight on a tandem axle group (axles spaced 42 to 96 inches apart) in Kentucky?","options":["34,000 pounds","36,000 pounds","40,000 pounds","32,000 pounds"],"answer":0,"explanation":"A tandem axle group spaced 42 to 96 inches apart is limited to 34,000 pounds in Kentucky. Source: KRS 189.222; 603 KAR 5:066; Kentucky DRIVE (KYTC) Legal Dimensions.","handbook":"","hbref":""},{"q":"In Kentucky, what is the maximum legal weight on a tridem (three-axle) group spaced 42 to 120 inches apart?","options":["45,000 pounds","42,000 pounds","51,000 pounds","48,000 pounds"],"answer":3,"explanation":"A tridem axle group spaced between 42 and 120 inches is allowed up to 48,000 pounds in Kentucky. Source: KRS 189.222; Kentucky DRIVE (KYTC) Legal Dimensions page.","handbook":"","hbref":""},{"q":"Kentucky allows a weight tolerance on axle weights, but only on certain roads. On which highways does the 5 percent axle-weight tolerance apply?","options":["Only county-maintained roads","All highways including the Interstate system","State-maintained highways that are NOT part of the Interstate system","Only the Interstate system"],"answer":2,"explanation":"Kentucky allows a tolerance of not more than 5 percent on axle weight on state-maintained highways that are not part of the Interstate system; no such axle tolerance applies on the Interstate. Source: KRS 189.222.","handbook":"","hbref":""},{"q":"Under Kentucky law, how does the 5 percent weight tolerance apply to GROSS vehicle weight?","options":["A 5 percent tolerance applies only on the Interstate","No tolerance is allowed on gross weight","A 10 percent tolerance applies on non-Interstate roads","A 5 percent tolerance applies on all roads"],"answer":1,"explanation":"Kentucky expressly allows NO tolerance on gross weight; the 5 percent tolerance applies only to axle weights on non-Interstate state-maintained highways. Source: KRS 189.222.","handbook":"","hbref":""},{"q":"Kentucky uses the federal bridge formula to limit weight on groups of consecutive axles. What does the formula primarily relate gross weight to?","options":["The number of axles and the spacing (distance) between them","The number of tires and their air pressure","The horsepower of the engine and the gross combination weight rating","The trailer length and the cargo density"],"answer":0,"explanation":"The federal Bridge Formula, W=500(LN/(N-1)+12N+36), limits the weight on any group of two or more consecutive axles based on the number of axles (N) and the distance (L) between the extreme axles of the group. Kentucky applies it via adoption of 23 CFR Part 658. Source: 23 CFR 658.17; KRS 189.222.","handbook":"","hbref":""},{"q":"In the federal bridge formula W = 500(LN/(N-1) + 12N + 36) used in Kentucky, what does the variable 'L' represent?","options":["The legal load weight in tons","The lift capacity of the suspension","The length of the trailer in feet","The distance in feet between the extreme axles of the group"],"answer":3,"explanation":"In the bridge formula, L is the distance in feet between the extremes of any group of two or more consecutive axles, while N is the number of axles in that group. Source: 23 CFR 658.17 (Bridge Formula), adopted in Kentucky under KRS 189.222.","handbook":"","hbref":""},{"q":"Two consecutive sets of tandem axles may each carry the full 34,000 pounds in Kentucky only if the distance between the first and last axles of those tandems is at least how many feet?","options":["28 feet","40 feet","36 feet","30 feet"],"answer":2,"explanation":"Under the bridge formula exception adopted by Kentucky, two consecutive tandem axle sets may each carry 34,000 pounds only when the overall spacing between the first and last axles of those tandems is 36 feet or more. Source: 23 CFR 658.17; KRS 189.222.","handbook":"","hbref":""},{"q":"When is a Kentucky oversize/overweight (OS/OW) permit required?","options":["Only when traveling on county roads","Before moving any vehicle or load that exceeds the legal limits for width, height, length, or weight","Only when the gross weight exceeds 90,000 pounds","Only when the load is wider than 10 feet"],"answer":1,"explanation":"A Kentucky permit must be obtained PRIOR to moving any vehicle or load that exceeds the statutory legal limits for width, height, length, or weight. Source: KYTC Division of Motor Carriers; 601 KAR 1:018.","handbook":"","hbref":""},{"q":"Which Kentucky agency issues special overweight/over-dimensional motor vehicle load permits, and what generally cannot receive such a permit?","options":["The KYTC Division of Motor Carriers; reasonably divisible loads generally cannot be permitted","The U.S. DOT; only Interstate loads can be permitted","The Kentucky State Police; only farm loads can be permitted","County fiscal courts; only forest products can be permitted"],"answer":0,"explanation":"The Kentucky Transportation Cabinet's Division of Motor Carriers issues OS/OW permits under 601 KAR 1:018, and permits are generally NOT issued for loads that are reasonably divisible (could be disassembled or split to meet legal limits). Source: 601 KAR 1:018; KRS 189.270.","handbook":"","hbref":""},{"q":"Kentucky provides a special variance for non-divisible farm equipment. What does this allow?","options":["Farm equipment may travel at any width without a permit on two-lane roads","Farm equipment may exceed 120,000 pounds on the Interstate without a permit","Farm equipment is exempt from all permit and weight rules statewide","A single-trip permit may be issued for non-divisible farm equipment exceeding the legal weight or dimension limits"],"answer":3,"explanation":"Kentucky issues an overweight/over-dimensional single-trip permit for the movement of non-divisible farm equipment that exceeds the limits in KRS 189.222 or 189.270; it is a permitted variance, not a blanket exemption. Source: 601 KAR 1:019; 601 KAR 1:018.","handbook":"","hbref":""},{"q":"Under Kentucky's Extended-Weight Coal Haul Road System (ECWHRS), what maximum gross weight may a 5-or-more-axle tractor-semitrailer hauling coal operate at?","options":["90,000 pounds (with a 5 percent tolerance)","80,000 pounds (with no tolerance)","120,000 pounds (with a 5 percent tolerance)","100,000 pounds (with a 10 percent tolerance)"],"answer":2,"explanation":"On the Extended-Weight Coal Haul Road System, a tractor-semitrailer with five or more axles transporting coal or coal by-products may operate up to 120,000 pounds gross with a 5 percent tolerance. Source: KRS 177.9771.","handbook":"","hbref":""},{"q":"In Kentucky, a Class A CDL is required to operate any combination of vehicles with a gross combination weight rating (GCWR) of 26,001 pounds or more, provided the GVWR of the vehicle(s) being towed exceeds what weight?","options":["10,000 pounds","26,001 pounds","16,000 pounds","1,000 pounds"],"answer":0,"explanation":"Kentucky requires a Class A CDL for combinations with a GCWR of 26,001 lbs or more when the towed unit(s) have a GVWR over 10,000 lbs. Source: Kentucky CDL Manual (KYTC, March 2025), 'Who Must Apply? - Class A CDL.'","handbook":"","hbref":""},{"q":"Under Kentucky rules, a Class B CDL is required to drive any single vehicle with a gross vehicle weight rating (GVWR) of at least how many pounds?","options":["10,001 pounds","26,001 pounds","33,000 pounds","16,001 pounds"],"answer":1,"explanation":"A Class B CDL covers any single vehicle with a GVWR of 26,001 lbs or more, including such a vehicle towing a unit with a GVWR of 10,000 lbs or less. Source: Kentucky CDL Manual (KYTC, March 2025), 'Class B CDL.'","handbook":"","hbref":""},{"q":"According to the Kentucky CDL Manual, a vehicle with a GVWR under 26,001 pounds requires a Class C CDL when it is designed to transport at least how many people, including the driver?","options":["15","24","16","9"],"answer":2,"explanation":"Kentucky requires a Class C CDL for a vehicle under 26,001 lbs GVWR that transports 16 or more passengers including the driver, or that hauls placardable hazardous materials. Source: Kentucky CDL Manual (KYTC, March 2025), 'Class C CDL.'","handbook":"","hbref":""},{"q":"In Kentucky, which CDL class applies to a vehicle with a GVWR of less than 26,001 pounds that transports hazardous materials in amounts requiring placarding?","options":["Class A","Class B","Class D","Class C"],"answer":3,"explanation":"A Class C CDL covers vehicles under 26,001 lbs GVWR that carry placardable hazardous materials or 16+ passengers (including the driver). Source: Kentucky CDL Manual (KYTC, March 2025), 'Class C CDL.'","handbook":"","hbref":""},{"q":"What is the minimum age at which Kentucky may issue a CDL limited to intrastate commerce (with a 'K' restriction)?","options":["21 years","18 years","19 years","16 years"],"answer":1,"explanation":"Kentucky may issue a class-specific CDL with a 'K' (intrastate only) restriction to an individual age 18 to 20 who meets testing requirements and does not drive a school bus or haul hazardous materials. Source: Kentucky CDL Manual (KYTC, March 2025), 'Individual Eighteen (18) Years of Age Driving Intrastate.'","handbook":"","hbref":""},{"q":"A Kentucky CDL holder who wants to drive a commercial motor vehicle in interstate commerce (across state lines, unrestricted) must be at least how old?","options":["18 years","19 years","21 years","25 years"],"answer":2,"explanation":"Drivers 18-20 are limited to Kentucky intrastate commerce ('K' restriction); a driver must be 21 to operate without that restriction in interstate commerce. Source: Kentucky CDL Manual (KYTC, March 2025), intrastate age section.","handbook":"","hbref":""},{"q":"After a Kentucky CDL instruction permit (CLP) is issued, how long must the applicant hold the permit before a skills test can be administered?","options":["30 days","10 days","60 days","14 days"],"answer":3,"explanation":"The permit must be held for 14 days before a skills test is given, matching the federal CLP rule. Source: Kentucky CDL Manual (KYTC, March 2025), 'How to Apply for a CDL.'","handbook":"","hbref":""},{"q":"How long is a Kentucky CDL instruction permit (CLP) valid?","options":["6 months","12 months","30 days","180 days renewable indefinitely"],"answer":0,"explanation":"A Kentucky CDL instruction permit is valid for six (6) months. It may be renewed only once before the applicant must reapply. Source: Kentucky CDL Manual (KYTC, March 2025), 'How to Apply for a CDL' and ELDT section.","handbook":"","hbref":""},{"q":"How many times may a Kentucky CDL instruction permit be renewed before the applicant must reapply (and pay all fees and retake written tests)?","options":["Twice","It cannot be renewed","Once","Unlimited times"],"answer":2,"explanation":"A Kentucky CDL permit may only be renewed once; if the road skills test is not passed before the renewed permit expires, the applicant must reapply with all fees and written tests. Source: Kentucky CDL Manual (KYTC, March 2025), 'Entry Level Driver Training (ELDT).'","handbook":"","hbref":""},{"q":"Which endorsement is required on a Kentucky CDL to drive a vehicle designed to transport passengers, such as a transit or charter bus?","options":["S (School Bus)","N (Tank)","T (Doubles/Triples)","P (Passenger)"],"answer":3,"explanation":"The P (Passenger) endorsement is required to carry passengers; adding it requires a complete skills test in a passenger vehicle of the class being applied for. Source: Kentucky CDL Manual (KYTC, March 2025), 'Endorsements' and 'Adding a Passenger endorsement.'","handbook":"","hbref":""},{"q":"To drive a school bus in Kentucky, a CDL holder must obtain the S (School Bus) endorsement in addition to which other endorsement?","options":["P (Passenger)","N (Tank)","H (HazMat)","T (Doubles/Triples)"],"answer":0,"explanation":"School bus drivers must hold a School Bus (S) endorsement in addition to a Passenger (P) endorsement, and must pass a knowledge test plus all three skills-test portions in the class of school bus to be driven. Source: Kentucky CDL Manual (KYTC, March 2025), school bus endorsement section.","handbook":"","hbref":""},{"q":"On the Kentucky CDL knowledge tests, the Hazardous Materials (H) endorsement test contains how many questions?","options":["20 questions","30 questions","50 questions","25 questions"],"answer":1,"explanation":"Kentucky's HazMat endorsement knowledge test has 30 questions, while the Doubles/Triples, Tanker, Passenger, and School Bus endorsement tests each have 20. Source: Kentucky CDL Manual (KYTC, March 2025), 'Endorsements are required for the following vehicles.'","handbook":"","hbref":""},{"q":"Before being issued or renewing a Kentucky Hazardous Materials (H) endorsement, an applicant must complete fingerprinting and a security background check processed by the FBI and which federal agency?","options":["Federal Motor Carrier Safety Administration (FMCSA)","Department of Homeland Security Coast Guard","Federal Highway Administration (FHWA)","Transportation Security Administration (TSA)"],"answer":3,"explanation":"HazMat applicants are fingerprinted and the application is sent to the FBI and the Transportation Security Administration (TSA) for a security threat assessment before testing. A TWIC card can serve as proof of the assessment. Source: Kentucky CDL Manual (KYTC, March 2025), HazMat endorsement section.","handbook":"","hbref":""},{"q":"Which Kentucky CDL endorsement is required to pull double or triple trailers?","options":["T","N","H","X"],"answer":0,"explanation":"The T endorsement (Doubles/Triples) is required to pull double or triple trailers and requires passing a 20-question knowledge test. Source: Kentucky CDL Manual (KYTC, March 2025), 'Endorsements.'","handbook":"","hbref":""},{"q":"Which endorsement does a Kentucky CDL driver need to haul liquids or gases in a bulk tank vehicle (a tanker)?","options":["T (Doubles/Triples)","N (Tank)","P (Passenger)","H (HazMat)"],"answer":1,"explanation":"The N (Tank) endorsement is required to operate a tank vehicle hauling liquid or gaseous bulk cargo, and requires a 20-question knowledge test. Source: Kentucky CDL Manual (KYTC, March 2025), 'Endorsements.'","handbook":"","hbref":""},{"q":"As of February 7, 2022, federal Entry-Level Driver Training (ELDT) must be completed in Kentucky before obtaining a Class A or B CDL for the first time, and the training must come from a provider listed where?","options":["The Kentucky State Police testing roster","Any KYTC Regional Office list","The FMCSA Training Provider Registry","The CDLIS clearinghouse"],"answer":2,"explanation":"ELDT under 49 CFR part 380 must be completed before a first-time Class A/B CDL, an upgrade, or a first H, P, or S endorsement, using a provider listed on the FMCSA Training Provider Registry. Source: Kentucky CDL Manual (KYTC, March 2025), 'Entry Level Driver Training (ELDT).'","handbook":"","hbref":""},{"q":"For which of the following does Kentucky NOT require Entry-Level Driver Training (ELDT) before it is added the first time?","options":["H (HazMat) endorsement","N (Tank) endorsement","P (Passenger) endorsement","S (School Bus) endorsement"],"answer":1,"explanation":"ELDT is required for a first-time Class A/B CDL, an upgrade, and a first H, P, or S endorsement; the Tank (N) endorsement is not on the ELDT list. Source: Kentucky CDL Manual (KYTC, March 2025), 'Entry Level Driver Training (ELDT)'; 49 CFR part 380.","handbook":"","hbref":""},{"q":"Which medical self-certification category should a Kentucky CDL applicant choose if they operate or expect to operate only within Kentucky (intrastate) and are NOT excepted from medical requirements?","options":["Excepted Intrastate (EA)","Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)"],"answer":3,"explanation":"A driver operating only in Kentucky who must be medically certified selects Non-Excepted Intrastate (NA). The Excepted Intrastate (EA) box is not used in Kentucky because all KY CDL holders must be medically certified. Source: KYTC Commercial Driver License Self-Certification form (TC 94-169); 601 KAR 1:005.","handbook":"","hbref":""},{"q":"On the Kentucky CDL self-certification form, which medical-certification category is NOT available and should never be selected because all Kentucky CDL holders must be medically certified?","options":["Excepted Intrastate (EA)","Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)"],"answer":0,"explanation":"Kentucky does not allow the Excepted Intrastate (EA) category; every KY CDL holder must be medically certified, so EA must never be marked. The other three (NI, EI, NA) are valid choices. Source: KYTC Commercial Driver License Self-Certification form (TC 94-169); 601 KAR 1:005.","handbook":"","hbref":""},{"q":"On a Kentucky CDL, what does the 'K' restriction code indicate?","options":["No air-brake-equipped CMV","No cargo in a tank vehicle","Intrastate (Kentucky only) operation","No passengers in a CMV bus"],"answer":2,"explanation":"The 'K' restriction limits the holder to intrastate commerce within Kentucky and applies to drivers under 21 and others restricted to intrastate driving. (For reference, X = no cargo in tank, L = no air brakes, P = no passengers in a CMV bus.) Source: Kentucky CDL Manual (KYTC, March 2025), 'Restrictions.'","handbook":"","hbref":""},{"q":"While operating a commercial motor vehicle (CMV) in Kentucky, what blood alcohol concentration (BAC) is the legal threshold at which a driver is considered to be driving under the influence and is disqualified?","options":["0.04 or greater","0.08 or greater","0.02 or greater","0.10 or greater"],"answer":0,"explanation":"Kentucky sets the CMV BAC limit at 0.04 or greater, half the 0.08 limit for regular drivers. Operating a CMV at or above 0.04 is a major offense triggering disqualification. Source: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"In Kentucky, a first conviction of a major offense (such as a DUI in a CMV) results in disqualification of the CDL for how long?","options":["1 year","60 days","6 months","3 years"],"answer":0,"explanation":"A first major offense disqualifies the driver for 1 year (3 years if transporting placarded hazardous materials at the time). Source: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"If a Kentucky CDL holder commits a first major offense while transporting placarded hazardous materials, the disqualification period increases to how long?","options":["3 years","1 year","5 years","2 years"],"answer":0,"explanation":"A first major offense while hauling placarded hazardous materials raises the disqualification from 1 year to 3 years. Source: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"Under Kentucky's implied-consent law, by operating a commercial motor vehicle a driver is deemed to have consented to a chemical test of which substances?","options":["Blood, breath, or urine for alcohol or drugs","Only breath for alcohol","Only blood for drugs","Only urine for controlled substances"],"answer":0,"explanation":"Kentucky's implied-consent law deems every CMV operator to have consented to a test of blood, breath, or urine to detect alcohol or controlled substances when an officer has reasonable cause. Source: Kentucky CDL Manual (KYTC), KRS 281A.150/281A.190.","handbook":"","hbref":""},{"q":"In Kentucky, what happens to a CDL holder who refuses to submit to a required chemical test of breath, blood, or urine?","options":["Treated as a major offense — at least a 1-year disqualification","A warning only on the first refusal","A 60-day disqualification","A 30-day suspension and a fine"],"answer":0,"explanation":"Refusing the test is itself a major offense, carrying the same disqualification as a DUI conviction: at least 1 year (3 years if placarded HazMat). Source: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"A Kentucky CDL holder is convicted of a second major offense in a separate incident. What is the disqualification period?","options":["Lifetime disqualification","10 years","5 years","3 years"],"answer":0,"explanation":"A second major offense in a separate incident results in lifetime disqualification of the CDL. Source: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"After how many years may a Kentucky driver disqualified for life potentially be eligible for reinstatement, provided eligibility requirements such as completing an approved rehabilitation program are met?","options":["10 years","5 years","7 years","15 years"],"answer":0,"explanation":"A state may reinstate a lifetime-disqualified driver after a minimum of 10 years if the person completes an approved rehabilitation program; some drug/trafficking felonies are never eligible. Source: Kentucky CDL Manual (KYTC); 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Even below the 0.04 disqualifying level, what happens to a Kentucky CMV driver found with any detectable amount of alcohol in their system?","options":["Placed out of service for 24 hours","Immediately disqualified for 1 year","Fined $100 with no other action","Given a 60-day disqualification"],"answer":0,"explanation":"A driver with any measurable amount of alcohol below 0.04 is placed out of service for 24 hours. Reaching 0.04 or higher is a major offense. Source: Kentucky CDL Manual (KYTC); 49 CFR 392.5.","handbook":"","hbref":""},{"q":"In Kentucky, conviction of two serious traffic violations in a CMV within a 3-year period (separate incidents) results in disqualification for how long?","options":["60 days","30 days","120 days","90 days"],"answer":0,"explanation":"Two serious traffic violations within 3 years (separate incidents) result in a 60-day disqualification. Source: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"In Kentucky, conviction of three serious traffic violations in a CMV within a 3-year period (separate incidents) results in disqualification for how long?","options":["120 days","60 days","180 days","1 year"],"answer":0,"explanation":"Three serious traffic violations within 3 years (separate incidents) result in a 120-day disqualification, served consecutively to other disqualifications. Source: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"Which of the following is classified as a serious traffic violation for a Kentucky CDL holder?","options":["Speeding 15 mph or more over the posted limit","Speeding 5 mph over the posted limit","A single parking violation","Driving with an expired registration sticker"],"answer":0,"explanation":"Excessive speeding (15 mph or more over the limit) is a serious traffic violation, along with reckless driving, improper lane changes, following too closely, texting, and handheld phone use. Source: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"For Kentucky CDL purposes, how is texting while driving a CMV treated when counting toward disqualification?","options":["As a serious traffic violation","As a major offense","As an out-of-service violation","It carries no CDL consequence"],"answer":0,"explanation":"Texting while driving a CMV is a serious traffic violation; two within 3 years bring a 60-day disqualification and three bring 120 days. Source: Kentucky CDL Manual (KYTC); 49 CFR 383.51 and 49 CFR 392.80.","handbook":"","hbref":""},{"q":"Using a hand-held mobile telephone while driving a CMV in Kentucky is prohibited and is counted toward CDL disqualification as which type of offense?","options":["A serious traffic violation","A major offense","A railroad-crossing violation","An out-of-service order violation"],"answer":0,"explanation":"Hand-held phone use while driving a CMV is a serious traffic violation; two within 3 years yield a 60-day disqualification, three yield 120 days. Source: Kentucky CDL Manual (KYTC); 49 CFR 383.51 and 49 CFR 392.82.","handbook":"","hbref":""},{"q":"A first conviction for a railroad-highway grade crossing violation in a CMV results in a Kentucky CDL disqualification of at least how long?","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"A first railroad grade crossing violation carries a disqualification of no less than 60 days. Source: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"A second railroad-highway grade crossing violation within a 3-year period results in a Kentucky CDL disqualification of at least how long?","options":["120 days","60 days","180 days","1 year"],"answer":0,"explanation":"A second grade crossing violation within 3 years carries a disqualification of no less than 120 days. Source: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"A third or subsequent railroad-highway grade crossing violation within a 3-year period results in a Kentucky CDL disqualification of at least how long?","options":["1 year","120 days","180 days","60 days"],"answer":0,"explanation":"A third or subsequent grade crossing violation within 3 years carries a disqualification of no less than 1 year. Source: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"Which of the following is a railroad grade-crossing violation that can disqualify a Kentucky CDL holder?","options":["Driving onto a crossing without enough space to fully clear it","Stopping 50 feet before the tracks to check for trains","Slowing down and checking that the tracks are clear","Yielding to a train that has the right of way"],"answer":0,"explanation":"Crossing without sufficient space to clear the tracks is a violation, as are failing to slow/check, failing to stop when required, and not having enough undercarriage clearance. Source: Kentucky CDL Manual (KYTC); 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"A Kentucky CDL holder who violates an out-of-service order for the first time (non-HazMat, non-passenger) is disqualified for a period of no less than how long?","options":["180 days","60 days","90 days","1 year"],"answer":0,"explanation":"A first out-of-service order violation carries a disqualification of no less than 180 days (up to 1 year). Source: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"For a second out-of-service order violation within a 10-year period, a Kentucky CDL holder is disqualified for no less than how long?","options":["2 years","180 days","1 year","3 years"],"answer":0,"explanation":"A second out-of-service order violation within 10 years carries a disqualification of no less than 2 years (up to 5 years). Source: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"A third or subsequent out-of-service order violation within a 10-year period results in a Kentucky CDL disqualification of no less than how long?","options":["3 years","2 years","1 year","5 years"],"answer":0,"explanation":"A third or subsequent out-of-service order violation within 10 years carries a disqualification of no less than 3 years (up to 5 years). Source: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"Under Kentucky's 'Slow Down, Move Over' law, when a CDL driver approaches a stopped emergency or public safety vehicle displaying flashing lights on a multi-lane highway, what is the driver's FIRST obligation if it can be done safely?","options":["Continue at the posted speed while staying in the same lane","Come to a complete stop until the emergency vehicle leaves","Vacate the lane closest to the stopped vehicle by moving over one lane","Honk to alert the responders that the truck is approaching"],"answer":2,"explanation":"Kentucky's Move Over law (KRS 189.930) requires a driver on a road with two or more lanes in the same direction to vacate the lane nearest a stopped emergency/public safety vehicle showing flashing lights when it is safe to do so. Source: KRS 189.930; Kentucky CDL Manual.","handbook":"","hbref":""},{"q":"On a two-lane Kentucky road where a driver cannot safely move over for a stopped emergency vehicle with flashing lights, the Move Over law requires the driver to do what instead?","options":["Reduce speed to a level that is safe for the road, weather, and traffic conditions","Stop completely 500 feet before the emergency vehicle","Activate four-way flashers and maintain the speed limit","Pull onto the shoulder and wait to be waved through"],"answer":0,"explanation":"Under KRS 189.930, if changing lanes is impossible or unsafe, the driver must slow to a speed safe for the existing road, weather, and traffic conditions and proceed with caution. Source: KRS 189.930.","handbook":"","hbref":""},{"q":"Kentucky expanded its Move Over law in July 2024. Besides police, fire, and ambulances, the expanded law now also requires drivers to move over or slow down for which of the following?","options":["Any stationary vehicle displaying hazard lights or warning signals, including disabled vehicles and tow trucks","Only marked law enforcement cruisers","Only vehicles that are actively blocking a travel lane","Only vehicles owned by the Kentucky Transportation Cabinet"],"answer":0,"explanation":"The July 2024 expansion of KRS 189.930 broadened protection to any stationary vehicle showing flashing lights, hazard lights, or warning devices, such as tow/wrecker vehicles and disabled motorists, not just traditional first responders. Source: KRS 189.930 (2024 amendment).","handbook":"","hbref":""},{"q":"A CDL driver in Kentucky is hauling a placarded load of hazardous materials and approaches a railroad crossing. Within what distance from the nearest rail must the driver stop?","options":["Not less than 5 feet and not more than 25 feet","Not less than 15 feet and not more than 50 feet","Not less than 25 feet and not more than 75 feet","Not less than 50 feet and not more than 100 feet"],"answer":1,"explanation":"A driver of a placarded hazmat vehicle must stop within 50 feet of, but not closer than 15 feet to, the nearest rail before crossing (the '15-to-50-foot' rule). Source: 49 CFR 392.10, adopted in Kentucky; Kentucky CDL Manual.","handbook":"","hbref":""},{"q":"Which of these commercial vehicles is REQUIRED to stop at every railroad crossing under the rules taught in the Kentucky CDL Manual?","options":["An empty flatbed tractor-trailer","A bus carrying passengers","A box truck hauling general freight","A dump truck carrying gravel"],"answer":1,"explanation":"Buses carrying passengers and vehicles displaying hazardous-materials placards must stop at railroad crossings, stopping within 15 to 50 feet of the nearest rail. General-freight trucks are not required to stop unless signals require it. Source: 49 CFR 392.10; Kentucky CDL Manual.","handbook":"","hbref":""},{"q":"Under Kentucky's school bus law, on a four-lane highway a school bus stops with red lights flashing and the stop arm extended. Which drivers are NOT required to stop?","options":["Drivers in the lane next to the bus traveling the same direction","Drivers directly behind the bus in the same lane","All drivers must stop regardless of direction or number of lanes","Drivers approaching from the opposite direction on the four-or-more-lane highway"],"answer":3,"explanation":"Under KRS 189.370, on a highway of four or more lanes, vehicles approaching from the opposite direction of a stopped school bus are not required to stop. Traffic on the bus's side must still stop. Source: KRS 189.370.","handbook":"","hbref":""},{"q":"On a standard two-lane Kentucky highway, a school bus stops with its red lights flashing and stop arm out to load children. What must oncoming traffic do?","options":["Slow to 25 mph but may keep moving past the bus","Stop and remain stopped until the bus resumes motion","Proceed normally because the bus is on the other side of the centerline","Stop only if children are visible crossing the road"],"answer":1,"explanation":"On a two-lane road, KRS 189.370 requires drivers from BOTH directions to stop for a school bus loading or unloading with its signals activated, and not to proceed until the bus moves again. The opposite-direction exception applies only to highways of four or more lanes. Source: KRS 189.370.","handbook":"","hbref":""},{"q":"The Kentucky school bus stopping requirement (and its opposite-direction exception) is based on what specific roadway characteristic?","options":["The number of lanes on the highway (four or more)","Whether the speed limit is 55 mph or higher","Whether the highway is a designated state parkway","Whether a physical concrete barrier separates the directions"],"answer":0,"explanation":"KRS 189.370 ties the opposite-direction exception specifically to a highway 'of four (4) or more lanes' rather than to the presence of a median barrier or a speed threshold. Source: KRS 189.370.","handbook":"","hbref":""},{"q":"Kentucky law restricts certain large vehicles from the leftmost lane. On a highway with three or more lanes traveling in the same direction, which vehicles are prohibited from the far-left lane except when passing, entering, or leaving?","options":["Motorcycles and mopeds","Recreational vehicles and motorhomes","Truck tractors, trailers, and semitrailers","All passenger cars and pickups"],"answer":2,"explanation":"KRS 189.340 prohibits a truck tractor, trailer, or semitrailer from operating in the leftmost lane of a highway with three or more lanes in the same direction, except when passing, entering or leaving the highway, yielding to entering traffic, or when other lanes are unsafe. Source: KRS 189.340.","handbook":"","hbref":""},{"q":"Under Kentucky's left-lane truck rule, which of the following is a valid reason for a semitrailer to legally be in the far-left lane of a three-lane interstate?","options":["Maintaining a steady cruising speed for fuel economy","Keeping clear of vehicles merging from on-ramps for the whole trip","Passing a slower vehicle, then returning right as soon as practicable","Traveling slightly below the speed limit to save the brakes"],"answer":2,"explanation":"KRS 189.340 allows a truck tractor/trailer/semitrailer to use the leftmost lane only for limited reasons such as passing (then returning right as soon as practicable), entering/leaving the highway, yielding to entering traffic, or when the right/center lanes are unsafe. Source: KRS 189.340.","handbook":"","hbref":""},{"q":"What is the maximum speed limit for trucks on rural sections of Kentucky's interstate highways such as I-64, I-65, and I-75?","options":["70 mph","65 mph","60 mph","75 mph"],"answer":0,"explanation":"Kentucky posts a maximum of 70 mph on most rural interstate segments; this applies to trucks unless a lower limit is posted. Urban sections (e.g., around Louisville and Lexington) are typically 65 mph. Source: KRS 189.390; KYTC posted limits.","handbook":"","hbref":""},{"q":"Through urban areas near Louisville and Lexington, the interstate speed limit a CDL driver should expect is most commonly:","options":["70 mph","65 mph","45 mph","55 mph"],"answer":1,"explanation":"While rural Kentucky interstates are generally posted at 70 mph, urban interstate segments around metro areas like Louisville and Lexington are commonly posted at 65 mph. Drivers must always obey the posted limit. Source: KRS 189.390; KYTC posted limits.","handbook":"","hbref":""},{"q":"A CDL driver's truck breaks down on the shoulder of a two-lane, two-way Kentucky highway during daylight. After putting out the required warning devices, where should the three reflective triangles be placed?","options":["100 feet behind, 100 feet ahead, and one beside the cab","10 feet behind, 100 feet behind, and 100 feet ahead of the vehicle","25 feet behind, 200 feet behind, and 200 feet ahead of the vehicle","10 feet behind, 50 feet behind, and 50 feet ahead of the vehicle"],"answer":1,"explanation":"On a two-lane, two-way road, place one triangle within 10 feet of the rear, one about 100 feet behind, and one about 100 feet in front of the vehicle. Source: 49 CFR 392.22, adopted in Kentucky; Kentucky CDL Manual.","handbook":"","hbref":""},{"q":"When a commercial vehicle is stopped on a one-way or divided Kentucky highway, where are the three warning devices placed relative to approaching traffic?","options":["100 feet behind and 100 feet ahead, plus one at the cab","10 feet, 100 feet, and 200 feet toward the approaching traffic","200 feet, 200 feet, and 500 feet toward the approaching traffic","10 feet, 50 feet, and 100 feet toward the approaching traffic"],"answer":1,"explanation":"On a one-way or divided highway, place the warning devices 10 feet, 100 feet, and 200 feet toward the approaching traffic in the center of the lane or shoulder occupied by the vehicle. Source: 49 CFR 392.22; Kentucky CDL Manual.","handbook":"","hbref":""},{"q":"After stopping a disabled commercial vehicle on a Kentucky roadway, within how many minutes must the driver set out the required emergency warning devices?","options":["Within 10 minutes","Within 5 minutes","Within 30 minutes","Within 15 minutes"],"answer":0,"explanation":"A driver must place the three required warning devices within 10 minutes of stopping. Source: 49 CFR 392.22, adopted in Kentucky; Kentucky CDL Manual.","handbook":"","hbref":""},{"q":"On a long downgrade like Kentucky's Pine Mountain (U.S. 119), what is the proper braking technique taught in the Kentucky CDL Manual?","options":["Apply the parking brake intermittently to slow the vehicle","Shift to neutral to let the engine cool and ride the brakes lightly","Select a low gear before the descent and use light, steady or snub braking","Keep the highest gear possible and pump the brakes continuously"],"answer":2,"explanation":"Drivers should choose the proper low gear before starting down a grade and rely primarily on engine braking, using the service brakes in light, intermittent (snub) applications. Riding the brakes causes overheating and brake fade. Source: Kentucky CDL Manual (Controlling Speed / Mountain Driving).","handbook":"","hbref":""},{"q":"Without an oversize permit in Kentucky, what is the maximum legal width allowed for a commercial vehicle and load on designated highways?","options":["10 feet 0 inches","9 feet 6 inches","8 feet 0 inches","8 feet 6 inches"],"answer":3,"explanation":"Kentucky's legal maximum vehicle/load width on interstates and designated highways is 8 feet 6 inches (102 inches); anything wider requires an oversize permit from KYTC. Source: KRS Chapter 189; KYTC Overweight/Over-Dimensional Permits.","handbook":"","hbref":""},{"q":"A load in Kentucky measures 14 feet tall. Without a permit, the legal maximum height is 13 feet 6 inches. What must the carrier obtain before moving this load?","options":["Permission from the local county sheriff only","Nothing, because height limits are only advisory in Kentucky","An oversize/over-dimensional permit from the Kentucky Transportation Cabinet","A hazardous-materials endorsement only"],"answer":2,"explanation":"Kentucky's legal maximum height is 13 feet 6 inches; a load of 14 feet exceeds that and requires an over-dimensional permit issued through the KYTC Division of Motor Carriers before travel. Source: KRS Chapter 189; KYTC Overweight/Over-Dimensional Permits.","handbook":"","hbref":""},{"q":"Kentucky will generally NOT issue an oversize/overweight permit for which type of load?","options":["A single piece of industrial machinery that cannot be taken apart","A load that is reasonably divisible and could be reconfigured to meet legal limits","A large transformer that exceeds legal weight","A pre-fabricated building section that exceeds legal width"],"answer":1,"explanation":"Kentucky issues OS/OW permits only for non-divisible loads; it will not permit a load that is reasonably divisible (one that could be disassembled or reconfigured to comply with legal limits), except under specific statutory authority. Source: KYTC Overweight/Over-Dimensional Permits; KRS Chapter 189.","handbook":"","hbref":""},{"q":"Which Kentucky agency actually issues the Commercial Driver License (CDL) credential to qualified applicants?","options":["The Kentucky Transportation Cabinet's Division of Driver Licensing","The Kentucky State Police","The Federal Motor Carrier Safety Administration","The county Circuit Court Clerk's bonding office"],"answer":0,"explanation":"In Kentucky the CDL credential is issued by the Kentucky Transportation Cabinet (KYTC), Division of Driver Licensing. Source: KYTC drive.ky.gov CDL page; 2025 Kentucky CDL Manual.","handbook":"","hbref":""},{"q":"Who conducts the CDL knowledge tests and the road skills test for applicants in Kentucky?","options":["The Kentucky State Police","The county Circuit Court Clerk","Private third-party truck driving schools only","The FMCSA National Registry"],"answer":0,"explanation":"The Kentucky State Police (KSP) is exclusively responsible for administering all CDL knowledge and skills testing in Kentucky, while KYTC issues the license. Source: 2025 Kentucky CDL Manual; Kentucky State Police Driver Testing.","handbook":"","hbref":""},{"q":"For how many days is a Kentucky Commercial Learner's Permit (CLP) valid?","options":["180 days","60 days","365 days","90 days"],"answer":0,"explanation":"A Kentucky CLP is valid for a maximum of 180 days. Source: KRS 281A.120; 2025 Kentucky CDL Manual.","handbook":"","hbref":""},{"q":"After being issued a CLP, how long must an applicant wait before taking the CDL skills test in Kentucky?","options":["At least 14 days","At least 30 days","At least 7 days","At least 60 days"],"answer":0,"explanation":"An applicant must hold the CLP for at least 14 days before being eligible to take the CDL skills test. This is a federal standard applied in Kentucky. Source: 2025 Kentucky CDL Manual; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"How long is a Kentucky Commercial Driver License valid before it must be renewed?","options":["8 years","4 years","5 years","10 years"],"answer":0,"explanation":"A Kentucky CDL credential is valid for 8 years. Source: KRS 281A.170; KYTC drive.ky.gov.","handbook":"","hbref":""},{"q":"Which form is the DOT Medical Examiner's Certificate that a Kentucky CDL applicant must obtain from a certified medical examiner?","options":["Form MCSA-5876","Form TC 94-169","Form MCSA-5875 only","Form DOT-391"],"answer":0,"explanation":"The Medical Examiner's Certificate is Form MCSA-5876, completed by a National Registry Certified Medical Examiner; it must be on file for the CDL holder. (TC 94-169 is the separate self-certification form.) Source: KYTC first-time applicant info; FMCSA.","handbook":"","hbref":""},{"q":"On the Kentucky CDL self-certification, how many driving-type categories must an applicant choose from?","options":["Four","Two","Three","Five"],"answer":0,"explanation":"The self-certification (Form TC 94-169) has four categories: non-excepted interstate, excepted interstate, non-excepted intrastate, and excepted intrastate. Source: KYTC Form TC 94-169; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"A Kentucky driver who operates across state lines and must meet the federal physical qualification standards should self-certify as which category?","options":["Non-excepted interstate","Excepted interstate","Non-excepted intrastate","Excepted intrastate"],"answer":0,"explanation":"Drivers in interstate commerce subject to the federal physical qualification rules certify as non-excepted interstate, which requires a current Medical Examiner's Certificate on file. Source: KYTC Form TC 94-169; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"Before a first-time Class A or Class B applicant can take the CDL skills test in Kentucky, what training requirement must be met?","options":["Entry-Level Driver Training (ELDT) from a registered provider","A 160-hour state apprenticeship sponsored by KYTC","A defensive driving course at the Circuit Court Clerk","Two years of documented intrastate driving"],"answer":0,"explanation":"Federal Entry-Level Driver Training (ELDT) from an FMCSA Training Provider Registry provider is required before first-time Class A/B testing (and before first P, S, or H endorsement testing). Source: 2025 Kentucky CDL Manual; 49 CFR Part 380.","handbook":"","hbref":""},{"q":"Which of the following endorsements requires completing ELDT before the test, in addition to first-time Class A and Class B applicants?","options":["Hazardous materials (H), passenger (P), and school bus (S)","Tank vehicle (N) and doubles/triples (T)","Only the school bus (S) endorsement","No endorsement requires ELDT"],"answer":0,"explanation":"ELDT is required for first-time applicants for the hazardous materials (H), passenger (P), and school bus (S) endorsements, as well as for initial Class A/B issuance and Class B-to-A upgrades. Source: 2025 Kentucky CDL Manual; 49 CFR Part 380.","handbook":"","hbref":""},{"q":"The Kentucky CDL skills test is administered in three parts. Which set correctly lists those three parts?","options":["Pre-trip inspection, basic vehicle control, and on-road driving","Written knowledge, vision screening, and on-road driving","Pre-trip inspection, air-brake written test, and backing","Basic vehicle control, hazmat written test, and on-road driving"],"answer":0,"explanation":"The CDL skills test consists of three parts: the pre-trip inspection, basic vehicle control skills, and the on-road driving test. Source: 2025 Kentucky CDL Manual; 49 CFR 383.113.","handbook":"","hbref":""},{"q":"In which type of vehicle must a Kentucky applicant take the CDL skills test?","options":["The class/type of vehicle the applicant intends to be licensed to drive","Any commercial vehicle weighing over 10,001 pounds","A standard passenger car provided by the testing station","A Class C vehicle regardless of the license class sought"],"answer":0,"explanation":"Applicants must take the skills test in a representative vehicle of the class and type for which they seek licensure. Source: 2025 Kentucky CDL Manual; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"What documents must a first-time Kentucky CDL applicant have on file before the permit or license is issued?","options":["The CDL application, the self-certification form, and a legible DOT Medical Examiner's Certificate","Only a Social Security card and a vision screening result","An employer letter and a vehicle registration","A passport and an FMCSA clearinghouse subscription"],"answer":0,"explanation":"Before a CLP or CDL is issued, Kentucky requires the CDL application, the self-certification (TC 94-169), and a legible copy of the DOT Medical Examiner's Certificate, all submitted to KYTC (via mycdl.ky.gov). Source: KYTC first-time applicant info; drive.ky.gov.","handbook":"","hbref":""},{"q":"If a Kentucky CLP expires before the applicant passes the skills test, what generally happens?","options":["The applicant must retake the required knowledge tests to obtain a new CLP","The CLP is automatically extended for another 180 days","The skills test scores carry over for two years","The applicant may take the skills test within a 30-day grace period"],"answer":0,"explanation":"Kentucky does not extend the 180-day CLP; if it expires before the skills test is passed, the applicant must retake the knowledge test(s) to be issued a new CLP. Source: 2025 Kentucky CDL Manual; KRS 281A.120.","handbook":"","hbref":""},{"q":"What is the minimum passing score on the Kentucky CDL general knowledge test?","options":["80 percent correct","70 percent correct","75 percent correct","90 percent correct"],"answer":0,"explanation":"An applicant must score at least 80 percent to pass each CDL knowledge test, the federal standard applied in Kentucky. Source: 2025 Kentucky CDL Manual; 49 CFR 383.135.","handbook":"","hbref":""},{"q":"What is the minimum age to be issued a Kentucky CDL limited to intrastate (within-Kentucky) commerce?","options":["18 years old","21 years old","19 years old","16 years old"],"answer":0,"explanation":"A person must be at least 18 to hold a CDL for intrastate driving in Kentucky; 21 is required for interstate driving and for hazmat/school bus operation. Source: KRS 281A; 2025 Kentucky CDL Manual.","handbook":"","hbref":""},{"q":"What is the minimum age required to operate a commercial motor vehicle in interstate commerce on a Kentucky CDL?","options":["21 years old","18 years old","19 years old","25 years old"],"answer":0,"explanation":"Drivers must be at least 21 to operate in interstate commerce; 18- to 20-year-olds receive an intrastate (Kentucky-only) restriction. Source: KRS 281A; 2025 Kentucky CDL Manual; 49 CFR 391.11.","handbook":"","hbref":""},{"q":"When a Kentucky CDL holder gets a new DOT medical examination, what must the driver do to keep the CDL in 'certified' status?","options":["Submit the updated Medical Examiner's Certificate to KYTC through mycdl.ky.gov so the driving record stays current","Keep the certificate only in the cab and show it to police if asked","Mail the certificate to the FMCSA National Registry instead of the state","Take the knowledge test again to revalidate the certificate"],"answer":0,"explanation":"To avoid being downgraded to 'not certified,' the driver must submit each new Medical Examiner's Certificate to KYTC, typically via the mycdl.ky.gov portal, so it posts to the CDLIS driving record. Source: KYTC first-time applicant info; 49 CFR 383.71/383.73.","handbook":"","hbref":""},{"q":"Which statement about renewing a Kentucky CDL is correct regarding the mail/online process?","options":["A CDL generally cannot be renewed by mail and requires an in-person renewal","A CDL is renewed automatically and mailed without any application","A CDL can always be renewed online with no documents","A CDL never expires once the driver passes the skills test"],"answer":0,"explanation":"Class A, B, or C (CDL) credentials generally cannot be renewed by mail; an in-person renewal with current medical certification is required. Source: KRS 281A.170; KYTC drive.ky.gov.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная допустимая ширина коммерческого транспортного средства на межштатных и установленных автомагистралях Кентукки (без учёта одобренных элементов безопасности, таких как зеркала)?","options":["8 футов 3 дюйма (99 дюймов)","8 футов 6 дюймов (102 дюйма)","8 футов 0 дюймов (96 дюймов)","9 футов 0 дюймов (108 дюймов)"],"explanation":"Кентукки ограничивает ширину транспортного средства до 8 футов 6 дюймов (102 дюйма) на межштатных и установленных автомагистралях, что соответствует 23 CFR 658. Источник: страница Legal Dimensions Kentucky DRIVE (KYTC); KRS 189.221/189.222."},"1":{"q":"Какова максимальная допустимая ширина транспортного средства на обслуживаемых штатом автомагистралях Кентукки, которые НЕ являются межштатными или иным образом установленными автомагистралями?","options":["8 футов (96 дюймов)","8 футов 6 дюймов (102 дюйма)","7 футов 6 дюймов (90 дюймов)","9 футов (108 дюймов)"],"explanation":"На неустановленных обслуживаемых штатом дорогах Кентукки допустимая ширина снижается до 8 футов (96 дюймов); допуск в 8'6\" применяется только к межштатной и установленной системе автомагистралей. Источник: страница Legal Dimensions Kentucky DRIVE (KYTC); KRS 189.221."},"2":{"q":"Какова максимальная допустимая высота транспортного средства на автомагистралях Кентукки, прежде чем потребуется разрешение на превышение габаритов?","options":["14 футов 0 дюймов","14 футов 6 дюймов","13 футов 0 дюймов","13 футов 6 дюймов"],"explanation":"Кентукки устанавливает допустимую максимальную высоту транспортного средства и груза в 13 футов 6 дюймов; всё, что выше, требует разрешения на превышение габаритов. Источник: страница Legal Dimensions Kentucky DRIVE (KYTC); KRS 189.222."},"3":{"q":"Какова максимальная допустимая длина одиночного полуприцепа, эксплуатируемого в межштатной и установленной системе автомагистралей Кентукки?","options":["45 футов","57 футов","53 фута","48 футов"],"explanation":"Одиночный полуприцеп может иметь длину до 53 футов на межштатных и установленных автомагистралях Кентукки. Источник: страница Legal Dimensions Kentucky DRIVE (KYTC); KRS 189.221/189.222."},"4":{"q":"В сцепке из двух прицепов (двойной), эксплуатируемой в Кентукки, какова максимальная допустимая длина каждого отдельного прицепа?","options":["26 футов каждый","28 футов каждый","30 футов каждый","32 фута каждый"],"explanation":"Кентукки разрешает сдвоенные/двойные прицепы длиной до 28 футов каждый, что соответствует федерально защищённому габариту для двойных прицепов. Источник: страница Legal Dimensions Kentucky DRIVE (KYTC); KRS 189.222."},"5":{"q":"Какова максимальная допустимая длина одиночного грузового автомобиля на автомагистралях Кентукки?","options":["45 футов","53 фута","48 футов","40 футов"],"explanation":"Одиночный грузовой автомобиль ограничен длиной 45 футов согласно правилам о габаритах Кентукки. Источник: страница Legal Dimensions Kentucky DRIVE (KYTC); KRS 189.221."},"6":{"q":"На обслуживаемых штатом автомагистралях Кентукки, которые НЕ входят в установленную систему, какова максимальная общая длина сцепки тягача с прицепом?","options":["75 футов","70 футов","60 футов","65 футов"],"explanation":"На неустановленных обслуживаемых штатом дорогах общая длина сцепки ограничена 65 футами, несмотря на то что на установленных автомагистралях разрешён 53-футовый полуприцеп. Источник: страница Legal Dimensions Kentucky DRIVE (KYTC); KRS 189.221."},"7":{"q":"Каков максимальный допустимый полный вес коммерческого транспортного средства с грузом на автомагистралях Кентукки без разрешения на перевес?","options":["84,000 фунтов","88,000 фунтов","80,000 фунтов","73,280 фунтов"],"explanation":"Кентукки ограничивает общий полный вес транспортного средства до 80,000 фунтов, что соответствует федеральному стандарту для межштатных автомагистралей. Источник: KRS 189.222; 603 KAR 5:066; Kentucky DRIVE (KYTC)."},"8":{"q":"Каков максимальный допустимый вес, который может приходиться на одиночную ось в Кентукки?","options":["22,400 фунтов","20,000 фунтов","18,000 фунтов","24,000 фунтов"],"explanation":"Ни одна одиночная ось не может превышать 20,000 фунтов в Кентукки (или 700 фунтов на дюйм суммарной ширины шин, в зависимости от того, что меньше). Источник: KRS 189.222; 603 KAR 5:066."},"9":{"q":"Каков максимальный допустимый вес на группу спаренных осей (с расстоянием между осями от 42 до 96 дюймов) в Кентукки?","options":["34,000 фунтов","36,000 фунтов","40,000 фунтов","32,000 фунтов"],"explanation":"Группа спаренных осей с расстоянием между осями от 42 до 96 дюймов ограничена 34,000 фунтами в Кентукки. Источник: KRS 189.222; 603 KAR 5:066; Kentucky DRIVE (KYTC) Legal Dimensions."},"10":{"q":"В Кентукки каков максимальный допустимый вес на группу из трёх осей (тридем) с расстоянием между осями от 42 до 120 дюймов?","options":["45,000 фунтов","42,000 фунтов","51,000 фунтов","48,000 фунтов"],"explanation":"Группа из трёх осей (тридем) с расстоянием между осями от 42 до 120 дюймов допускается до 48,000 фунтов в Кентукки. Источник: KRS 189.222; страница Legal Dimensions Kentucky DRIVE (KYTC)."},"11":{"q":"Кентукки допускает допуск по весу на оси, но только на определённых дорогах. На каких автомагистралях применяется 5-процентный допуск по весу на оси?","options":["Только на дорогах, обслуживаемых округом","На всех автомагистралях, включая межштатную систему","На обслуживаемых штатом автомагистралях, которые НЕ входят в межштатную систему","Только на межштатной системе"],"explanation":"Кентукки допускает допуск не более 5 процентов по весу на оси на обслуживаемых штатом автомагистралях, которые не входят в межштатную систему; на межштатной системе такого допуска по осям нет. Источник: KRS 189.222."},"12":{"q":"Согласно закону Кентукки, как применяется 5-процентный допуск по весу к ПОЛНОМУ весу транспортного средства?","options":["5-процентный допуск применяется только на межштатной системе","Допуск по полному весу не разрешён","10-процентный допуск применяется на дорогах вне межштатной системы","5-процентный допуск применяется на всех дорогах"],"explanation":"Кентукки прямо НЕ допускает никакого допуска по полному весу; 5-процентный допуск применяется только к весу на оси на обслуживаемых штатом автомагистралях вне межштатной системы. Источник: KRS 189.222."},"13":{"q":"Кентукки использует федеральную мостовую формулу для ограничения веса на группы последовательных осей. С чем эта формула в первую очередь связывает полный вес?","options":["С количеством осей и расстоянием (дистанцией) между ними","С количеством шин и их давлением воздуха","С мощностью двигателя и номинальным полным весом сцепки","С длиной прицепа и плотностью груза"],"explanation":"Федеральная мостовая формула W=500(LN/(N-1)+12N+36) ограничивает вес на любую группу из двух или более последовательных осей в зависимости от количества осей (N) и расстояния (L) между крайними осями группы. Кентукки применяет её через принятие 23 CFR Part 658. Источник: 23 CFR 658.17; KRS 189.222."},"14":{"q":"В федеральной мостовой формуле W = 500(LN/(N-1) + 12N + 36), используемой в Кентукки, что обозначает переменная 'L'?","options":["Допустимый вес груза в тоннах","Подъёмную способность подвески","Длину прицепа в футах","Расстояние в футах между крайними осями группы"],"explanation":"В мостовой формуле L — это расстояние в футах между крайними осями любой группы из двух или более последовательных осей, а N — количество осей в этой группе. Источник: 23 CFR 658.17 (мостовая формула), принятая в Кентукки согласно KRS 189.222."},"15":{"q":"Два последовательных комплекта спаренных осей могут каждый нести полные 34,000 фунтов в Кентукки только при условии, что расстояние между первой и последней осями этих спаренных групп составляет не менее скольких футов?","options":["28 футов","40 футов","36 футов","30 футов"],"explanation":"Согласно исключению из мостовой формулы, принятому Кентукки, два последовательных комплекта спаренных осей могут каждый нести 34,000 фунтов только тогда, когда общее расстояние между первой и последней осями этих спаренных групп составляет 36 футов или более. Источник: 23 CFR 658.17; KRS 189.222."},"16":{"q":"Когда требуется разрешение Кентукки на превышение габаритов/перевес (OS/OW)?","options":["Только при движении по дорогам округа","Перед перемещением любого транспортного средства или груза, превышающего допустимые ограничения по ширине, высоте, длине или весу","Только когда полный вес превышает 90,000 фунтов","Только когда груз шире 10 футов"],"explanation":"Разрешение Кентукки должно быть получено ДО перемещения любого транспортного средства или груза, превышающего установленные законом ограничения по ширине, высоте, длине или весу. Источник: KYTC Division of Motor Carriers; 601 KAR 1:018."},"17":{"q":"Какое ведомство Кентукки выдаёт специальные разрешения на перевес/превышение габаритов для перевозки грузов, и что, как правило, не может получить такое разрешение?","options":["KYTC Division of Motor Carriers; разумно делимые грузы, как правило, не могут получить разрешение","U.S. DOT; разрешение могут получить только межштатные грузы","Kentucky State Police; разрешение могут получить только сельскохозяйственные грузы","Окружные фискальные суды; разрешение могут получить только лесопродукты"],"explanation":"Division of Motor Carriers Транспортного кабинета Кентукки выдаёт разрешения OS/OW согласно 601 KAR 1:018, и разрешения, как правило, НЕ выдаются на грузы, которые разумно делимы (могут быть разобраны или разделены для соблюдения допустимых ограничений). Источник: 601 KAR 1:018; KRS 189.270."},"18":{"q":"Кентукки предоставляет специальное исключение для неделимой сельскохозяйственной техники. Что это позволяет?","options":["Сельскохозяйственная техника может перемещаться любой ширины без разрешения на двухполосных дорогах","Сельскохозяйственная техника может превышать 120,000 фунтов на межштатной системе без разрешения","Сельскохозяйственная техника освобождена от всех правил о разрешениях и весе по всему штату","Может быть выдано разрешение на одну поездку для неделимой сельскохозяйственной техники, превышающей допустимые ограничения по весу или габаритам"],"explanation":"Кентукки выдаёт разрешение на одну поездку для перевеса/превышения габаритов при перемещении неделимой сельскохозяйственной техники, превышающей ограничения KRS 189.222 или 189.270; это разрешённое исключение, а не общее освобождение. Источник: 601 KAR 1:019; 601 KAR 1:018."},"19":{"q":"Согласно системе дорог Кентукки для повышенной массы при перевозке угля (Extended-Weight Coal Haul Road System, ECWHRS), с каким максимальным полным весом может эксплуатироваться тягач с полуприцепом с 5 или более осями, перевозящий уголь?","options":["90,000 фунтов (с допуском 5 процентов)","80,000 фунтов (без допуска)","120,000 фунтов (с допуском 5 процентов)","100,000 фунтов (с допуском 10 процентов)"],"explanation":"В системе дорог для повышенной массы при перевозке угля тягач с полуприцепом с пятью или более осями, перевозящий уголь или побочные продукты угля, может эксплуатироваться с полным весом до 120,000 фунтов с допуском 5 процентов. Источник: KRS 177.9771."},"20":{"q":"В Кентукки CDL класса A требуется для управления любой сцепкой транспортных средств с номинальным полным весом сцепки (GCWR) 26,001 фунт или более при условии, что GVWR буксируемого(ых) транспортного(ых) средства(средств) превышает какой вес?","options":["10,000 фунтов","26,001 фунт","16,000 фунтов","1,000 фунтов"],"explanation":"Кентукки требует CDL класса A для сцепок с GCWR 26,001 фунт или более, когда буксируемая(ые) единица(ы) имеет(ют) GVWR более 10,000 фунтов. Источник: Kentucky CDL Manual (KYTC, март 2025), 'Who Must Apply? - Class A CDL.'"},"21":{"q":"Согласно правилам Кентукки, CDL класса B требуется для управления любым одиночным транспортным средством с номинальным полным весом (GVWR) не менее скольких фунтов?","options":["10,001 фунт","26,001 фунт","33,000 фунтов","16,001 фунт"],"explanation":"CDL класса B охватывает любое одиночное транспортное средство с GVWR 26,001 фунт или более, включая такое транспортное средство, буксирующее единицу с GVWR 10,000 фунтов или менее. Источник: Kentucky CDL Manual (KYTC, март 2025), 'Class B CDL.'"},"22":{"q":"Согласно руководству Kentucky CDL Manual, транспортное средство с GVWR менее 26,001 фунта требует CDL класса C, когда оно предназначено для перевозки не менее скольких человек, включая водителя?","options":["15","24","16","9"],"explanation":"Кентукки требует CDL класса C для транспортного средства с GVWR менее 26,001 фунта, которое перевозит 16 или более пассажиров, включая водителя, или которое перевозит опасные материалы, требующие плакатной маркировки. Источник: Kentucky CDL Manual (KYTC, март 2025), 'Class C CDL.'"},"23":{"q":"В Кентукки какой класс CDL применяется к транспортному средству с GVWR менее 26,001 фунта, которое перевозит опасные материалы в количествах, требующих плакатной маркировки?","options":["Класс A","Класс B","Класс D","Класс C"],"explanation":"CDL класса C охватывает транспортные средства с GVWR менее 26,001 фунта, которые перевозят опасные материалы, требующие плакатной маркировки, или 16+ пассажиров (включая водителя). Источник: Kentucky CDL Manual (KYTC, март 2025), 'Class C CDL.'"},"24":{"q":"Каков минимальный возраст, в котором Кентукки может выдать CDL, ограниченный внутриштатной коммерцией (с ограничением 'K')?","options":["21 год","18 лет","19 лет","16 лет"],"explanation":"Кентукки может выдать CDL определённого класса с ограничением 'K' (только внутриштатная) лицу в возрасте от 18 до 20 лет, которое отвечает требованиям тестирования и не управляет школьным автобусом и не перевозит опасные материалы. Источник: Kentucky CDL Manual (KYTC, март 2025), 'Individual Eighteen (18) Years of Age Driving Intrastate.'"},"25":{"q":"Владелец CDL Кентукки, желающий управлять коммерческим автотранспортным средством в межштатной коммерции (через границы штатов, без ограничений), должен быть не моложе скольких лет?","options":["18 лет","19 лет","21 год","25 лет"],"explanation":"Водители в возрасте 18-20 лет ограничены внутриштатной коммерцией Кентукки (ограничение 'K'); водителю должен быть 21 год, чтобы управлять без этого ограничения в межштатной коммерции. Источник: Kentucky CDL Manual (KYTC, март 2025), раздел о возрасте для внутриштатной коммерции."},"26":{"q":"После выдачи учебного разрешения CDL Кентукки (CLP), как долго заявитель должен иметь это разрешение, прежде чем можно будет провести экзамен по навыкам вождения?","options":["30 дней","10 дней","60 дней","14 дней"],"explanation":"Разрешение должно удерживаться 14 дней до проведения экзамена по навыкам, что соответствует федеральному правилу о CLP. Источник: Kentucky CDL Manual (KYTC, март 2025), 'How to Apply for a CDL.'"},"27":{"q":"Как долго действует учебное разрешение CDL Кентукки (CLP)?","options":["6 месяцев","12 месяцев","30 дней","180 дней с неограниченным продлением"],"explanation":"Учебное разрешение CDL Кентукки действует шесть (6) месяцев. Оно может быть продлено только один раз, прежде чем заявителю придётся подавать заявление заново. Источник: Kentucky CDL Manual (KYTC, март 2025), 'How to Apply for a CDL' и раздел ELDT."},"28":{"q":"Сколько раз учебное разрешение CDL Кентукки может быть продлено, прежде чем заявителю придётся подавать заявление заново (и оплачивать все сборы и повторно сдавать письменные экзамены)?","options":["Дважды","Оно не может быть продлено","Один раз","Неограниченное количество раз"],"explanation":"Разрешение CDL Кентукки может быть продлено только один раз; если экзамен по навыкам вождения не сдан до истечения срока продлённого разрешения, заявитель должен подать заявление заново со всеми сборами и письменными экзаменами. Источник: Kentucky CDL Manual (KYTC, март 2025), 'Entry Level Driver Training (ELDT).'"},"29":{"q":"Какое дополнение (endorsement) требуется на CDL Кентукки для управления транспортным средством, предназначенным для перевозки пассажиров, таким как транзитный или чартерный автобус?","options":["S (School Bus)","N (Tank)","T (Doubles/Triples)","P (Passenger)"],"explanation":"Дополнение P (Passenger) требуется для перевозки пассажиров; для его добавления необходимо полностью сдать экзамен по навыкам на пассажирском транспортном средстве того класса, на который подаётся заявление. Источник: Kentucky CDL Manual (KYTC, март 2025), 'Endorsements' и 'Adding a Passenger endorsement.'"},"30":{"q":"Чтобы управлять школьным автобусом в Кентукки, владелец CDL должен получить дополнение S (School Bus) вдобавок к какому другому дополнению?","options":["P (Passenger)","N (Tank)","H (HazMat)","T (Doubles/Triples)"],"explanation":"Водители школьных автобусов должны иметь дополнение School Bus (S) вдобавок к дополнению Passenger (P), а также сдать теоретический экзамен и все три части экзамена по навыкам на том классе школьного автобуса, которым предстоит управлять. Источник: Kentucky CDL Manual (KYTC, март 2025), раздел о дополнении для школьного автобуса."},"31":{"q":"В теоретических экзаменах CDL Кентукки экзамен на дополнение для опасных материалов (H) содержит сколько вопросов?","options":["20 вопросов","30 вопросов","50 вопросов","25 вопросов"],"explanation":"Теоретический экзамен Кентукки на дополнение HazMat содержит 30 вопросов, тогда как экзамены на дополнения Doubles/Triples, Tanker, Passenger и School Bus содержат по 20 каждый. Источник: Kentucky CDL Manual (KYTC, март 2025), 'Endorsements are required for the following vehicles.'"},"32":{"q":"Перед выдачей или продлением дополнения для опасных материалов (H) в Кентукки заявитель должен пройти дактилоскопию и проверку безопасности, обрабатываемую ФБР и каким федеральным ведомством?","options":["Federal Motor Carrier Safety Administration (FMCSA)","Береговая охрана Министерства внутренней безопасности","Federal Highway Administration (FHWA)","Transportation Security Administration (TSA)"],"explanation":"У заявителей на HazMat снимают отпечатки пальцев, а заявление направляется в ФБР и Transportation Security Administration (TSA) для оценки угрозы безопасности перед тестированием. Карта TWIC может служить подтверждением прохождения такой оценки. Источник: Kentucky CDL Manual (KYTC, март 2025), раздел о дополнении HazMat."},"33":{"q":"Какое дополнение CDL Кентукки требуется для буксировки двойных или тройных прицепов?","options":["T","N","H","X"],"explanation":"Дополнение T (Doubles/Triples) требуется для буксировки двойных или тройных прицепов и требует сдачи теоретического экзамена из 20 вопросов. Источник: Kentucky CDL Manual (KYTC, март 2025), 'Endorsements.'"},"34":{"q":"Какое дополнение нужно водителю CDL Кентукки для перевозки жидкостей или газов в наливном цистерновом транспортном средстве (цистерне)?","options":["T (Doubles/Triples)","N (Tank)","P (Passenger)","H (HazMat)"],"explanation":"Дополнение N (Tank) требуется для управления цистерновым транспортным средством, перевозящим жидкий или газообразный наливной груз, и требует теоретического экзамена из 20 вопросов. Источник: Kentucky CDL Manual (KYTC, март 2025), 'Endorsements.'"},"35":{"q":"Начиная с 7 февраля 2022 года, федеральное начальное обучение водителей (ELDT) должно быть пройдено в Кентукки до первого получения CDL класса A или B, и обучение должно осуществляться поставщиком, включённым куда?","options":["Реестр тестирования Kentucky State Police","Любой список региональных офисов KYTC","FMCSA Training Provider Registry","Клиринговый центр CDLIS"],"explanation":"ELDT согласно 49 CFR part 380 должно быть пройдено до первого получения CDL класса A/B, повышения класса или первого дополнения H, P или S, у поставщика, включённого в FMCSA Training Provider Registry. Источник: Kentucky CDL Manual (KYTC, март 2025), 'Entry Level Driver Training (ELDT).'"},"36":{"q":"Для чего из перечисленного Кентукки НЕ требует начального обучения водителей (ELDT) перед первым добавлением?","options":["Дополнение H (HazMat)","Дополнение N (Tank)","Дополнение P (Passenger)","Дополнение S (School Bus)"],"explanation":"ELDT требуется для первого получения CDL класса A/B, повышения класса и первого дополнения H, P или S; дополнение Tank (N) не входит в перечень ELDT. Источник: Kentucky CDL Manual (KYTC, март 2025), 'Entry Level Driver Training (ELDT)'; 49 CFR part 380."},"37":{"q":"Какую категорию медицинской самосертификации должен выбрать заявитель на CDL в Кентукки, если он работает или ожидает, что будет работать только в пределах Кентукки (внутриштатно) и НЕ освобождён от медицинских требований?","options":["Excepted Intrastate (EA)","Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)"],"explanation":"Водитель, работающий только в Кентукки, который должен иметь медицинскую сертификацию, выбирает Non-Excepted Intrastate (NA). Поле Excepted Intrastate (EA) в Кентукки не используется, поскольку все владельцы CDL в Кентукки должны иметь медицинскую сертификацию. Источник: KYTC Commercial Driver License Self-Certification form (TC 94-169); 601 KAR 1:005."},"38":{"q":"В форме самосертификации CDL Кентукки какая категория медицинской сертификации недоступна и никогда не должна выбираться, поскольку все владельцы CDL в Кентукки должны иметь медицинскую сертификацию?","options":["Excepted Intrastate (EA)","Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)"],"explanation":"Кентукки не допускает категорию Excepted Intrastate (EA); каждый владелец CDL в Кентукки должен иметь медицинскую сертификацию, поэтому EA никогда не должна отмечаться. Остальные три (NI, EI, NA) являются допустимыми вариантами. Источник: KYTC Commercial Driver License Self-Certification form (TC 94-169); 601 KAR 1:005."},"39":{"q":"Что на CDL Кентукки обозначает код ограничения 'K'?","options":["Запрет на CMV, оснащённый пневматическими тормозами","Запрет на груз в цистерновом транспортном средстве","Внутриштатная (только в пределах Кентукки) эксплуатация","Запрет на пассажиров в автобусе CMV"],"explanation":"Ограничение 'K' ограничивает владельца внутриштатной коммерцией в пределах Кентукки и применяется к водителям моложе 21 года и другим лицам, ограниченным внутриштатным вождением. (Для справки: X = запрет на груз в цистерне, L = запрет на пневматические тормоза, P = запрет на пассажиров в автобусе CMV.) Источник: Kentucky CDL Manual (KYTC, март 2025), 'Restrictions.'"},"40":{"q":"При управлении коммерческим автотранспортным средством (CMV) в Кентукки, какая концентрация алкоголя в крови (BAC) является законным порогом, при котором водитель считается управляющим в состоянии опьянения и дисквалифицируется?","options":["0.04 или выше","0.08 или выше","0.02 или выше","0.10 или выше"],"explanation":"Кентукки устанавливает предел BAC для CMV в 0.04 или выше, что вдвое меньше предела 0.08 для обычных водителей. Управление CMV при BAC 0.04 или выше является тяжким нарушением, влекущим дисквалификацию. Источник: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51."},"41":{"q":"В Кентукки первое осуждение за тяжкое нарушение (например, DUI в CMV) приводит к дисквалификации CDL на какой срок?","options":["1 год","60 дней","6 месяцев","3 года"],"explanation":"Первое тяжкое нарушение дисквалифицирует водителя на 1 год (3 года, если в момент нарушения перевозились опасные материалы с плакатной маркировкой). Источник: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 1."},"42":{"q":"Если владелец CDL Кентукки совершает первое тяжкое нарушение при перевозке опасных материалов с плакатной маркировкой, срок дисквалификации увеличивается до какого периода?","options":["3 года","1 год","5 лет","2 года"],"explanation":"Первое тяжкое нарушение при перевозке опасных материалов с плакатной маркировкой увеличивает дисквалификацию с 1 года до 3 лет. Источник: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 1."},"43":{"q":"Согласно закону Кентукки о подразумеваемом согласии, управляя коммерческим автотранспортным средством, водитель считается давшим согласие на химический анализ каких веществ?","options":["Крови, дыхания или мочи на алкоголь или наркотики","Только дыхания на алкоголь","Только крови на наркотики","Только мочи на контролируемые вещества"],"explanation":"Закон Кентукки о подразумеваемом согласии считает каждого оператора CMV давшим согласие на анализ крови, дыхания или мочи для обнаружения алкоголя или контролируемых веществ, когда у сотрудника есть разумное основание. Источник: Kentucky CDL Manual (KYTC), KRS 281A.150/281A.190."},"44":{"q":"Что в Кентукки происходит с владельцем CDL, который отказывается пройти требуемый химический анализ дыхания, крови или мочи?","options":["Рассматривается как тяжкое нарушение — дисквалификация не менее чем на 1 год","Только предупреждение при первом отказе","Дисквалификация на 60 дней","Приостановка на 30 дней и штраф"],"explanation":"Отказ от анализа сам по себе является тяжким нарушением, влекущим ту же дисквалификацию, что и осуждение за DUI: не менее 1 года (3 года при перевозке HazMat с плакатной маркировкой). Источник: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 1."},"45":{"q":"Владелец CDL Кентукки осуждён за второе тяжкое нарушение в отдельном случае. Каков срок дисквалификации?","options":["Пожизненная дисквалификация","10 лет","5 лет","3 года"],"explanation":"Второе тяжкое нарушение в отдельном случае приводит к пожизненной дисквалификации CDL. Источник: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 1."},"46":{"q":"Через сколько лет водитель Кентукки, дисквалифицированный пожизненно, может потенциально получить право на восстановление при условии соблюдения требований, таких как прохождение одобренной программы реабилитации?","options":["10 лет","5 лет","7 лет","15 лет"],"explanation":"Штат может восстановить пожизненно дисквалифицированного водителя минимум через 10 лет, если лицо проходит одобренную программу реабилитации; некоторые тяжкие преступления, связанные с наркотиками/торговлей, никогда не дают права на восстановление. Источник: Kentucky CDL Manual (KYTC); 49 CFR 383.51."},"47":{"q":"Даже ниже дисквалифицирующего уровня 0.04, что происходит с водителем CMV в Кентукки, у которого обнаружено любое определяемое количество алкоголя в организме?","options":["Отстраняется от работы на 24 часа","Немедленно дисквалифицируется на 1 год","Штрафуется на $100 без иных мер","Получает дисквалификацию на 60 дней"],"explanation":"Водитель с любым измеримым количеством алкоголя ниже 0.04 отстраняется от работы на 24 часа. Достижение 0.04 или выше является тяжким нарушением. Источник: Kentucky CDL Manual (KYTC); 49 CFR 392.5."},"48":{"q":"В Кентукки осуждение за два серьёзных нарушения правил дорожного движения в CMV в течение 3-летнего периода (отдельные случаи) приводит к дисквалификации на какой срок?","options":["60 дней","30 дней","120 дней","90 дней"],"explanation":"Два серьёзных нарушения правил дорожного движения в течение 3 лет (отдельные случаи) приводят к дисквалификации на 60 дней. Источник: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 2."},"49":{"q":"В Кентукки осуждение за три серьёзных нарушения правил дорожного движения в CMV в течение 3-летнего периода (отдельные случаи) приводит к дисквалификации на какой срок?","options":["120 дней","60 дней","180 дней","1 год"],"explanation":"Три серьёзных нарушения правил дорожного движения в течение 3 лет (отдельные случаи) приводят к дисквалификации на 120 дней, отбываемой последовательно с другими дисквалификациями. Источник: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 2."},"50":{"q":"Что из перечисленного классифицируется как серьёзное нарушение правил дорожного движения для владельца CDL Кентукки?","options":["Превышение скорости на 15 mph или более сверх установленного предела","Превышение скорости на 5 mph сверх установленного предела","Одно нарушение правил парковки","Управление с просроченным стикером регистрации"],"explanation":"Чрезмерное превышение скорости (на 15 mph или более сверх предела) является серьёзным нарушением правил дорожного движения, наряду с неосторожным вождением, неправильной сменой полосы, слишком близким следованием, набором текстовых сообщений и использованием ручного телефона. Источник: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 2."},"51":{"q":"Для целей CDL Кентукки, как рассматривается набор текстовых сообщений во время управления CMV при учёте в счёт дисквалификации?","options":["Как серьёзное нарушение правил дорожного движения","Как тяжкое нарушение","Как нарушение предписания об отстранении от эксплуатации","Это не влечёт последствий для CDL"],"explanation":"Набор текстовых сообщений во время управления CMV является серьёзным нарушением правил дорожного движения; два в течение 3 лет влекут дисквалификацию на 60 дней, а три — на 120 дней. Источник: Kentucky CDL Manual (KYTC); 49 CFR 383.51 и 49 CFR 392.80."},"52":{"q":"Использование ручного мобильного телефона во время управления CMV в Кентукки запрещено и учитывается в счёт дисквалификации CDL как нарушение какого типа?","options":["Серьёзное нарушение правил дорожного движения","Тяжкое нарушение","Нарушение на железнодорожном переезде","Нарушение предписания об отстранении от эксплуатации"],"explanation":"Использование ручного телефона во время управления CMV является серьёзным нарушением правил дорожного движения; два в течение 3 лет влекут дисквалификацию на 60 дней, три — на 120 дней. Источник: Kentucky CDL Manual (KYTC); 49 CFR 383.51 и 49 CFR 392.82."},"53":{"q":"Первое осуждение за нарушение на железнодорожном переезде в одном уровне в CMV приводит к дисквалификации CDL Кентукки на срок не менее какого?","options":["60 дней","30 дней","120 дней","1 год"],"explanation":"Первое нарушение на железнодорожном переезде в одном уровне влечёт дисквалификацию не менее чем на 60 дней. Источник: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 3."},"54":{"q":"Второе нарушение на железнодорожном переезде в одном уровне в течение 3-летнего периода приводит к дисквалификации CDL Кентукки на срок не менее какого?","options":["120 дней","60 дней","180 дней","1 год"],"explanation":"Второе нарушение на переезде в одном уровне в течение 3 лет влечёт дисквалификацию не менее чем на 120 дней. Источник: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 3."},"55":{"q":"Третье или последующее нарушение на железнодорожном переезде в одном уровне в течение 3-летнего периода приводит к дисквалификации CDL Кентукки на срок не менее какого?","options":["1 год","120 дней","180 дней","60 дней"],"explanation":"Третье или последующее нарушение на переезде в одном уровне в течение 3 лет влечёт дисквалификацию не менее чем на 1 год. Источник: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 3."},"56":{"q":"Что из перечисленного является нарушением на железнодорожном переезде в одном уровне, которое может дисквалифицировать владельца CDL Кентукки?","options":["Выезд на переезд без достаточного пространства для его полного проезда","Остановка за 50 футов до путей для проверки наличия поездов","Снижение скорости и проверка того, что пути свободны","Уступание дороги поезду, имеющему преимущественное право проезда"],"explanation":"Выезд на переезд без достаточного пространства для проезда путей является нарушением, как и непринятие мер для снижения скорости/проверки, неостановка при необходимости и недостаточный клиренс ходовой части. Источник: Kentucky CDL Manual (KYTC); 49 CFR 383.51 Table 3."},"57":{"q":"Владелец CDL Кентукки, нарушивший предписание об отстранении от эксплуатации впервые (без HazMat, без пассажиров), дисквалифицируется на срок не менее какого?","options":["180 дней","60 дней","90 дней","1 год"],"explanation":"Первое нарушение предписания об отстранении от эксплуатации влечёт дисквалификацию не менее чем на 180 дней (до 1 года). Источник: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 4."},"58":{"q":"За второе нарушение предписания об отстранении от эксплуатации в течение 10-летнего периода владелец CDL Кентукки дисквалифицируется на срок не менее какого?","options":["2 года","180 дней","1 год","3 года"],"explanation":"Второе нарушение предписания об отстранении от эксплуатации в течение 10 лет влечёт дисквалификацию не менее чем на 2 года (до 5 лет). Источник: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 4."},"59":{"q":"Третье или последующее нарушение предписания об отстранении от эксплуатации в течение 10-летнего периода приводит к дисквалификации CDL Кентукки на срок не менее какого?","options":["3 года","2 года","1 год","5 лет"],"explanation":"Третье или последующее нарушение предписания об отстранении от эксплуатации в течение 10 лет влечёт дисквалификацию не менее чем на 3 года (до 5 лет). Источник: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 4."},"60":{"q":"Согласно закону Кентукки «Сбавь скорость, перестройся» (Slow Down, Move Over), когда водитель с CDL приближается на многополосном шоссе к остановившемуся автомобилю экстренных или общественных служб с включёнными проблесковыми маячками, какова ПЕРВАЯ обязанность водителя, если это можно сделать безопасно?","options":["Продолжать движение с установленной скоростью, оставаясь в той же полосе","Полностью остановиться, пока автомобиль экстренной службы не уедет","Освободить полосу, ближайшую к остановившемуся автомобилю, перестроившись на одну полосу в сторону","Подать звуковой сигнал, чтобы предупредить спасателей о приближении грузовика"],"explanation":"Закон Кентукки о перестроении (KRS 189.930) требует, чтобы водитель на дороге с двумя или более полосами в одном направлении освободил полосу, ближайшую к остановившемуся автомобилю экстренных/общественных служб с включёнными проблесковыми маячками, когда это безопасно. Источник: KRS 189.930; Kentucky CDL Manual."},"61":{"q":"На двухполосной дороге в Кентукки, где водитель не может безопасно перестроиться, чтобы объехать остановившийся автомобиль экстренной службы с включёнными проблесковыми маячками, что вместо этого требует закон о перестроении?","options":["Снизить скорость до уровня, безопасного с учётом состояния дороги, погоды и условий движения","Полностью остановиться за 500 feet до автомобиля экстренной службы","Включить аварийную сигнализацию и держать максимально разрешённую скорость","Съехать на обочину и ждать, пока пропустят"],"explanation":"Согласно KRS 189.930, если перестроение невозможно или небезопасно, водитель должен снизить скорость до безопасной с учётом фактического состояния дороги, погоды и условий движения и продолжать движение с осторожностью. Источник: KRS 189.930."},"62":{"q":"В июле 2024 года Кентукки расширил действие своего закона о перестроении. Помимо полиции, пожарных и машин скорой помощи, расширенный закон теперь также требует от водителей перестраиваться или снижать скорость для чего из перечисленного?","options":["Любого стоящего транспортного средства с включённой аварийной сигнализацией или предупреждающими сигналами, включая неисправные автомобили и эвакуаторы","Только обозначенных полицейских патрульных машин","Только транспортных средств, активно блокирующих полосу движения","Только транспортных средств, принадлежащих Kentucky Transportation Cabinet"],"explanation":"Расширение KRS 189.930 в июле 2024 года распространило защиту на любое стоящее транспортное средство с проблесковыми маячками, аварийной сигнализацией или предупреждающими устройствами, например эвакуаторы/аварийные машины и неисправные автомобили, а не только на традиционные службы экстренного реагирования. Источник: KRS 189.930 (поправка 2024 года)."},"63":{"q":"Водитель с CDL в Кентукки перевозит маркированный груз опасных материалов и приближается к железнодорожному переезду. В пределах какого расстояния от ближайшего рельса водитель должен остановиться?","options":["Не менее 5 feet и не более 25 feet","Не менее 15 feet и не более 50 feet","Не менее 25 feet и не более 75 feet","Не менее 50 feet и не более 100 feet"],"explanation":"Водитель транспортного средства с маркировкой HazMat должен остановиться в пределах 50 feet, но не ближе 15 feet к ближайшему рельсу перед переездом (правило «от 15 до 50 feet»). Источник: 49 CFR 392.10, принятое в Кентукки; Kentucky CDL Manual."},"64":{"q":"Какое из этих коммерческих транспортных средств ОБЯЗАНО останавливаться на каждом железнодорожном переезде согласно правилам, изложенным в Kentucky CDL Manual?","options":["Пустой тягач с прицепом-платформой","Автобус с пассажирами","Фургон, перевозящий обычный груз","Самосвал, перевозящий гравий"],"explanation":"Автобусы с пассажирами и транспортные средства с маркировкой опасных материалов должны останавливаться на железнодорожных переездах, останавливаясь в пределах от 15 до 50 feet от ближайшего рельса. Грузовики с обычным грузом не обязаны останавливаться, если этого не требуют сигналы. Источник: 49 CFR 392.10; Kentucky CDL Manual."},"65":{"q":"Согласно закону Кентукки о школьных автобусах, на четырёхполосном шоссе школьный автобус останавливается с включёнными красными мигающими огнями и выдвинутым знаком «Стоп». Какие водители НЕ обязаны останавливаться?","options":["Водители на соседней с автобусом полосе, движущиеся в том же направлении","Водители непосредственно за автобусом в той же полосе","Все водители должны остановиться независимо от направления или числа полос","Водители, приближающиеся со встречного направления на шоссе с четырьмя или более полосами"],"explanation":"Согласно KRS 189.370, на шоссе с четырьмя или более полосами транспортные средства, приближающиеся со встречного направления к остановившемуся школьному автобусу, не обязаны останавливаться. Транспорт на стороне автобуса всё равно должен остановиться. Источник: KRS 189.370."},"66":{"q":"На обычном двухполосном шоссе в Кентукки школьный автобус останавливается с включёнными красными мигающими огнями и выдвинутым знаком «Стоп», чтобы посадить детей. Что должен делать встречный транспорт?","options":["Снизить скорость до 25 mph, но продолжать движение мимо автобуса","Остановиться и оставаться на месте, пока автобус не возобновит движение","Продолжать движение в обычном режиме, поскольку автобус находится по другую сторону осевой линии","Остановиться только в том случае, если видно, что дети переходят дорогу"],"explanation":"На двухполосной дороге KRS 189.370 требует, чтобы водители из ОБОИХ направлений остановились перед школьным автобусом, который сажает или высаживает детей с включёнными сигналами, и не продолжали движение, пока автобус снова не тронется. Исключение для встречного направления применяется только к шоссе с четырьмя или более полосами. Источник: KRS 189.370."},"67":{"q":"Требование Кентукки об остановке перед школьным автобусом (и исключение для встречного направления) основано на какой именно характеристике дороги?","options":["Числе полос на шоссе (четыре или более)","Том, составляет ли ограничение скорости 55 mph или выше","Том, является ли шоссе обозначенным парковым шоссе штата (state parkway)","Том, разделяет ли направления физический бетонный барьер"],"explanation":"KRS 189.370 связывает исключение для встречного направления конкретно с шоссе «из четырёх (4) или более полос», а не с наличием разделительного барьера или порогом скорости. Источник: KRS 189.370."},"68":{"q":"Закон Кентукки ограничивает движение определённых крупных транспортных средств по крайней левой полосе. На шоссе с тремя или более полосами в одном направлении каким транспортным средствам запрещено двигаться по крайней левой полосе, кроме случаев обгона, въезда или съезда?","options":["Мотоциклам и мопедам","Домам на колёсах и автодомам","Седельным тягачам, прицепам и полуприцепам","Всем легковым автомобилям и пикапам"],"explanation":"KRS 189.340 запрещает седельному тягачу, прицепу или полуприцепу двигаться по крайней левой полосе шоссе с тремя или более полосами в одном направлении, за исключением случаев обгона, въезда на шоссе или съезда с него, уступания дороги въезжающему транспорту или когда другие полосы небезопасны. Источник: KRS 189.340."},"69":{"q":"Согласно правилу Кентукки о движении грузовиков по левой полосе, что из перечисленного является законной причиной для полуприцепа находиться в крайней левой полосе трёхполосной автомагистрали?","options":["Поддержание постоянной крейсерской скорости для экономии топлива","Удержание дистанции от транспорта, въезжающего с пандусов, на протяжении всей поездки","Обгон более медленного транспортного средства с последующим возвращением вправо, как только это станет возможным","Движение немного ниже разрешённой скорости для экономии тормозов"],"explanation":"KRS 189.340 разрешает седельному тягачу/прицепу/полуприцепу использовать крайнюю левую полосу только по ограниченным причинам, таким как обгон (с последующим возвращением вправо, как только это станет возможным), въезд/съезд с шоссе, уступание дороги въезжающему транспорту или когда правые/средние полосы небезопасны. Источник: KRS 189.340."},"70":{"q":"Какова максимальная разрешённая скорость для грузовиков на загородных участках автомагистралей Кентукки, таких как I-64, I-65 и I-75?","options":["70 mph","65 mph","60 mph","75 mph"],"explanation":"Кентукки устанавливает максимум 70 mph на большинстве загородных участков автомагистралей; это применяется к грузовикам, если не установлен более низкий предел. Городские участки (например, вокруг Луисвилла и Лексингтона) обычно имеют ограничение 65 mph. Источник: KRS 189.390; установленные KYTC ограничения."},"71":{"q":"В городских районах вблизи Луисвилла и Лексингтона ограничение скорости на автомагистрали, которое следует ожидать водителю с CDL, чаще всего составляет:","options":["70 mph","65 mph","45 mph","55 mph"],"explanation":"Хотя на загородных автомагистралях Кентукки обычно установлено ограничение 70 mph, на городских участках автомагистралей вокруг таких мегаполисов, как Луисвилл и Лексингтон, обычно установлено ограничение 65 mph. Водители всегда должны соблюдать установленное ограничение. Источник: KRS 189.390; установленные KYTC ограничения."},"72":{"q":"Грузовик водителя с CDL сломался на обочине двухполосного шоссе Кентукки с двусторонним движением в дневное время. После выставления требуемых предупреждающих устройств, где следует разместить три светоотражающих треугольника?","options":["100 feet позади, 100 feet впереди и один рядом с кабиной","10 feet позади, 100 feet позади и 100 feet впереди транспортного средства","25 feet позади, 200 feet позади и 200 feet впереди транспортного средства","10 feet позади, 50 feet позади и 50 feet впереди транспортного средства"],"explanation":"На двухполосной дороге с двусторонним движением разместите один треугольник в пределах 10 feet от задней части, один примерно в 100 feet позади и один примерно в 100 feet впереди транспортного средства. Источник: 49 CFR 392.22, принятое в Кентукки; Kentucky CDL Manual."},"73":{"q":"Когда коммерческое транспортное средство остановилось на шоссе Кентукки с односторонним движением или на разделённом шоссе, где размещаются три предупреждающих устройства относительно приближающегося транспорта?","options":["100 feet позади и 100 feet впереди, плюс одно у кабины","10 feet, 100 feet и 200 feet в сторону приближающегося транспорта","200 feet, 200 feet и 500 feet в сторону приближающегося транспорта","10 feet, 50 feet и 100 feet в сторону приближающегося транспорта"],"explanation":"На шоссе с односторонним движением или разделённом шоссе разместите предупреждающие устройства в 10 feet, 100 feet и 200 feet в сторону приближающегося транспорта по центру полосы или обочины, занятой транспортным средством. Источник: 49 CFR 392.22; Kentucky CDL Manual."},"74":{"q":"После остановки неисправного коммерческого транспортного средства на дороге Кентукки, в течение скольких минут водитель должен выставить требуемые аварийные предупреждающие устройства?","options":["В течение 10 минут","В течение 5 минут","В течение 30 минут","В течение 15 минут"],"explanation":"Водитель должен разместить три требуемых предупреждающих устройства в течение 10 минут после остановки. Источник: 49 CFR 392.22, принятое в Кентукки; Kentucky CDL Manual."},"75":{"q":"На длинном спуске, таком как Пайн-Маунтин в Кентукки (U.S. 119), какова правильная техника торможения, изложенная в Kentucky CDL Manual?","options":["Периодически применять стояночный тормоз для замедления транспортного средства","Перейти на нейтраль, чтобы дать двигателю остыть, и слегка притормаживать","Выбрать низкую передачу перед спуском и применять лёгкое, равномерное или прерывистое (snub) торможение","Держать максимально возможную передачу и непрерывно прокачивать тормоза"],"explanation":"Водители должны выбрать правильную низкую передачу перед началом спуска и в основном полагаться на торможение двигателем, применяя рабочие тормоза лёгкими, прерывистыми (snub) нажатиями. Постоянное удержание тормозов приводит к перегреву и потере эффективности торможения. Источник: Kentucky CDL Manual (Контроль скорости / Вождение в горах)."},"76":{"q":"Без разрешения на негабаритный груз в Кентукки, какова максимальная разрешённая законом ширина для коммерческого транспортного средства с грузом на обозначенных шоссе?","options":["10 feet 0 inches","9 feet 6 inches","8 feet 0 inches","8 feet 6 inches"],"explanation":"Максимальная разрешённая законом ширина транспортного средства/груза в Кентукки на автомагистралях и обозначенных шоссе составляет 8 feet 6 inches (102 inches); всё, что шире, требует разрешения на негабаритный груз от KYTC. Источник: KRS Chapter 189; KYTC Overweight/Over-Dimensional Permits."},"77":{"q":"Груз в Кентукки имеет высоту 14 feet. Без разрешения максимальная разрешённая законом высота составляет 13 feet 6 inches. Что должен получить перевозчик перед перемещением этого груза?","options":["Только разрешение от местного окружного шерифа","Ничего, поскольку ограничения по высоте в Кентукки носят лишь рекомендательный характер","Разрешение на негабаритный/сверхгабаритный груз от Kentucky Transportation Cabinet","Только сертификат на перевозку опасных материалов"],"explanation":"Максимальная разрешённая законом высота в Кентукки составляет 13 feet 6 inches; груз высотой 14 feet превышает это значение и требует разрешения на сверхгабаритный груз, выдаваемого через KYTC Division of Motor Carriers перед поездкой. Источник: KRS Chapter 189; KYTC Overweight/Over-Dimensional Permits."},"78":{"q":"Кентукки, как правило, НЕ выдаёт разрешение на негабаритный/сверхтяжёлый груз для какого типа груза?","options":["Единого элемента промышленного оборудования, который нельзя разобрать","Груза, который разумно делим и может быть переконфигурирован для соблюдения законных пределов","Крупного трансформатора, превышающего законный вес","Сборной секции здания, превышающей законную ширину"],"explanation":"Кентукки выдаёт разрешения OS/OW только для неделимых грузов; он не выдаст разрешение на груз, который разумно делим (тот, который можно разобрать или переконфигурировать для соблюдения законных пределов), за исключением случаев, предусмотренных конкретными законными полномочиями. Источник: KYTC Overweight/Over-Dimensional Permits; KRS Chapter 189."},"79":{"q":"Какое ведомство Кентукки фактически выдаёт удостоверение коммерческого водителя (CDL) квалифицированным заявителям?","options":["Division of Driver Licensing при Kentucky Transportation Cabinet","Kentucky State Police","Federal Motor Carrier Safety Administration","Бюро поручительства при окружном секретаре Circuit Court"],"explanation":"В Кентукки удостоверение CDL выдаётся Kentucky Transportation Cabinet (KYTC), Division of Driver Licensing. Источник: страница CDL на KYTC drive.ky.gov; 2025 Kentucky CDL Manual."},"80":{"q":"Кто проводит тесты на знание CDL и дорожный тест навыков для заявителей в Кентукки?","options":["Kentucky State Police","Окружной секретарь Circuit Court","Только частные сторонние школы вождения грузовиков","FMCSA National Registry"],"explanation":"Kentucky State Police (KSP) несёт исключительную ответственность за проведение всех тестов на знание и навыки CDL в Кентукки, в то время как KYTC выдаёт лицензию. Источник: 2025 Kentucky CDL Manual; Kentucky State Police Driver Testing."},"81":{"q":"В течение скольких дней действителен коммерческий ученический пермит (CLP) Кентукки?","options":["180 дней","60 дней","365 дней","90 дней"],"explanation":"CLP Кентукки действителен не более 180 дней. Источник: KRS 281A.120; 2025 Kentucky CDL Manual."},"82":{"q":"После выдачи CLP, как долго заявитель должен ждать, прежде чем сдавать тест навыков CDL в Кентукки?","options":["Не менее 14 дней","Не менее 30 дней","Не менее 7 дней","Не менее 60 дней"],"explanation":"Заявитель должен иметь CLP не менее 14 дней, прежде чем получить право сдавать тест навыков CDL. Это федеральный стандарт, применяемый в Кентукки. Источник: 2025 Kentucky CDL Manual; 49 CFR 383.25."},"83":{"q":"Как долго действителен коммерческий водительский лицензия Кентукки, прежде чем её необходимо продлить?","options":["8 лет","4 года","5 лет","10 лет"],"explanation":"Удостоверение CDL Кентукки действительно в течение 8 лет. Источник: KRS 281A.170; KYTC drive.ky.gov."},"84":{"q":"Какая форма является медицинским сертификатом DOT (Medical Examiner's Certificate), который заявитель на CDL в Кентукки должен получить у сертифицированного медицинского эксперта?","options":["Форма MCSA-5876","Форма TC 94-169","Только форма MCSA-5875","Форма DOT-391"],"explanation":"Medical Examiner's Certificate — это форма MCSA-5876, заполняемая медицинским экспертом, сертифицированным в National Registry; она должна храниться в деле держателя CDL. (TC 94-169 — это отдельная форма самосертификации.) Источник: информация KYTC для впервые подающих заявление; FMCSA."},"85":{"q":"В самосертификации CDL Кентукки из скольких категорий типа вождения должен выбрать заявитель?","options":["Четырёх","Двух","Трёх","Пяти"],"explanation":"Самосертификация (форма TC 94-169) имеет четыре категории: non-excepted interstate, excepted interstate, non-excepted intrastate и excepted intrastate. Источник: KYTC Form TC 94-169; 49 CFR 383.71."},"86":{"q":"Водитель из Кентукки, который работает на межштатных перевозках и должен соответствовать федеральным стандартам физической квалификации, должен самосертифицироваться как какая категория?","options":["Non-excepted interstate","Excepted interstate","Non-excepted intrastate","Excepted intrastate"],"explanation":"Водители на межштатных перевозках, подпадающие под федеральные правила физической квалификации, сертифицируются как non-excepted interstate, что требует наличия действующего Medical Examiner's Certificate в деле. Источник: KYTC Form TC 94-169; 49 CFR 383.71."},"87":{"q":"Прежде чем заявитель, впервые претендующий на класс A или класс B, сможет сдать тест навыков CDL в Кентукки, какое требование к обучению должно быть выполнено?","options":["Entry-Level Driver Training (ELDT) от зарегистрированного провайдера","160-часовое государственное ученичество, спонсируемое KYTC","Курс безопасного вождения у окружного секретаря Circuit Court","Два года документально подтверждённого вождения внутри штата"],"explanation":"Федеральное Entry-Level Driver Training (ELDT) от провайдера из FMCSA Training Provider Registry требуется перед первым тестированием на класс A/B (и перед первым тестированием на сертификаты P, S или H). Источник: 2025 Kentucky CDL Manual; 49 CFR Part 380."},"88":{"q":"Какой из следующих сертификатов требует прохождения ELDT перед тестом, в дополнение к заявителям, впервые претендующим на класс A и класс B?","options":["Опасные материалы (H), пассажирский (P) и школьный автобус (S)","Цистерна (N) и сдвоенные/строенные прицепы (T)","Только сертификат школьного автобуса (S)","Ни один сертификат не требует ELDT"],"explanation":"ELDT требуется для заявителей, впервые претендующих на сертификаты по опасным материалам (H), пассажирский (P) и школьный автобус (S), а также для первичной выдачи класса A/B и повышения с класса B до A. Источник: 2025 Kentucky CDL Manual; 49 CFR Part 380."},"89":{"q":"Тест навыков CDL Кентукки проводится в трёх частях. Какой набор правильно перечисляет эти три части?","options":["Предрейсовый осмотр, базовое управление транспортным средством и вождение по дороге","Письменный тест на знание, проверка зрения и вождение по дороге","Предрейсовый осмотр, письменный тест по пневматическим тормозам и сдача задним ходом","Базовое управление транспортным средством, письменный тест по hazmat и вождение по дороге"],"explanation":"Тест навыков CDL состоит из трёх частей: предрейсовый осмотр, базовые навыки управления транспортным средством и дорожный тест вождения. Источник: 2025 Kentucky CDL Manual; 49 CFR 383.113."},"90":{"q":"На транспортном средстве какого типа заявитель в Кентукки должен сдавать тест навыков CDL?","options":["Класса/типа транспортного средства, на управление которым заявитель намерен получить лицензию","Любого коммерческого транспортного средства весом более 10,001 pounds","Стандартного легкового автомобиля, предоставленного станцией тестирования","Транспортного средства класса C независимо от запрашиваемого класса лицензии"],"explanation":"Заявители должны сдавать тест навыков на репрезентативном транспортном средстве того класса и типа, на который они хотят получить лицензию. Источник: 2025 Kentucky CDL Manual; 49 CFR 383.71."},"91":{"q":"Какие документы должен иметь в деле заявитель, впервые подающий заявление на CDL в Кентукки, прежде чем будет выдан пермит или лицензия?","options":["Заявление на CDL, форму самосертификации и разборчивый медицинский сертификат DOT (Medical Examiner's Certificate)","Только карточку социального страхования и результат проверки зрения","Письмо от работодателя и регистрацию транспортного средства","Паспорт и подписку на FMCSA clearinghouse"],"explanation":"Перед выдачей CLP или CDL Кентукки требует заявление на CDL, самосертификацию (TC 94-169) и разборчивую копию Medical Examiner's Certificate DOT, поданные в KYTC (через mycdl.ky.gov). Источник: информация KYTC для впервые подающих заявление; drive.ky.gov."},"92":{"q":"Если CLP Кентукки истекает до того, как заявитель сдаст тест навыков, что обычно происходит?","options":["Заявитель должен повторно сдать требуемые тесты на знание, чтобы получить новый CLP","CLP автоматически продлевается ещё на 180 дней","Результаты теста навыков сохраняются в течение двух лет","Заявитель может сдать тест навыков в течение 30-дневного льготного периода"],"explanation":"Кентукки не продлевает 180-дневный CLP; если он истекает до сдачи теста навыков, заявитель должен повторно сдать тест(ы) на знание, чтобы получить новый CLP. Источник: 2025 Kentucky CDL Manual; KRS 281A.120."},"93":{"q":"Каков минимальный проходной балл на тесте общих знаний CDL Кентукки?","options":["80 процентов правильных ответов","70 процентов правильных ответов","75 процентов правильных ответов","90 процентов правильных ответов"],"explanation":"Заявитель должен набрать не менее 80 процентов, чтобы сдать каждый тест на знание CDL, — это федеральный стандарт, применяемый в Кентукки. Источник: 2025 Kentucky CDL Manual; 49 CFR 383.135."},"94":{"q":"Каков минимальный возраст для выдачи CDL Кентукки, ограниченного перевозками внутри штата (в пределах Кентукки)?","options":["18 лет","21 год","19 лет","16 лет"],"explanation":"Человеку должно быть не менее 18 лет, чтобы иметь CDL для вождения внутри штата в Кентукки; для межштатного вождения и для работы с hazmat/школьными автобусами требуется 21 год. Источник: KRS 281A; 2025 Kentucky CDL Manual."},"95":{"q":"Каков минимальный возраст, требуемый для управления коммерческим транспортным средством на межштатных перевозках по CDL Кентукки?","options":["21 год","18 лет","19 лет","25 лет"],"explanation":"Водителям должно быть не менее 21 года для работы на межштатных перевозках; лица в возрасте от 18 до 20 лет получают ограничение на перевозки внутри штата (только в пределах Кентукки). Источник: KRS 281A; 2025 Kentucky CDL Manual; 49 CFR 391.11."},"96":{"q":"Когда держатель CDL Кентукки проходит новое медицинское обследование DOT, что водитель должен сделать, чтобы сохранить статус «сертифицирован» для CDL?","options":["Подать обновлённый Medical Examiner's Certificate в KYTC через mycdl.ky.gov, чтобы водительская запись оставалась актуальной","Хранить сертификат только в кабине и показывать его полиции по требованию","Отправить сертификат по почте в FMCSA National Registry вместо штата","Снова сдать тест на знание для повторной проверки сертификата"],"explanation":"Чтобы избежать понижения статуса до «не сертифицирован», водитель должен подавать каждый новый Medical Examiner's Certificate в KYTC, обычно через портал mycdl.ky.gov, чтобы он отображался в водительской записи CDLIS. Источник: информация KYTC для впервые подающих заявление; 49 CFR 383.71/383.73."},"97":{"q":"Какое утверждение о продлении CDL Кентукки верно в отношении процесса по почте/онлайн?","options":["CDL, как правило, нельзя продлить по почте и требуется личное продление","CDL продлевается автоматически и отправляется по почте без какого-либо заявления","CDL всегда можно продлить онлайн без документов","CDL никогда не истекает после того, как водитель сдал тест навыков"],"explanation":"Удостоверения класса A, B или C (CDL), как правило, нельзя продлить по почте; требуется личное продление с действующей медицинской сертификацией. Источник: KRS 281A.170; KYTC drive.ky.gov."}},"tr":{"0":{"q":"Kentucky eyaletler arası (Interstate) ve belirlenmiş karayollarında, bir ticari aracın maksimum yasal genişliği nedir (aynalar gibi onaylanmış güvenlik ekipmanları hariç)?","options":["8 fit 3 inç (99 inç)","8 fit 6 inç (102 inç)","8 fit 0 inç (96 inç)","9 fit 0 inç (108 inç)"],"explanation":"Kentucky, eyaletler arası ve belirlenmiş karayollarında araç genişliğini 8 fit 6 inç (102 inç) ile sınırlar; bu, 23 CFR 658 ile uyumludur. Kaynak: Kentucky DRIVE (KYTC) Yasal Boyutlar sayfası; KRS 189.221/189.222."},"1":{"q":"Kentucky'de eyaletler arası (Interstate) olmayan veya başka türlü belirlenmiş karayolu olmayan, eyalet tarafından bakımı yapılan karayollarında maksimum yasal araç genişliği nedir?","options":["8 fit (96 inç)","8 fit 6 inç (102 inç)","7 fit 6 inç (90 inç)","9 fit (108 inç)"],"explanation":"Kentucky'de belirlenmemiş, eyalet tarafından bakımı yapılan yollarda yasal genişlik 8 fite (96 inç) düşer; 8'6\" izni yalnızca eyaletler arası ve belirlenmiş karayolu sistemi için geçerlidir. Kaynak: Kentucky DRIVE (KYTC) Yasal Boyutlar sayfası; KRS 189.221."},"2":{"q":"Kentucky karayollarında, aşırı boyut izni gerekmeden önceki maksimum yasal araç yüksekliği nedir?","options":["14 fit 0 inç","14 fit 6 inç","13 fit 0 inç","13 fit 6 inç"],"explanation":"Kentucky, yasal maksimum araç ve yük yüksekliğini 13 fit 6 inç olarak belirler; daha yüksek olan her şey için aşırı boyut izni gerekir. Kaynak: Kentucky DRIVE (KYTC) Yasal Boyutlar sayfası; KRS 189.222."},"3":{"q":"Kentucky'nin eyaletler arası (Interstate) ve belirlenmiş karayolu sisteminde çalışan tek bir yarı römorkun maksimum yasal uzunluğu nedir?","options":["45 fit","57 fit","53 fit","48 fit"],"explanation":"Kentucky'nin eyaletler arası ve belirlenmiş karayollarında tek bir yarı römork en fazla 53 fit uzunluğunda olabilir. Kaynak: Kentucky DRIVE (KYTC) Yasal Boyutlar sayfası; KRS 189.221/189.222."},"4":{"q":"Kentucky'de çalışan ikiz römorklu (çift) bir kombinasyonda, her bir römorkun maksimum yasal uzunluğu nedir?","options":["Her biri 26 fit","Her biri 28 fit","Her biri 30 fit","Her biri 32 fit"],"explanation":"Kentucky, federal olarak korunan çift römork boyutuyla uyumlu olarak her biri en fazla 28 fit olan ikiz/çift römorklara izin verir. Kaynak: Kentucky DRIVE (KYTC) Yasal Boyutlar sayfası; KRS 189.222."},"5":{"q":"Kentucky karayollarında tek üniteli bir motorlu kamyonun maksimum yasal uzunluğu nedir?","options":["45 fit","53 fit","48 fit","40 fit"],"explanation":"Tek üniteli bir motorlu kamyon, Kentucky'nin boyut kuralları uyarınca 45 fit uzunlukla sınırlıdır. Kaynak: Kentucky DRIVE (KYTC) Yasal Boyutlar sayfası; KRS 189.221."},"6":{"q":"Kentucky'de belirlenmiş sistemin parçası OLMAYAN, eyalet tarafından bakımı yapılan karayollarında, bir çekici-römork kombinasyonunun maksimum toplam uzunluğu nedir?","options":["75 fit","70 fit","60 fit","65 fit"],"explanation":"Belirlenmemiş, eyalet tarafından bakımı yapılan yollarda, belirlenmiş karayollarında 53 fitlik bir yarı römorka izin verilse bile, toplam kombinasyon uzunluğu 65 fit ile sınırlanır. Kaynak: Kentucky DRIVE (KYTC) Yasal Boyutlar sayfası; KRS 189.221."},"7":{"q":"Kentucky karayollarında, aşırı ağırlık izni olmadan bir ticari araç ve yük için maksimum yasal brüt ağırlık nedir?","options":["84,000 pound","88,000 pound","80,000 pound","73,280 pound"],"explanation":"Kentucky, toplam brüt araç ağırlığını federal eyaletler arası standardıyla uyumlu olarak 80,000 pound ile sınırlar. Kaynak: KRS 189.222; 603 KAR 5:066; Kentucky DRIVE (KYTC)."},"8":{"q":"Kentucky'de tek bir akson üzerinde taşınabilecek maksimum yasal ağırlık nedir?","options":["22,400 pound","20,000 pound","18,000 pound","24,000 pound"],"explanation":"Kentucky'de hiçbir tek akson 20,000 pound'u (ya da toplam lastik genişliğinin her inçi başına 700 pound, hangisi daha azsa) aşamaz. Kaynak: KRS 189.222; 603 KAR 5:066."},"9":{"q":"Kentucky'de bir tandem akson grubunda (42 ila 96 inç aralıklı aksonlar) maksimum yasal ağırlık nedir?","options":["34,000 pound","36,000 pound","40,000 pound","32,000 pound"],"explanation":"Kentucky'de 42 ila 96 inç aralıklı bir tandem akson grubu 34,000 pound ile sınırlıdır. Kaynak: KRS 189.222; 603 KAR 5:066; Kentucky DRIVE (KYTC) Yasal Boyutlar."},"10":{"q":"Kentucky'de, 42 ila 120 inç aralıklı bir tridem (üç akson) grubunda maksimum yasal ağırlık nedir?","options":["45,000 pound","42,000 pound","51,000 pound","48,000 pound"],"explanation":"Kentucky'de 42 ila 120 inç arasında aralıklı bir tridem akson grubuna en fazla 48,000 pound'a kadar izin verilir. Kaynak: KRS 189.222; Kentucky DRIVE (KYTC) Yasal Boyutlar sayfası."},"11":{"q":"Kentucky, akson ağırlıklarında bir ağırlık toleransına izin verir, ancak yalnızca belirli yollarda. Yüzde 5'lik akson ağırlığı toleransı hangi karayollarında geçerlidir?","options":["Yalnızca ilçe tarafından bakımı yapılan yollar","Eyaletler arası sistem dahil tüm karayolları","Eyaletler arası (Interstate) sistemin parçası OLMAYAN, eyalet tarafından bakımı yapılan karayolları","Yalnızca eyaletler arası sistem"],"explanation":"Kentucky, eyaletler arası sistemin parçası olmayan, eyalet tarafından bakımı yapılan karayollarında akson ağırlığında yüzde 5'ten fazla olmayan bir toleransa izin verir; eyaletler arası sistemde böyle bir akson toleransı geçerli değildir. Kaynak: KRS 189.222."},"12":{"q":"Kentucky yasalarına göre, yüzde 5'lik ağırlık toleransı BRÜT araç ağırlığına nasıl uygulanır?","options":["Yüzde 5'lik bir tolerans yalnızca eyaletler arası sistemde geçerlidir","Brüt ağırlıkta hiçbir toleransa izin verilmez","Eyaletler arası olmayan yollarda yüzde 10'luk bir tolerans geçerlidir","Yüzde 5'lik bir tolerans tüm yollarda geçerlidir"],"explanation":"Kentucky, brüt ağırlıkta açıkça HİÇBİR toleransa izin vermez; yüzde 5'lik tolerans yalnızca eyaletler arası olmayan, eyalet tarafından bakımı yapılan karayollarındaki akson ağırlıklarına uygulanır. Kaynak: KRS 189.222."},"13":{"q":"Kentucky, ardışık akson gruplarındaki ağırlığı sınırlamak için federal köprü formülünü kullanır. Formül brüt ağırlığı öncelikle neyle ilişkilendirir?","options":["Akson sayısı ve aralarındaki aralık (mesafe)","Lastik sayısı ve hava basınçları","Motorun beygir gücü ve brüt kombinasyon ağırlık derecesi","Römork uzunluğu ve kargo yoğunluğu"],"explanation":"Federal Köprü Formülü, W=500(LN/(N-1)+12N+36), iki veya daha fazla ardışık aksondan oluşan herhangi bir gruptaki ağırlığı, akson sayısına (N) ve grubun uç aksonları arasındaki mesafeye (L) göre sınırlar. Kentucky bunu 23 CFR Part 658'in kabul edilmesiyle uygular. Kaynak: 23 CFR 658.17; KRS 189.222."},"14":{"q":"Kentucky'de kullanılan federal köprü formülü W = 500(LN/(N-1) + 12N + 36) içinde, 'L' değişkeni neyi temsil eder?","options":["Ton cinsinden yasal yük ağırlığı","Süspansiyonun kaldırma kapasitesi","Fit cinsinden römork uzunluğu","Grubun uç aksonları arasındaki fit cinsinden mesafe"],"explanation":"Köprü formülünde L, iki veya daha fazla ardışık aksondan oluşan herhangi bir grubun uçları arasındaki fit cinsinden mesafedir; N ise o gruptaki akson sayısıdır. Kaynak: 23 CFR 658.17 (Köprü Formülü), Kentucky'de KRS 189.222 uyarınca kabul edilmiştir."},"15":{"q":"Kentucky'de iki ardışık tandem akson seti, yalnızca bu tandemlerin ilk ve son aksonları arasındaki mesafe en az kaç fit olduğunda her biri tam 34,000 pound taşıyabilir?","options":["28 fit","40 fit","36 fit","30 fit"],"explanation":"Kentucky tarafından kabul edilen köprü formülü istisnası uyarınca, iki ardışık tandem akson seti, ancak bu tandemlerin ilk ve son aksonları arasındaki toplam aralık 36 fit veya daha fazla olduğunda her biri 34,000 pound taşıyabilir. Kaynak: 23 CFR 658.17; KRS 189.222."},"16":{"q":"Bir Kentucky büyük boy/aşırı ağırlık (OS/OW) izni ne zaman gereklidir?","options":["Yalnızca ilçe yollarında seyahat ederken","Genişlik, yükseklik, uzunluk veya ağırlık için yasal sınırları aşan herhangi bir aracı veya yükü hareket ettirmeden önce","Yalnızca brüt ağırlık 90,000 pound'u aştığında","Yalnızca yük 10 fitten daha geniş olduğunda"],"explanation":"Genişlik, yükseklik, uzunluk veya ağırlık için yasal sınırları aşan herhangi bir aracı veya yükü hareket ettirmeden ÖNCE bir Kentucky izni alınmalıdır. Kaynak: KYTC Motorlu Taşıyıcılar Dairesi; 601 KAR 1:018."},"17":{"q":"Hangi Kentucky kurumu özel aşırı ağırlık/aşırı boyutlu motorlu taşıt yük izinlerini verir ve genellikle hangisi böyle bir izin alamaz?","options":["KYTC Motorlu Taşıyıcılar Dairesi; makul ölçüde bölünebilir yükler genellikle izin alamaz","U.S. DOT; yalnızca eyaletler arası yükler izin alabilir","Kentucky Eyalet Polisi; yalnızca tarım yükleri izin alabilir","İlçe mali mahkemeleri; yalnızca orman ürünleri izin alabilir"],"explanation":"Kentucky Ulaştırma Bakanlığı'nın (Kentucky Transportation Cabinet) Motorlu Taşıyıcılar Dairesi, 601 KAR 1:018 uyarınca OS/OW izinlerini verir ve makul ölçüde bölünebilir (yasal sınırları karşılamak için sökülebilen veya ayrılabilen) yükler için genellikle izin VERİLMEZ. Kaynak: 601 KAR 1:018; KRS 189.270."},"18":{"q":"Kentucky, bölünemez tarım ekipmanları için özel bir muafiyet sağlar. Bu neye izin verir?","options":["Tarım ekipmanları iki şeritli yollarda izin olmadan herhangi bir genişlikte seyahat edebilir","Tarım ekipmanları eyaletler arası sistemde izin olmadan 120,000 pound'u aşabilir","Tarım ekipmanları eyalet genelinde tüm izin ve ağırlık kurallarından muaftır","Yasal ağırlık veya boyut sınırlarını aşan bölünemez tarım ekipmanları için tek seferlik bir izin verilebilir"],"explanation":"Kentucky, KRS 189.222 veya 189.270'teki sınırları aşan bölünemez tarım ekipmanlarının taşınması için bir aşırı ağırlık/aşırı boyutlu tek seferlik izin verir; bu, genel bir muafiyet değil, izinli bir istisnadır. Kaynak: 601 KAR 1:019; 601 KAR 1:018."},"19":{"q":"Kentucky'nin Genişletilmiş Ağırlıklı Kömür Taşıma Yolu Sistemi (ECWHRS) kapsamında, kömür taşıyan 5 veya daha fazla aksonlu bir çekici-yarı römork hangi maksimum brüt ağırlıkta çalışabilir?","options":["90,000 pound (yüzde 5 toleransla)","80,000 pound (toleranssız)","120,000 pound (yüzde 5 toleransla)","100,000 pound (yüzde 10 toleransla)"],"explanation":"Genişletilmiş Ağırlıklı Kömür Taşıma Yolu Sisteminde, kömür veya kömür yan ürünleri taşıyan beş veya daha fazla aksonlu bir çekici-yarı römork, yüzde 5 toleransla en fazla 120,000 pound brüt ağırlıkta çalışabilir. Kaynak: KRS 177.9771."},"20":{"q":"Kentucky'de, 26,001 pound veya daha fazla brüt kombinasyon ağırlık derecesine (GCWR) sahip herhangi bir araç kombinasyonunu kullanmak için, çekilen araç(lar)ın GVWR'si hangi ağırlığı aşması koşuluyla Class A CDL gereklidir?","options":["10,000 pound","26,001 pound","16,000 pound","1,000 pound"],"explanation":"Kentucky, çekilen ünite(ler)in GVWR'si 10,000 pound'un üzerinde olduğunda, 26,001 pound veya daha fazla GCWR'ye sahip kombinasyonlar için Class A CDL gerektirir. Kaynak: Kentucky CDL Kılavuzu (KYTC, Mart 2025), 'Kim Başvurmalı? - Class A CDL.'"},"21":{"q":"Kentucky kuralları uyarınca, en az kaç pound brüt araç ağırlık derecesine (GVWR) sahip herhangi bir tek aracı kullanmak için Class B CDL gereklidir?","options":["10,001 pound","26,001 pound","33,000 pound","16,001 pound"],"explanation":"Class B CDL, 26,001 pound veya daha fazla GVWR'ye sahip herhangi bir tek aracı kapsar; buna, GVWR'si 10,000 pound veya daha az olan bir üniteyi çeken böyle bir araç da dahildir. Kaynak: Kentucky CDL Kılavuzu (KYTC, Mart 2025), 'Class B CDL.'"},"22":{"q":"Kentucky CDL Kılavuzu'na göre, 26,001 pound'un altında GVWR'ye sahip bir araç, sürücü dahil en az kaç kişiyi taşıyacak şekilde tasarlandığında Class C CDL gerektirir?","options":["15","24","16","9"],"explanation":"Kentucky, sürücü dahil 16 veya daha fazla yolcu taşıyan ya da plaka gerektiren tehlikeli madde taşıyan, 26,001 pound altında GVWR'ye sahip bir araç için Class C CDL gerektirir. Kaynak: Kentucky CDL Kılavuzu (KYTC, Mart 2025), 'Class C CDL.'"},"23":{"q":"Kentucky'de, plaka gerektiren miktarlarda tehlikeli madde taşıyan, 26,001 pound'un altında GVWR'ye sahip bir araca hangi CDL sınıfı uygulanır?","options":["Class A","Class B","Class D","Class C"],"explanation":"Class C CDL, plaka gerektiren tehlikeli madde veya 16 ve üzeri yolcu (sürücü dahil) taşıyan, 26,001 pound altında GVWR'ye sahip araçları kapsar. Kaynak: Kentucky CDL Kılavuzu (KYTC, Mart 2025), 'Class C CDL.'"},"24":{"q":"Kentucky'nin eyalet içi (intrastate) ticaretle sınırlı bir CDL'yi ('K' kısıtlamasıyla) verebileceği minimum yaş nedir?","options":["21 yaş","18 yaş","19 yaş","16 yaş"],"explanation":"Kentucky, test gerekliliklerini karşılayan ve okul otobüsü kullanmayan veya tehlikeli madde taşımayan 18 ila 20 yaşındaki bir kişiye, sınıfa özel bir CDL'yi 'K' (yalnızca eyalet içi) kısıtlamasıyla verebilir. Kaynak: Kentucky CDL Kılavuzu (KYTC, Mart 2025), 'On Sekiz (18) Yaşında Eyalet İçi Sürüş Yapan Kişi.'"},"25":{"q":"Ticari motorlu bir aracı eyaletler arası ticarette (eyalet sınırları boyunca, kısıtlamasız) kullanmak isteyen bir Kentucky CDL sahibinin en az kaç yaşında olması gerekir?","options":["18 yaş","19 yaş","21 yaş","25 yaş"],"explanation":"18-20 yaşındaki sürücüler Kentucky eyalet içi ticaretiyle sınırlıdır ('K' kısıtlaması); bir sürücünün bu kısıtlama olmadan eyaletler arası ticarette çalışması için 21 yaşında olması gerekir. Kaynak: Kentucky CDL Kılavuzu (KYTC, Mart 2025), eyalet içi yaş bölümü."},"26":{"q":"Bir Kentucky CDL öğrenci belgesi (CLP) verildikten sonra, beceri testi uygulanabilmesi için başvuru sahibinin belgeyi ne kadar süre elinde tutması gerekir?","options":["30 gün","10 gün","60 gün","14 gün"],"explanation":"Beceri testi verilmeden önce belge, federal CLP kuralıyla uyumlu olarak 14 gün elde tutulmalıdır. Kaynak: Kentucky CDL Kılavuzu (KYTC, Mart 2025), 'CDL Başvurusu Nasıl Yapılır.'"},"27":{"q":"Bir Kentucky CDL öğrenci belgesi (CLP) ne kadar süre geçerlidir?","options":["6 ay","12 ay","30 gün","Süresiz olarak yenilenebilen 180 gün"],"explanation":"Bir Kentucky CDL öğrenci belgesi altı (6) ay geçerlidir. Başvuru sahibinin yeniden başvurması gerekmeden önce yalnızca bir kez yenilenebilir. Kaynak: Kentucky CDL Kılavuzu (KYTC, Mart 2025), 'CDL Başvurusu Nasıl Yapılır' ve ELDT bölümü."},"28":{"q":"Bir Kentucky CDL öğrenci belgesi, başvuru sahibinin yeniden başvurması (ve tüm ücretleri ödeyip yazılı testleri tekrar alması) gerekmeden önce kaç kez yenilenebilir?","options":["İki kez","Yenilenemez","Bir kez","Sınırsız kez"],"explanation":"Bir Kentucky CDL belgesi yalnızca bir kez yenilenebilir; yenilenen belge sona ermeden önce yol beceri testi geçilmezse, başvuru sahibinin tüm ücretler ve yazılı testlerle yeniden başvurması gerekir. Kaynak: Kentucky CDL Kılavuzu (KYTC, Mart 2025), 'Başlangıç Seviyesi Sürücü Eğitimi (ELDT).'"},"29":{"q":"Kentucky CDL'de, toplu taşıma veya tur otobüsü gibi yolcu taşımak için tasarlanmış bir aracı kullanmak için hangi onay (endorsement) gereklidir?","options":["S (Okul Otobüsü)","N (Tank)","T (Çift/Üçlü)","P (Yolcu)"],"explanation":"Yolcu taşımak için P (Yolcu) onayı gereklidir; bunu eklemek, başvurulan sınıftaki bir yolcu aracında tam bir beceri testi gerektirir. Kaynak: Kentucky CDL Kılavuzu (KYTC, Mart 2025), 'Onaylar' ve 'Yolcu onayı ekleme.'"},"30":{"q":"Kentucky'de bir okul otobüsü kullanmak için, bir CDL sahibinin hangi diğer onaya ek olarak S (Okul Otobüsü) onayını alması gerekir?","options":["P (Yolcu)","N (Tank)","H (HazMat)","T (Çift/Üçlü)"],"explanation":"Okul otobüsü sürücüleri, bir Yolcu (P) onayına ek olarak bir Okul Otobüsü (S) onayına sahip olmalı ve kullanılacak okul otobüsü sınıfında bir bilgi testini ve üç beceri testi bölümünün tümünü geçmelidir. Kaynak: Kentucky CDL Kılavuzu (KYTC, Mart 2025), okul otobüsü onay bölümü."},"31":{"q":"Kentucky CDL bilgi testlerinde, Tehlikeli Maddeler (H) onay testi kaç soru içerir?","options":["20 soru","30 soru","50 soru","25 soru"],"explanation":"Kentucky'nin HazMat onay bilgi testinde 30 soru bulunurken, Çift/Üçlü, Tank, Yolcu ve Okul Otobüsü onay testlerinin her birinde 20 soru vardır. Kaynak: Kentucky CDL Kılavuzu (KYTC, Mart 2025), 'Aşağıdaki araçlar için onaylar gereklidir.'"},"32":{"q":"Bir Kentucky Tehlikeli Maddeler (H) onayının verilmesinden veya yenilenmesinden önce, başvuru sahibinin parmak izi alma ve FBI ile hangi federal kurum tarafından işlenen bir güvenlik geçmiş kontrolünü tamamlaması gerekir?","options":["Federal Motorlu Taşıyıcı Güvenliği İdaresi (FMCSA)","İç Güvenlik Bakanlığı Sahil Güvenlik","Federal Karayolu İdaresi (FHWA)","Ulaştırma Güvenliği İdaresi (TSA)"],"explanation":"HazMat başvuru sahiplerinin parmak izi alınır ve başvuru, testten önce bir güvenlik tehdit değerlendirmesi için FBI'a ve Ulaştırma Güvenliği İdaresi'ne (TSA) gönderilir. Bir TWIC kartı, değerlendirmenin kanıtı olarak hizmet edebilir. Kaynak: Kentucky CDL Kılavuzu (KYTC, Mart 2025), HazMat onay bölümü."},"33":{"q":"Çift veya üçlü römork çekmek için hangi Kentucky CDL onayı gereklidir?","options":["T","N","H","X"],"explanation":"Çift veya üçlü römork çekmek için T onayı (Çift/Üçlü) gereklidir ve 20 soruluk bir bilgi testini geçmeyi gerektirir. Kaynak: Kentucky CDL Kılavuzu (KYTC, Mart 2025), 'Onaylar.'"},"34":{"q":"Bir Kentucky CDL sürücüsünün, sıvı veya gazları dökme bir tank aracında (tanker) taşımak için hangi onaya ihtiyacı vardır?","options":["T (Çift/Üçlü)","N (Tank)","P (Yolcu)","H (HazMat)"],"explanation":"Sıvı veya gaz halinde dökme kargo taşıyan bir tank aracını kullanmak için N (Tank) onayı gereklidir ve 20 soruluk bir bilgi testini gerektirir. Kaynak: Kentucky CDL Kılavuzu (KYTC, Mart 2025), 'Onaylar.'"},"35":{"q":"7 Şubat 2022 itibarıyla, Kentucky'de ilk kez bir Class A veya B CDL almadan önce federal Başlangıç Seviyesi Sürücü Eğitimi'nin (ELDT) tamamlanması gerekir ve eğitim, hangi yerde listelenen bir sağlayıcıdan alınmalıdır?","options":["Kentucky Eyalet Polisi test listesi","Herhangi bir KYTC Bölge Ofisi listesi","FMCSA Eğitim Sağlayıcı Kaydı (Training Provider Registry)","CDLIS takas merkezi (clearinghouse)"],"explanation":"49 CFR part 380 kapsamındaki ELDT, ilk kez bir Class A/B CDL'den, bir yükseltmeden veya ilk H, P ya da S onayından önce, FMCSA Eğitim Sağlayıcı Kaydı'nda listelenen bir sağlayıcı kullanılarak tamamlanmalıdır. Kaynak: Kentucky CDL Kılavuzu (KYTC, Mart 2025), 'Başlangıç Seviyesi Sürücü Eğitimi (ELDT).'"},"36":{"q":"Aşağıdakilerden hangisi için Kentucky, ilk kez eklenmeden önce Başlangıç Seviyesi Sürücü Eğitimi (ELDT) GEREKTİRMEZ?","options":["H (HazMat) onayı","N (Tank) onayı","P (Yolcu) onayı","S (Okul Otobüsü) onayı"],"explanation":"ELDT, ilk kez bir Class A/B CDL, bir yükseltme ve ilk H, P veya S onayı için gereklidir; Tank (N) onayı ELDT listesinde değildir. Kaynak: Kentucky CDL Kılavuzu (KYTC, Mart 2025), 'Başlangıç Seviyesi Sürücü Eğitimi (ELDT)'; 49 CFR part 380."},"37":{"q":"Bir Kentucky CDL başvuru sahibi, yalnızca Kentucky içinde (eyalet içi) çalışıyorsa veya çalışmayı bekliyorsa ve tıbbi gerekliliklerden muaf DEĞİLSE, hangi tıbbi öz-belgelendirme kategorisini seçmelidir?","options":["Muaf Eyalet İçi (EA)","Muaf Olmayan Eyaletler Arası (NI)","Muaf Eyaletler Arası (EI)","Muaf Olmayan Eyalet İçi (NA)"],"explanation":"Yalnızca Kentucky içinde çalışan ve tıbbi olarak belgelendirilmesi gereken bir sürücü, Muaf Olmayan Eyalet İçi'ni (NA) seçer. Muaf Eyalet İçi (EA) kutusu Kentucky'de kullanılmaz çünkü tüm KY CDL sahiplerinin tıbbi olarak belgelendirilmesi gerekir. Kaynak: KYTC Ticari Sürücü Belgesi Öz-Belgelendirme formu (TC 94-169); 601 KAR 1:005."},"38":{"q":"Kentucky CDL öz-belgelendirme formunda, tüm Kentucky CDL sahiplerinin tıbbi olarak belgelendirilmesi gerektiğinden hangi tıbbi belgelendirme kategorisi mevcut DEĞİLDİR ve asla seçilmemelidir?","options":["Muaf Eyalet İçi (EA)","Muaf Olmayan Eyaletler Arası (NI)","Muaf Eyaletler Arası (EI)","Muaf Olmayan Eyalet İçi (NA)"],"explanation":"Kentucky, Muaf Eyalet İçi (EA) kategorisine izin vermez; her KY CDL sahibinin tıbbi olarak belgelendirilmesi gerekir, bu nedenle EA asla işaretlenmemelidir. Diğer üçü (NI, EI, NA) geçerli seçimlerdir. Kaynak: KYTC Ticari Sürücü Belgesi Öz-Belgelendirme formu (TC 94-169); 601 KAR 1:005."},"39":{"q":"Bir Kentucky CDL'de, 'K' kısıtlama kodu neyi belirtir?","options":["Hava frenli CMV kullanılamaz","Tank aracında kargo taşınamaz","Eyalet içi (yalnızca Kentucky) operasyon","CMV otobüsünde yolcu taşınamaz"],"explanation":"'K' kısıtlaması, sahibini Kentucky içindeki eyalet içi ticaretle sınırlar ve 21 yaşın altındaki sürücüler ile eyalet içi sürüşle sınırlı diğer kişiler için geçerlidir. (Referans olarak, X = tankta kargo yok, L = hava freni yok, P = CMV otobüsünde yolcu yok.) Kaynak: Kentucky CDL Kılavuzu (KYTC, Mart 2025), 'Kısıtlamalar.'"},"40":{"q":"Kentucky'de ticari motorlu bir araç (CMV) kullanırken, bir sürücünün etki altında araç kullandığı kabul edildiği ve ehliyetinin geçersiz sayıldığı yasal eşik olan kandaki alkol konsantrasyonu (BAC) nedir?","options":["0.04 veya üzeri","0.08 veya üzeri","0.02 veya üzeri","0.10 veya üzeri"],"explanation":"Kentucky, CMV BAC sınırını, normal sürücüler için olan 0.08 sınırının yarısı olan 0.04 veya üzeri olarak belirler. Bir CMV'yi 0.04 veya üzerinde kullanmak, ehliyet geçersizliğini tetikleyen büyük bir ihlaldir. Kaynak: Kentucky CDL Kılavuzu (KYTC), KRS 281A.190; 49 CFR 383.51."},"41":{"q":"Kentucky'de, büyük bir ihlalden (örneğin bir CMV'de DUI) ilk mahkumiyet, CDL'nin ne kadar süreyle geçersiz kılınmasıyla sonuçlanır?","options":["1 yıl","60 gün","6 ay","3 yıl"],"explanation":"İlk büyük ihlal, sürücüyü 1 yıl süreyle (olay sırasında plaka gerektiren tehlikeli madde taşınıyorsa 3 yıl) diskalifiye eder. Kaynak: Kentucky CDL Kılavuzu (KYTC), KRS 281A.190; 49 CFR 383.51 Tablo 1."},"42":{"q":"Bir Kentucky CDL sahibi, plaka gerektiren tehlikeli madde taşırken ilk büyük ihlali işlerse, diskalifiye süresi ne kadara çıkar?","options":["3 yıl","1 yıl","5 yıl","2 yıl"],"explanation":"Plaka gerektiren tehlikeli madde taşırken işlenen ilk büyük ihlal, diskalifiye süresini 1 yıldan 3 yıla çıkarır. Kaynak: Kentucky CDL Kılavuzu (KYTC), KRS 281A.190; 49 CFR 383.51 Tablo 1."},"43":{"q":"Kentucky'nin zımni rıza (implied-consent) yasası uyarınca, ticari motorlu bir araç kullanarak bir sürücü hangi maddelerin kimyasal testine rıza göstermiş sayılır?","options":["Alkol veya uyuşturucu için kan, nefes veya idrar","Yalnızca alkol için nefes","Yalnızca uyuşturucu için kan","Yalnızca kontrollü maddeler için idrar"],"explanation":"Kentucky'nin zımni rıza yasası, bir memurun makul gerekçesi olduğunda her CMV sürücüsünün alkol veya kontrollü maddeleri tespit etmek için kan, nefes veya idrar testine rıza göstermiş sayıldığını kabul eder. Kaynak: Kentucky CDL Kılavuzu (KYTC), KRS 281A.150/281A.190."},"44":{"q":"Kentucky'de, gerekli bir nefes, kan veya idrar kimyasal testini vermeyi reddeden bir CDL sahibine ne olur?","options":["Büyük bir ihlal olarak değerlendirilir — en az 1 yıllık diskalifiye","İlk reddetmede yalnızca bir uyarı","60 günlük bir diskalifiye","30 günlük bir askıya alma ve bir para cezası"],"explanation":"Testi reddetmek başlı başına büyük bir ihlaldir ve bir DUI mahkumiyetiyle aynı diskalifiyeyi getirir: en az 1 yıl (plaka gerektiren HazMat ise 3 yıl). Kaynak: Kentucky CDL Kılavuzu (KYTC), KRS 281A.190; 49 CFR 383.51 Tablo 1."},"45":{"q":"Bir Kentucky CDL sahibi, ayrı bir olayda ikinci bir büyük ihlalden mahkum edilir. Diskalifiye süresi nedir?","options":["Ömür boyu diskalifiye","10 yıl","5 yıl","3 yıl"],"explanation":"Ayrı bir olayda ikinci bir büyük ihlal, CDL'nin ömür boyu diskalifiye edilmesiyle sonuçlanır. Kaynak: Kentucky CDL Kılavuzu (KYTC), KRS 281A.190; 49 CFR 383.51 Tablo 1."},"46":{"q":"Ömür boyu diskalifiye edilmiş bir Kentucky sürücüsü, onaylı bir rehabilitasyon programının tamamlanması gibi uygunluk gereklilikleri karşılanması koşuluyla, kaç yıl sonra yeniden ehliyet alma hakkına sahip olabilir?","options":["10 yıl","5 yıl","7 yıl","15 yıl"],"explanation":"Bir eyalet, kişi onaylı bir rehabilitasyon programını tamamlarsa, ömür boyu diskalifiye edilmiş bir sürücüyü en az 10 yıl sonra yeniden ehliyet sahibi yapabilir; bazı uyuşturucu/kaçakçılık ağır suçları için ise asla uygun olunmaz. Kaynak: Kentucky CDL Kılavuzu (KYTC); 49 CFR 383.51."},"47":{"q":"0.04'lük diskalifiye seviyesinin altında bile olsa, sisteminde herhangi bir tespit edilebilir miktarda alkol bulunan bir Kentucky CMV sürücüsüne ne olur?","options":["24 saat hizmet dışı bırakılır","Derhal 1 yıllığına diskalifiye edilir","Başka bir işlem yapılmadan 100 dolar para cezası verilir","60 günlük bir diskalifiye verilir"],"explanation":"0.04'ün altında ölçülebilir miktarda alkol bulunan bir sürücü 24 saat hizmet dışı bırakılır. 0.04 veya üzerine ulaşmak büyük bir ihlaldir. Kaynak: Kentucky CDL Kılavuzu (KYTC); 49 CFR 392.5."},"48":{"q":"Kentucky'de, 3 yıllık bir süre içinde (ayrı olaylarda) bir CMV'de iki ciddi trafik ihlalinden mahkumiyet, ne kadar süreyle diskalifiye ile sonuçlanır?","options":["60 gün","30 gün","120 gün","90 gün"],"explanation":"3 yıl içinde (ayrı olaylarda) iki ciddi trafik ihlali, 60 günlük bir diskalifiye ile sonuçlanır. Kaynak: Kentucky CDL Kılavuzu (KYTC), KRS 281A.190; 49 CFR 383.51 Tablo 2."},"49":{"q":"Kentucky'de, 3 yıllık bir süre içinde (ayrı olaylarda) bir CMV'de üç ciddi trafik ihlalinden mahkumiyet, ne kadar süreyle diskalifiye ile sonuçlanır?","options":["120 gün","60 gün","180 gün","1 yıl"],"explanation":"3 yıl içinde (ayrı olaylarda) üç ciddi trafik ihlali, diğer diskalifiyelerle ardışık olarak uygulanan 120 günlük bir diskalifiye ile sonuçlanır. Kaynak: Kentucky CDL Kılavuzu (KYTC), KRS 281A.190; 49 CFR 383.51 Tablo 2."},"50":{"q":"Aşağıdakilerden hangisi bir Kentucky CDL sahibi için ciddi bir trafik ihlali olarak sınıflandırılır?","options":["Belirlenen sınırın 15 mph veya üzerinde aşılması","Belirlenen sınırın 5 mph üzerinde aşılması","Tek bir park ihlali","Süresi dolmuş tescil etiketiyle araç kullanmak"],"explanation":"Aşırı hız (sınırın 15 mph veya üzerinde aşılması), pervasız sürüş, hatalı şerit değiştirme, çok yakından takip, mesaj yazma ve elde telefon kullanımının yanı sıra ciddi bir trafik ihlalidir. Kaynak: Kentucky CDL Kılavuzu (KYTC), KRS 281A.190; 49 CFR 383.51 Tablo 2."},"51":{"q":"Kentucky CDL amaçları açısından, bir CMV kullanırken mesaj yazma, diskalifiyeye doğru sayılırken nasıl değerlendirilir?","options":["Ciddi bir trafik ihlali olarak","Büyük bir ihlal olarak","Hizmet dışı bir ihlal olarak","Hiçbir CDL sonucu doğurmaz"],"explanation":"Bir CMV kullanırken mesaj yazma ciddi bir trafik ihlalidir; 3 yıl içinde iki tanesi 60 günlük diskalifiye, üç tanesi ise 120 günlük diskalifiye getirir. Kaynak: Kentucky CDL Kılavuzu (KYTC); 49 CFR 383.51 ve 49 CFR 392.80."},"52":{"q":"Kentucky'de bir CMV kullanırken elde tutulan bir cep telefonu kullanmak yasaktır ve CDL diskalifiyesine doğru hangi tür ihlal olarak sayılır?","options":["Ciddi bir trafik ihlali","Büyük bir ihlal","Demiryolu geçidi ihlali","Hizmet dışı emir ihlali"],"explanation":"Bir CMV kullanırken elde telefon kullanımı ciddi bir trafik ihlalidir; 3 yıl içinde iki tanesi 60 günlük diskalifiye, üç tanesi ise 120 günlük diskalifiye getirir. Kaynak: Kentucky CDL Kılavuzu (KYTC); 49 CFR 383.51 ve 49 CFR 392.82."},"53":{"q":"Bir CMV'de demiryolu-karayolu hemzemin geçit ihlalinden ilk mahkumiyet, en az ne kadar süreyle bir Kentucky CDL diskalifiyesiyle sonuçlanır?","options":["60 gün","30 gün","120 gün","1 yıl"],"explanation":"İlk demiryolu hemzemin geçit ihlali, 60 günden az olmayan bir diskalifiye getirir. Kaynak: Kentucky CDL Kılavuzu (KYTC), KRS 281A.190; 49 CFR 383.51 Tablo 3."},"54":{"q":"3 yıllık bir süre içinde ikinci bir demiryolu-karayolu hemzemin geçit ihlali, en az ne kadar süreyle bir Kentucky CDL diskalifiyesiyle sonuçlanır?","options":["120 gün","60 gün","180 gün","1 yıl"],"explanation":"3 yıl içinde ikinci bir hemzemin geçit ihlali, 120 günden az olmayan bir diskalifiye getirir. Kaynak: Kentucky CDL Kılavuzu (KYTC), KRS 281A.190; 49 CFR 383.51 Tablo 3."},"55":{"q":"3 yıllık bir süre içinde üçüncü veya sonraki bir demiryolu-karayolu hemzemin geçit ihlali, en az ne kadar süreyle bir Kentucky CDL diskalifiyesiyle sonuçlanır?","options":["1 yıl","120 gün","180 gün","60 gün"],"explanation":"3 yıl içinde üçüncü veya sonraki bir hemzemin geçit ihlali, 1 yıldan az olmayan bir diskalifiye getirir. Kaynak: Kentucky CDL Kılavuzu (KYTC), KRS 281A.190; 49 CFR 383.51 Tablo 3."},"56":{"q":"Aşağıdakilerden hangisi, bir Kentucky CDL sahibini diskalifiye edebilecek bir demiryolu hemzemin geçit ihlalidir?","options":["Geçidi tamamen geçecek yeterli alan olmadan bir geçide girmek","Trenleri kontrol etmek için raylardan 50 fit önce durmak","Yavaşlayıp rayların temiz olduğunu kontrol etmek","Geçiş hakkına sahip bir trene yol vermek"],"explanation":"Rayları geçmek için yeterli alan olmadan geçmek bir ihlaldir; yavaşlamamak/kontrol etmemek, gerektiğinde durmamak ve yeterli alt şasi açıklığına sahip olmamak gibi durumlar da ihlaldir. Kaynak: Kentucky CDL Kılavuzu (KYTC); 49 CFR 383.51 Tablo 3."},"57":{"q":"İlk kez bir hizmet dışı emri (out-of-service order) ihlal eden bir Kentucky CDL sahibi (HazMat olmayan, yolcu olmayan), en az ne kadar süreyle diskalifiye edilir?","options":["180 gün","60 gün","90 gün","1 yıl"],"explanation":"İlk hizmet dışı emir ihlali, 180 günden az olmayan (1 yıla kadar) bir diskalifiye getirir. Kaynak: Kentucky CDL Kılavuzu (KYTC), KRS 281A.190; 49 CFR 383.51 Tablo 4."},"58":{"q":"10 yıllık bir süre içindeki ikinci bir hizmet dışı emir ihlali için, bir Kentucky CDL sahibi en az ne kadar süreyle diskalifiye edilir?","options":["2 yıl","180 gün","1 yıl","3 yıl"],"explanation":"10 yıl içinde ikinci bir hizmet dışı emir ihlali, 2 yıldan az olmayan (5 yıla kadar) bir diskalifiye getirir. Kaynak: Kentucky CDL Kılavuzu (KYTC), KRS 281A.190; 49 CFR 383.51 Tablo 4."},"59":{"q":"10 yıllık bir süre içinde üçüncü veya sonraki bir hizmet dışı emir ihlali, en az ne kadar süreyle bir Kentucky CDL diskalifiyesiyle sonuçlanır?","options":["3 yıl","2 yıl","1 yıl","5 yıl"],"explanation":"10 yıl içinde üçüncü veya sonraki bir hizmet dışı emir ihlali, 3 yıldan az olmayan (5 yıla kadar) bir diskalifiye getirir. Kaynak: Kentucky CDL Kılavuzu (KYTC), KRS 281A.190; 49 CFR 383.51 Tablo 4."},"60":{"q":"Kentucky'nin 'Yavaşla, Şerit Değiştir' (Slow Down, Move Over) yasası kapsamında, bir CDL sürücüsü çok şeritli bir karayolunda yanıp sönen ışıklar gösteren ve durmuş bir acil durum veya kamu güvenliği aracına yaklaştığında, güvenli bir şekilde yapılabiliyorsa sürücünün İLK yükümlülüğü nedir?","options":["Aynı şeritte kalarak belirtilen hızda devam etmek","Acil durum aracı ayrılana kadar tamamen durmak","Bir şerit kayarak durmuş araca en yakın şeridi boşaltmak","Kamyonun yaklaştığını müdahale ekiplerine bildirmek için korna çalmak"],"explanation":"Kentucky'nin Şerit Değiştirme (Move Over) yasası (KRS 189.930), aynı yönde iki veya daha fazla şeride sahip bir yolda ilerleyen sürücünün, güvenli olduğunda, yanıp sönen ışıklar gösteren ve durmuş bir acil durum/kamu güvenliği aracına en yakın şeridi boşaltmasını gerektirir. Kaynak: KRS 189.930; Kentucky CDL Manual."},"61":{"q":"Sürücünün, yanıp sönen ışıklarla durmuş bir acil durum aracı için güvenli bir şekilde şerit değiştiremediği iki şeritli bir Kentucky yolunda, Şerit Değiştirme (Move Over) yasası sürücünün bunun yerine ne yapmasını gerektirir?","options":["Hızı; yol, hava ve trafik koşulları için güvenli bir seviyeye düşürmek","Acil durum aracından 500 feet önce tamamen durmak","Dörtlü flaşörleri yakmak ve hız sınırını korumak","Banketin üzerine çekip geçmesine izin verilmesini beklemek"],"explanation":"KRS 189.930 kapsamında, şerit değiştirmek imkansız veya güvensizse, sürücü hızı mevcut yol, hava ve trafik koşulları için güvenli bir seviyeye düşürmeli ve dikkatli bir şekilde ilerlemelidir. Kaynak: KRS 189.930."},"62":{"q":"Kentucky, Şerit Değiştirme (Move Over) yasasını Temmuz 2024'te genişletti. Polis, itfaiye ve ambulansların yanı sıra, genişletilmiş yasa artık sürücülerin aşağıdakilerden hangisi için şerit değiştirmesini veya yavaşlamasını da gerektirir?","options":["Arızalı araçlar ve çekiciler dahil, tehlike ışıkları veya uyarı sinyalleri gösteren herhangi bir sabit araç","Yalnızca işaretli kolluk kuvveti devriye araçları","Yalnızca aktif olarak bir seyir şeridini kapatan araçlar","Yalnızca Kentucky Transportation Cabinet'e ait araçlar"],"explanation":"KRS 189.930'un Temmuz 2024 genişlemesi, korumayı yalnızca geleneksel ilk müdahale ekipleriyle sınırlı tutmayıp, çekici/kurtarma araçları ve arızalı sürücüler gibi yanıp sönen ışıklar, tehlike ışıkları veya uyarı cihazları gösteren herhangi bir sabit araca genişletti. Kaynak: KRS 189.930 (2024 değişikliği)."},"63":{"q":"Kentucky'de bir CDL sürücüsü, plaka takılı (placarded) tehlikeli madde yükü taşıyor ve bir demiryolu geçidine yaklaşıyor. Sürücü, en yakın raydan ne kadar mesafe içinde durmalıdır?","options":["5 feet'ten az ve 25 feet'ten fazla olmamak üzere","15 feet'ten az ve 50 feet'ten fazla olmamak üzere","25 feet'ten az ve 75 feet'ten fazla olmamak üzere","50 feet'ten az ve 100 feet'ten fazla olmamak üzere"],"explanation":"Plaka takılı (placarded) tehlikeli madde aracının sürücüsü, geçiş yapmadan önce en yakın raydan 50 feet içinde ancak 15 feet'ten daha yakın olmamak üzere durmalıdır ('15 ile 50 feet' kuralı). Kaynak: 49 CFR 392.10, Kentucky'de kabul edilmiştir; Kentucky CDL Manual."},"64":{"q":"Kentucky CDL Manual'da öğretilen kurallara göre, bu ticari araçlardan hangisinin her demiryolu geçidinde durması GEREKİR?","options":["Boş bir düz platformlu (flatbed) çekici-römork","Yolcu taşıyan bir otobüs","Genel yük taşıyan bir kapalı kasa kamyon","Çakıl taşıyan bir damperli kamyon"],"explanation":"Yolcu taşıyan otobüsler ve tehlikeli madde plakaları (placards) gösteren araçlar, demiryolu geçitlerinde en yakın raydan 15 ile 50 feet içinde durarak durmalıdır. Genel yük kamyonlarının, sinyaller gerektirmedikçe durması gerekmez. Kaynak: 49 CFR 392.10; Kentucky CDL Manual."},"65":{"q":"Kentucky'nin okul otobüsü yasası kapsamında, dört şeritli bir karayolunda bir okul otobüsü kırmızı ışıkları yanıp sönerek ve dur kolu açık halde durur. Hangi sürücülerin durması GEREKMEZ?","options":["Otobüsün yanındaki şeritte aynı yönde ilerleyen sürücüler","Otobüsün hemen arkasında aynı şeritte bulunan sürücüler","Yön veya şerit sayısından bağımsız olarak tüm sürücüler durmalıdır","Dört veya daha fazla şeritli karayolunda karşı yönden yaklaşan sürücüler"],"explanation":"KRS 189.370 kapsamında, dört veya daha fazla şeritli bir karayolunda, durmuş bir okul otobüsünün karşı yönünden yaklaşan araçların durması gerekmez. Otobüsün bulunduğu taraftaki trafik yine de durmalıdır. Kaynak: KRS 189.370."},"66":{"q":"Standart iki şeritli, çift yönlü bir Kentucky karayolunda, bir okul otobüsü çocukları almak için kırmızı ışıkları yanıp sönerek ve dur kolu açık halde durur. Karşıdan gelen trafik ne yapmalıdır?","options":["25 mph'ye yavaşlamalı ancak otobüsün yanından geçmeye devam edebilir","Durmalı ve otobüs hareketine devam edene kadar durmuş halde kalmalıdır","Otobüs orta çizginin diğer tarafında olduğu için normal şekilde ilerlemelidir","Yalnızca yolu geçen çocuklar görünüyorsa durmalıdır"],"explanation":"İki şeritli bir yolda, KRS 189.370, sinyalleri aktif halde çocuk alıp indiren bir okul otobüsü için HER İKİ yönden gelen sürücülerin durmasını ve otobüs tekrar hareket edene kadar ilerlememesini gerektirir. Karşı yön istisnası yalnızca dört veya daha fazla şeritli karayollarına uygulanır. Kaynak: KRS 189.370."},"67":{"q":"Kentucky okul otobüsü durma gerekliliği (ve karşı yön istisnası) hangi belirli yol özelliğine dayanır?","options":["Karayolundaki şerit sayısı (dört veya daha fazla)","Hız sınırının 55 mph veya daha yüksek olup olmaması","Karayolunun belirlenmiş bir eyalet parkway'i olup olmaması","Yönleri ayıran fiziksel bir beton bariyerin olup olmaması"],"explanation":"KRS 189.370, karşı yön istisnasını bir orta bariyerin varlığına veya bir hız eşiğine değil, özellikle 'dört (4) veya daha fazla şeritli' bir karayoluna bağlar. Kaynak: KRS 189.370."},"68":{"q":"Kentucky yasası, belirli büyük araçları en soldaki şeritten kısıtlar. Aynı yönde ilerleyen üç veya daha fazla şeride sahip bir karayolunda, hangi araçların geçiş, giriş veya çıkış dışında en sol şeritte bulunması yasaktır?","options":["Motosikletler ve mopedler","Karavanlar ve motorlu karavanlar (motorhomes)","Çekiciler, römorklar ve yarı römorklar (semitrailers)","Tüm binek otomobilleri ve kamyonetler"],"explanation":"KRS 189.340, bir çekici, römork veya yarı römorkun (semitrailer); geçiş yaparken, karayoluna girip çıkarken, giren trafiğe yol verirken veya diğer şeritler güvensiz olduğunda haricinde, aynı yönde üç veya daha fazla şeride sahip bir karayolunun en sol şeridinde ilerlemesini yasaklar. Kaynak: KRS 189.340."},"69":{"q":"Kentucky'nin sol şerit kamyon kuralı kapsamında, bir yarı römorkun (semitrailer) üç şeritli bir eyaletler arası karayolunun en sol şeridinde yasal olarak bulunması için aşağıdakilerden hangisi geçerli bir nedendir?","options":["Yakıt tasarrufu için sabit bir seyir hızı korumak","Tüm yolculuk boyunca giriş rampalarından katılan araçlardan uzak durmak","Daha yavaş bir aracı geçmek, ardından mümkün olan en kısa sürede sağa dönmek","Frenleri korumak için hız sınırının biraz altında seyretmek"],"explanation":"KRS 189.340, bir çekici/römork/yarı römorkun (semitrailer) en sol şeridi yalnızca; geçiş yapmak (sonra mümkün olan en kısa sürede sağa dönmek), karayoluna girip çıkmak, giren trafiğe yol vermek veya sağ/orta şeritler güvensiz olduğunda gibi sınırlı nedenlerle kullanmasına izin verir. Kaynak: KRS 189.340."},"70":{"q":"I-64, I-65 ve I-75 gibi Kentucky'nin eyaletler arası karayollarının kırsal kesimlerinde kamyonlar için maksimum hız sınırı nedir?","options":["70 mph","65 mph","60 mph","75 mph"],"explanation":"Kentucky, çoğu kırsal eyaletler arası kesimde maksimum 70 mph belirler; daha düşük bir sınır belirtilmedikçe bu kamyonlara uygulanır. Kentsel kesimler (örn. Louisville ve Lexington çevresinde) tipik olarak 65 mph'dir. Kaynak: KRS 189.390; KYTC belirtilen sınırlar."},"71":{"q":"Louisville ve Lexington yakınındaki kentsel bölgelerde, bir CDL sürücüsünün beklemesi gereken eyaletler arası karayolu hız sınırı en yaygın olarak nedir?","options":["70 mph","65 mph","45 mph","55 mph"],"explanation":"Kentucky'nin kırsal eyaletler arası karayolları genellikle 70 mph olarak belirtilirken, Louisville ve Lexington gibi metropol alanları çevresindeki kentsel eyaletler arası kesimler yaygın olarak 65 mph olarak belirtilir. Sürücüler her zaman belirtilen sınıra uymalıdır. Kaynak: KRS 189.390; KYTC belirtilen sınırlar."},"72":{"q":"Bir CDL sürücüsünün kamyonu, gündüz vakti iki şeritli, çift yönlü bir Kentucky karayolunun banketinde arızalanır. Gerekli uyarı cihazları yerleştirildikten sonra, üç reflektif üçgen nereye yerleştirilmelidir?","options":["100 feet arkaya, 100 feet öne ve biri kabinin yanına","10 feet arkaya, 100 feet arkaya ve aracın 100 feet önüne","25 feet arkaya, 200 feet arkaya ve aracın 200 feet önüne","10 feet arkaya, 50 feet arkaya ve aracın 50 feet önüne"],"explanation":"İki şeritli, çift yönlü bir yolda, bir üçgeni arkanın 10 feet içine, birini yaklaşık 100 feet arkaya ve birini aracın yaklaşık 100 feet önüne yerleştirin. Kaynak: 49 CFR 392.22, Kentucky'de kabul edilmiştir; Kentucky CDL Manual."},"73":{"q":"Bir ticari araç tek yönlü veya bölünmüş bir Kentucky karayolunda durduğunda, üç uyarı cihazı yaklaşan trafiğe göre nereye yerleştirilir?","options":["100 feet arkaya ve 100 feet öne, ayrıca biri kabinde","Yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet","Yaklaşan trafiğe doğru 200 feet, 200 feet ve 500 feet","Yaklaşan trafiğe doğru 10 feet, 50 feet ve 100 feet"],"explanation":"Tek yönlü veya bölünmüş bir karayolunda, uyarı cihazlarını, aracın bulunduğu şeridin veya banketin ortasında yaklaşan trafiğe doğru 10 feet, 100 feet ve 200 feet'e yerleştirin. Kaynak: 49 CFR 392.22; Kentucky CDL Manual."},"74":{"q":"Arızalı bir ticari aracı bir Kentucky yolunda durdurduktan sonra, sürücü gerekli acil durum uyarı cihazlarını kaç dakika içinde yerleştirmelidir?","options":["10 dakika içinde","5 dakika içinde","30 dakika içinde","15 dakika içinde"],"explanation":"Bir sürücü, gerekli üç uyarı cihazını durduktan sonra 10 dakika içinde yerleştirmelidir. Kaynak: 49 CFR 392.22, Kentucky'de kabul edilmiştir; Kentucky CDL Manual."},"75":{"q":"Kentucky'nin Pine Mountain'ı (U.S. 119) gibi uzun bir inişte, Kentucky CDL Manual'da öğretilen doğru frenleme tekniği nedir?","options":["Aracı yavaşlatmak için el frenini aralıklı olarak uygulamak","Motorun soğumasına izin vermek için boşa almak ve frenlere hafifçe basmak","İnişten önce düşük bir vites seçmek ve hafif, sabit veya aralıklı (snub) frenleme kullanmak","Mümkün olan en yüksek vitesi korumak ve frenlere sürekli olarak basmak"],"explanation":"Sürücüler, bir yokuşu inmeye başlamadan önce uygun düşük vitesi seçmeli ve esas olarak motor frenine güvenmeli, servis frenlerini hafif, aralıklı (snub) uygulamalarda kullanmalıdır. Frenlere sürekli basmak, aşırı ısınmaya ve fren kaybına (brake fade) neden olur. Kaynak: Kentucky CDL Manual (Hız Kontrolü / Dağ Sürüşü)."},"76":{"q":"Kentucky'de gabari aşımı izni olmadan, belirlenmiş karayollarında bir ticari araç ve yük için izin verilen maksimum yasal genişlik nedir?","options":["10 feet 0 inches","9 feet 6 inches","8 feet 0 inches","8 feet 6 inches"],"explanation":"Kentucky'nin eyaletler arası karayollarında ve belirlenmiş karayollarındaki yasal maksimum araç/yük genişliği 8 feet 6 inches'tır (102 inches); daha geniş olan her şey KYTC'den gabari aşımı izni gerektirir. Kaynak: KRS Chapter 189; KYTC Overweight/Over-Dimensional Permits."},"77":{"q":"Kentucky'de bir yükün yüksekliği 14 feet'tir. İzin olmadan yasal maksimum yükseklik 13 feet 6 inches'tır. Taşıyıcı, bu yükü taşımadan önce ne almalıdır?","options":["Yalnızca yerel ilçe şerifinden izin","Hiçbir şey, çünkü Kentucky'de yükseklik sınırları yalnızca tavsiye niteliğindedir","Kentucky Transportation Cabinet'ten bir gabari aşımı/aşırı boyut izni","Yalnızca bir tehlikeli madde onayı (endorsement)"],"explanation":"Kentucky'nin yasal maksimum yüksekliği 13 feet 6 inches'tır; 14 feet'lik bir yük bunu aşar ve seyahatten önce KYTC Division of Motor Carriers aracılığıyla verilen bir aşırı boyut izni gerektirir. Kaynak: KRS Chapter 189; KYTC Overweight/Over-Dimensional Permits."},"78":{"q":"Kentucky, genellikle hangi tür yük için gabari aşımı/aşırı yük izni VERMEZ?","options":["Parçalara ayrılamayan tek bir endüstriyel makine parçası","Makul ölçüde bölünebilir olan ve yasal sınırları karşılayacak şekilde yeniden yapılandırılabilecek bir yük","Yasal ağırlığı aşan büyük bir transformatör","Yasal genişliği aşan ön üretimli bir bina bölümü"],"explanation":"Kentucky, OS/OW (gabari aşımı/aşırı yük) izinlerini yalnızca bölünemeyen yükler için verir; makul ölçüde bölünebilir bir yüke (yasal sınırlara uyacak şekilde sökülebilen veya yeniden yapılandırılabilen bir yük), belirli yasal yetki dışında izin vermez. Kaynak: KYTC Overweight/Over-Dimensional Permits; KRS Chapter 189."},"79":{"q":"Hangi Kentucky kurumu, nitelikli başvuru sahiplerine Ticari Sürücü Belgesi (CDL) kimlik belgesini fiilen verir?","options":["Kentucky Transportation Cabinet'in Division of Driver Licensing'i","Kentucky State Police","Federal Motor Carrier Safety Administration","İlçe Circuit Court Clerk'ın kefalet bürosu"],"explanation":"Kentucky'de CDL kimlik belgesi, Kentucky Transportation Cabinet (KYTC), Division of Driver Licensing tarafından verilir. Kaynak: KYTC drive.ky.gov CDL sayfası; 2025 Kentucky CDL Manual."},"80":{"q":"Kentucky'de başvuru sahipleri için CDL bilgi testlerini ve yol becerileri testini kim yürütür?","options":["Kentucky State Police","İlçe Circuit Court Clerk","Yalnızca özel üçüncü taraf kamyon sürücü okulları","FMCSA National Registry"],"explanation":"Kentucky State Police (KSP), Kentucky'deki tüm CDL bilgi ve beceri testlerini yürütmekten münhasıran sorumludur; lisansı ise KYTC verir. Kaynak: 2025 Kentucky CDL Manual; Kentucky State Police Driver Testing."},"81":{"q":"Bir Kentucky Ticari Öğrenci İzni (CLP) kaç gün geçerlidir?","options":["180 gün","60 gün","365 gün","90 gün"],"explanation":"Bir Kentucky CLP, en fazla 180 gün geçerlidir. Kaynak: KRS 281A.120; 2025 Kentucky CDL Manual."},"82":{"q":"Bir CLP verildikten sonra, başvuru sahibi Kentucky'de CDL beceri testine girmeden önce ne kadar beklemelidir?","options":["En az 14 gün","En az 30 gün","En az 7 gün","En az 60 gün"],"explanation":"Bir başvuru sahibi, CDL beceri testine girmeye hak kazanmadan önce CLP'yi en az 14 gün boyunca elinde bulundurmalıdır. Bu, Kentucky'de uygulanan bir federal standarttır. Kaynak: 2025 Kentucky CDL Manual; 49 CFR 383.25."},"83":{"q":"Bir Kentucky Ticari Sürücü Belgesi, yenilenmesi gerekmeden önce ne kadar süre geçerlidir?","options":["8 yıl","4 yıl","5 yıl","10 yıl"],"explanation":"Bir Kentucky CDL kimlik belgesi 8 yıl geçerlidir. Kaynak: KRS 281A.170; KYTC drive.ky.gov."},"84":{"q":"Bir Kentucky CDL başvuru sahibinin sertifikalı bir tıbbi muayeneciden alması gereken DOT Tıbbi Muayeneci Sertifikası hangi formdur?","options":["Form MCSA-5876","Form TC 94-169","Yalnızca Form MCSA-5875","Form DOT-391"],"explanation":"Tıbbi Muayeneci Sertifikası, National Registry Certified Medical Examiner tarafından doldurulan Form MCSA-5876'dır; CDL sahibi için dosyada bulunmalıdır. (TC 94-169, ayrı bir öz-sertifikasyon formudur.) Kaynak: KYTC ilk kez başvuru sahibi bilgileri; FMCSA."},"85":{"q":"Kentucky CDL öz-sertifikasyonunda, bir başvuru sahibinin kaç sürüş türü kategorisinden seçim yapması gerekir?","options":["Dört","İki","Üç","Beş"],"explanation":"Öz-sertifikasyon (Form TC 94-169) dört kategoriye sahiptir: muafiyetsiz eyaletler arası (non-excepted interstate), muafiyetli eyaletler arası (excepted interstate), muafiyetsiz eyalet içi (non-excepted intrastate) ve muafiyetli eyalet içi (excepted intrastate). Kaynak: KYTC Form TC 94-169; 49 CFR 383.71."},"86":{"q":"Eyalet sınırlarının ötesinde araç kullanan ve federal fiziksel yeterlilik standartlarını karşılaması gereken bir Kentucky sürücüsü, hangi kategoride öz-sertifikasyon yapmalıdır?","options":["Muafiyetsiz eyaletler arası (non-excepted interstate)","Muafiyetli eyaletler arası (excepted interstate)","Muafiyetsiz eyalet içi (non-excepted intrastate)","Muafiyetli eyalet içi (excepted intrastate)"],"explanation":"Federal fiziksel yeterlilik kurallarına tabi olan eyaletler arası ticaretteki sürücüler, dosyada güncel bir Tıbbi Muayeneci Sertifikası gerektiren muafiyetsiz eyaletler arası (non-excepted interstate) olarak sertifikasyon yapar. Kaynak: KYTC Form TC 94-169; 49 CFR 383.71."},"87":{"q":"İlk kez başvuran bir Class A veya Class B başvuru sahibi Kentucky'de CDL beceri testine girmeden önce hangi eğitim gerekliliğinin karşılanması gerekir?","options":["Kayıtlı bir sağlayıcıdan Giriş Düzeyi Sürücü Eğitimi (ELDT)","KYTC tarafından desteklenen 160 saatlik bir eyalet çıraklık programı","Circuit Court Clerk'ta bir savunmacı sürüş kursu","İki yıl belgelenmiş eyalet içi sürüş"],"explanation":"İlk kez Class A/B testinden (ve ilk P, S veya H onayı testinden) önce bir FMCSA Training Provider Registry sağlayıcısından federal Giriş Düzeyi Sürücü Eğitimi (ELDT) gereklidir. Kaynak: 2025 Kentucky CDL Manual; 49 CFR Part 380."},"88":{"q":"Aşağıdaki onaylardan (endorsements) hangisi, ilk kez başvuran Class A ve Class B başvuru sahiplerine ek olarak, testten önce ELDT tamamlanmasını gerektirir?","options":["Tehlikeli maddeler (H), yolcu (P) ve okul otobüsü (S)","Tank aracı (N) ve ikili/üçlü (T)","Yalnızca okul otobüsü (S) onayı","Hiçbir onay ELDT gerektirmez"],"explanation":"ELDT; ilk kez başvuran tehlikeli maddeler (H), yolcu (P) ve okul otobüsü (S) onayları için olduğu kadar, ilk Class A/B verilmesi ve Class B'den A'ya yükseltmeler için de gereklidir. Kaynak: 2025 Kentucky CDL Manual; 49 CFR Part 380."},"89":{"q":"Kentucky CDL beceri testi üç bölümde uygulanır. Hangi grup bu üç bölümü doğru şekilde listeler?","options":["Sefer öncesi muayene (pre-trip inspection), temel araç kontrolü ve yolda sürüş","Yazılı bilgi, görme taraması ve yolda sürüş","Sefer öncesi muayene, hava freni yazılı testi ve geri manevra","Temel araç kontrolü, hazmat yazılı testi ve yolda sürüş"],"explanation":"CDL beceri testi üç bölümden oluşur: sefer öncesi muayene (pre-trip inspection), temel araç kontrol becerileri ve yolda sürüş testi. Kaynak: 2025 Kentucky CDL Manual; 49 CFR 383.113."},"90":{"q":"Bir Kentucky başvuru sahibi CDL beceri testini hangi tür araçta yapmalıdır?","options":["Başvuru sahibinin sürmek için lisans almak istediği araç sınıfı/türü","10,001 pounds'tan ağır herhangi bir ticari araç","Test istasyonu tarafından sağlanan standart bir binek otomobili","Talep edilen lisans sınıfından bağımsız olarak bir Class C aracı"],"explanation":"Başvuru sahipleri, beceri testini lisans almak istedikleri sınıf ve türü temsil eden bir araçta yapmalıdır. Kaynak: 2025 Kentucky CDL Manual; 49 CFR 383.71."},"91":{"q":"İlk kez başvuran bir Kentucky CDL başvuru sahibi, izin veya lisans verilmeden önce hangi belgelere dosyada sahip olmalıdır?","options":["CDL başvurusu, öz-sertifikasyon formu ve okunaklı bir DOT Tıbbi Muayeneci Sertifikası","Yalnızca bir Social Security kartı ve bir görme taraması sonucu","Bir işveren mektubu ve bir araç tescili","Bir pasaport ve bir FMCSA clearinghouse aboneliği"],"explanation":"Bir CLP veya CDL verilmeden önce, Kentucky; CDL başvurusunu, öz-sertifikasyonu (TC 94-169) ve DOT Tıbbi Muayeneci Sertifikasının okunaklı bir kopyasını, hepsi KYTC'ye sunulmuş (mycdl.ky.gov aracılığıyla) olarak gerektirir. Kaynak: KYTC ilk kez başvuru sahibi bilgileri; drive.ky.gov."},"92":{"q":"Bir Kentucky CLP, başvuru sahibi beceri testini geçmeden önce süresi dolarsa, genellikle ne olur?","options":["Başvuru sahibi, yeni bir CLP almak için gerekli bilgi testlerini yeniden yapmalıdır","CLP otomatik olarak bir 180 gün daha uzatılır","Beceri testi puanları iki yıl boyunca devredilir","Başvuru sahibi, 30 günlük bir ek süre içinde beceri testine girebilir"],"explanation":"Kentucky, 180 günlük CLP'yi uzatmaz; beceri testi geçilmeden önce süresi dolarsa, başvuru sahibi yeni bir CLP alabilmek için bilgi testlerini yeniden yapmalıdır. Kaynak: 2025 Kentucky CDL Manual; KRS 281A.120."},"93":{"q":"Kentucky CDL genel bilgi testinde minimum geçme puanı nedir?","options":["Yüzde 80 doğru","Yüzde 70 doğru","Yüzde 75 doğru","Yüzde 90 doğru"],"explanation":"Bir başvuru sahibi, her bir CDL bilgi testini geçmek için en az yüzde 80 puan almalıdır; bu, Kentucky'de uygulanan federal standarttır. Kaynak: 2025 Kentucky CDL Manual; 49 CFR 383.135."},"94":{"q":"Eyalet içi (Kentucky içi) ticaretle sınırlı bir Kentucky CDL'sinin verilebilmesi için minimum yaş nedir?","options":["18 yaşında","21 yaşında","19 yaşında","16 yaşında"],"explanation":"Bir kişi, Kentucky'de eyalet içi sürüş için bir CDL'ye sahip olmak üzere en az 18 yaşında olmalıdır; eyaletler arası sürüş ve hazmat/okul otobüsü kullanımı için 21 yaş gereklidir. Kaynak: KRS 281A; 2025 Kentucky CDL Manual."},"95":{"q":"Bir Kentucky CDL'si ile eyaletler arası ticarette bir ticari motorlu araç kullanmak için gereken minimum yaş nedir?","options":["21 yaşında","18 yaşında","19 yaşında","25 yaşında"],"explanation":"Sürücüler, eyaletler arası ticarette çalışmak için en az 21 yaşında olmalıdır; 18 ila 20 yaşındakiler bir eyalet içi (yalnızca Kentucky) kısıtlaması alır. Kaynak: KRS 281A; 2025 Kentucky CDL Manual; 49 CFR 391.11."},"96":{"q":"Bir Kentucky CDL sahibi yeni bir DOT tıbbi muayenesi olduğunda, CDL'yi 'sertifikalı' (certified) durumda tutmak için sürücü ne yapmalıdır?","options":["Sürüş kaydının güncel kalması için güncellenmiş Tıbbi Muayeneci Sertifikasını mycdl.ky.gov aracılığıyla KYTC'ye sunmak","Sertifikayı yalnızca kabinde tutmak ve istenirse polise göstermek","Sertifikayı eyalet yerine FMCSA National Registry'ye postalamak","Sertifikayı yeniden geçerli kılmak için bilgi testini tekrar yapmak"],"explanation":"'Sertifikasız' (not certified) durumuna düşürülmemek için, sürücü her yeni Tıbbi Muayeneci Sertifikasını, CDLIS sürüş kaydına işlenmesi amacıyla, tipik olarak mycdl.ky.gov portalı aracılığıyla KYTC'ye sunmalıdır. Kaynak: KYTC ilk kez başvuru sahibi bilgileri; 49 CFR 383.71/383.73."},"97":{"q":"Bir Kentucky CDL'sini yenileme konusunda, posta/çevrimiçi süreçle ilgili hangi ifade doğrudur?","options":["Bir CDL genellikle posta yoluyla yenilenemez ve yüz yüze yenileme gerektirir","Bir CDL otomatik olarak yenilenir ve herhangi bir başvuru olmadan postalanır","Bir CDL her zaman belge olmadan çevrimiçi yenilenebilir","Sürücü beceri testini geçtikten sonra bir CDL'nin süresi asla dolmaz"],"explanation":"Class A, B veya C (CDL) kimlik belgeleri genellikle posta yoluyla yenilenemez; güncel tıbbi sertifikasyonla yüz yüze yenileme gereklidir. Kaynak: KRS 281A.170; KYTC drive.ky.gov."}},"es":{"0":{"q":"En las autopistas interestatales y vías designadas de Kentucky, ¿cuál es el ancho máximo legal de un vehículo comercial (excluyendo los accesorios de seguridad aprobados, como los espejos)?","options":["8 pies 3 pulgadas (99 pulgadas)","8 pies 6 pulgadas (102 pulgadas)","8 pies 0 pulgadas (96 pulgadas)","9 pies 0 pulgadas (108 pulgadas)"],"explanation":"Kentucky limita el ancho del vehículo a 8 pies 6 pulgadas (102 pulgadas) en las interestatales y vías designadas, en concordancia con 23 CFR 658. Fuente: página de Dimensiones Legales de Kentucky DRIVE (KYTC); KRS 189.221/189.222."},"1":{"q":"¿Cuál es el ancho máximo legal de un vehículo en las vías mantenidas por el estado de Kentucky que NO son interestatales ni vías designadas de otro modo?","options":["8 pies (96 pulgadas)","8 pies 6 pulgadas (102 pulgadas)","7 pies 6 pulgadas (90 pulgadas)","9 pies (108 pulgadas)"],"explanation":"En las carreteras no designadas mantenidas por el estado en Kentucky, el ancho legal baja a 8 pies (96 pulgadas); la tolerancia de 8'6\" se aplica únicamente al sistema interestatal y de vías designadas. Fuente: página de Dimensiones Legales de Kentucky DRIVE (KYTC); KRS 189.221."},"2":{"q":"¿Cuál es la altura máxima legal de un vehículo en las carreteras de Kentucky antes de requerir un permiso por exceso de dimensiones?","options":["14 pies 0 pulgadas","14 pies 6 pulgadas","13 pies 0 pulgadas","13 pies 6 pulgadas"],"explanation":"Kentucky establece la altura máxima legal del vehículo y la carga en 13 pies 6 pulgadas; cualquier cosa más alta requiere un permiso por exceso de dimensiones. Fuente: página de Dimensiones Legales de Kentucky DRIVE (KYTC); KRS 189.222."},"3":{"q":"¿Cuál es la longitud máxima legal de un semirremolque individual que opera en el sistema interestatal y de vías designadas de Kentucky?","options":["45 pies","57 pies","53 pies","48 pies"],"explanation":"Un semirremolque individual puede tener hasta 53 pies de longitud en las interestatales y vías designadas de Kentucky. Fuente: página de Dimensiones Legales de Kentucky DRIVE (KYTC); KRS 189.221/189.222."},"4":{"q":"En una combinación de remolques gemelos (dobles) que opera en Kentucky, ¿cuál es la longitud máxima legal de cada remolque individual?","options":["26 pies cada uno","28 pies cada uno","30 pies cada uno","32 pies cada uno"],"explanation":"Kentucky permite remolques gemelos/dobles de hasta 28 pies cada uno, en concordancia con la dimensión de dobles protegida a nivel federal. Fuente: página de Dimensiones Legales de Kentucky DRIVE (KYTC); KRS 189.222."},"5":{"q":"¿Cuál es la longitud máxima legal de un camión de motor de una sola unidad en las carreteras de Kentucky?","options":["45 pies","53 pies","48 pies","40 pies"],"explanation":"Un camión de motor de una sola unidad está limitado a 45 pies de longitud según las reglas de dimensiones de Kentucky. Fuente: página de Dimensiones Legales de Kentucky DRIVE (KYTC); KRS 189.221."},"6":{"q":"En las vías mantenidas por el estado de Kentucky que NO forman parte del sistema designado, ¿cuál es la longitud total máxima de una combinación de camión tractor y remolque?","options":["75 pies","70 pies","60 pies","65 pies"],"explanation":"En las carreteras no designadas mantenidas por el estado, la longitud total de la combinación se limita a 65 pies, aun cuando se permita un semirremolque de 53 pies en las vías designadas. Fuente: página de Dimensiones Legales de Kentucky DRIVE (KYTC); KRS 189.221."},"7":{"q":"¿Cuál es el peso bruto máximo legal de un vehículo comercial y su carga en las carreteras de Kentucky sin un permiso por sobrepeso?","options":["84,000 libras","88,000 libras","80,000 libras","73,280 libras"],"explanation":"Kentucky limita el peso bruto vehicular total a 80,000 libras, en concordancia con el estándar federal interestatal. Fuente: KRS 189.222; 603 KAR 5:066; Kentucky DRIVE (KYTC)."},"8":{"q":"¿Cuál es el peso máximo legal que se puede llevar sobre un solo eje en Kentucky?","options":["22,400 libras","20,000 libras","18,000 libras","24,000 libras"],"explanation":"Ningún eje individual puede exceder las 20,000 libras en Kentucky (o 700 libras por pulgada de ancho agregado de neumático, lo que sea menor). Fuente: KRS 189.222; 603 KAR 5:066."},"9":{"q":"¿Cuál es el peso máximo legal sobre un grupo de ejes en tándem (ejes separados de 42 a 96 pulgadas) en Kentucky?","options":["34,000 libras","36,000 libras","40,000 libras","32,000 libras"],"explanation":"Un grupo de ejes en tándem separados de 42 a 96 pulgadas está limitado a 34,000 libras en Kentucky. Fuente: KRS 189.222; 603 KAR 5:066; Dimensiones Legales de Kentucky DRIVE (KYTC)."},"10":{"q":"En Kentucky, ¿cuál es el peso máximo legal sobre un grupo de ejes trídem (tres ejes) separados de 42 a 120 pulgadas?","options":["45,000 libras","42,000 libras","51,000 libras","48,000 libras"],"explanation":"Un grupo de ejes trídem separados entre 42 y 120 pulgadas puede llevar hasta 48,000 libras en Kentucky. Fuente: KRS 189.222; página de Dimensiones Legales de Kentucky DRIVE (KYTC)."},"11":{"q":"Kentucky permite una tolerancia de peso sobre los pesos por eje, pero solo en ciertas carreteras. ¿En cuáles carreteras se aplica la tolerancia del 5 por ciento sobre el peso por eje?","options":["Solo en las carreteras mantenidas por el condado","En todas las carreteras, incluido el sistema interestatal","En las carreteras mantenidas por el estado que NO forman parte del sistema interestatal","Solo en el sistema interestatal"],"explanation":"Kentucky permite una tolerancia de no más del 5 por ciento sobre el peso por eje en las carreteras mantenidas por el estado que no forman parte del sistema interestatal; en la interestatal no se aplica ninguna tolerancia por eje. Fuente: KRS 189.222."},"12":{"q":"Según la ley de Kentucky, ¿cómo se aplica la tolerancia de peso del 5 por ciento al peso BRUTO del vehículo?","options":["Una tolerancia del 5 por ciento se aplica solo en la interestatal","No se permite ninguna tolerancia sobre el peso bruto","Una tolerancia del 10 por ciento se aplica en carreteras que no son interestatales","Una tolerancia del 5 por ciento se aplica en todas las carreteras"],"explanation":"Kentucky no permite expresamente NINGUNA tolerancia sobre el peso bruto; la tolerancia del 5 por ciento se aplica únicamente a los pesos por eje en las carreteras no interestatales mantenidas por el estado. Fuente: KRS 189.222."},"13":{"q":"Kentucky usa la fórmula federal de puentes para limitar el peso sobre los grupos de ejes consecutivos. ¿Con qué relaciona principalmente el peso bruto esta fórmula?","options":["El número de ejes y la separación (distancia) entre ellos","El número de neumáticos y su presión de aire","Los caballos de fuerza del motor y la clasificación de peso bruto combinado","La longitud del remolque y la densidad de la carga"],"explanation":"La Fórmula Federal de Puentes, W=500(LN/(N-1)+12N+36), limita el peso sobre cualquier grupo de dos o más ejes consecutivos en función del número de ejes (N) y la distancia (L) entre los ejes extremos del grupo. Kentucky la aplica mediante la adopción de 23 CFR Parte 658. Fuente: 23 CFR 658.17; KRS 189.222."},"14":{"q":"En la fórmula federal de puentes W = 500(LN/(N-1) + 12N + 36) usada en Kentucky, ¿qué representa la variable 'L'?","options":["El peso legal de la carga en toneladas","La capacidad de elevación de la suspensión","La longitud del remolque en pies","La distancia en pies entre los ejes extremos del grupo"],"explanation":"En la fórmula de puentes, L es la distancia en pies entre los extremos de cualquier grupo de dos o más ejes consecutivos, mientras que N es el número de ejes de ese grupo. Fuente: 23 CFR 658.17 (Fórmula de Puentes), adoptada en Kentucky bajo KRS 189.222."},"15":{"q":"Dos conjuntos consecutivos de ejes en tándem pueden llevar cada uno las 34,000 libras completas en Kentucky solo si la distancia entre el primer y el último eje de esos tándems es de al menos cuántos pies?","options":["28 pies","40 pies","36 pies","30 pies"],"explanation":"Bajo la excepción de la fórmula de puentes adoptada por Kentucky, dos conjuntos consecutivos de ejes en tándem pueden llevar cada uno 34,000 libras solo cuando la separación total entre el primer y el último eje de esos tándems es de 36 pies o más. Fuente: 23 CFR 658.17; KRS 189.222."},"16":{"q":"¿Cuándo se requiere un permiso de Kentucky por exceso de tamaño/sobrepeso (OS/OW)?","options":["Solo al circular por carreteras del condado","Antes de mover cualquier vehículo o carga que exceda los límites legales de ancho, altura, longitud o peso","Solo cuando el peso bruto exceda las 90,000 libras","Solo cuando la carga sea más ancha de 10 pies"],"explanation":"Se debe obtener un permiso de Kentucky ANTES de mover cualquier vehículo o carga que exceda los límites legales establecidos por ley para ancho, altura, longitud o peso. Fuente: División de Transportistas Motorizados de la KYTC; 601 KAR 1:018."},"17":{"q":"¿Qué agencia de Kentucky emite los permisos especiales para cargas de vehículos motorizados por sobrepeso/exceso de dimensiones, y qué tipo de carga generalmente no puede recibir dicho permiso?","options":["La División de Transportistas Motorizados de la KYTC; las cargas razonablemente divisibles generalmente no pueden ser autorizadas","El DOT de EE. UU.; solo las cargas interestatales pueden ser autorizadas","La Policía Estatal de Kentucky; solo las cargas agrícolas pueden ser autorizadas","Los tribunales fiscales del condado; solo los productos forestales pueden ser autorizados"],"explanation":"La División de Transportistas Motorizados del Gabinete de Transporte de Kentucky emite permisos OS/OW bajo 601 KAR 1:018, y por lo general NO se emiten permisos para cargas que sean razonablemente divisibles (que podrían desarmarse o dividirse para cumplir con los límites legales). Fuente: 601 KAR 1:018; KRS 189.270."},"18":{"q":"Kentucky ofrece una variación especial para equipo agrícola no divisible. ¿Qué permite esto?","options":["El equipo agrícola puede circular con cualquier ancho sin permiso en carreteras de dos carriles","El equipo agrícola puede exceder las 120,000 libras en la interestatal sin permiso","El equipo agrícola está exento de todas las reglas de permisos y peso en todo el estado","Se puede emitir un permiso de un solo viaje para equipo agrícola no divisible que exceda los límites legales de peso o dimensiones"],"explanation":"Kentucky emite un permiso de un solo viaje por sobrepeso/exceso de dimensiones para el traslado de equipo agrícola no divisible que exceda los límites de KRS 189.222 o 189.270; es una variación autorizada, no una exención general. Fuente: 601 KAR 1:019; 601 KAR 1:018."},"19":{"q":"Bajo el Sistema de Carreteras de Transporte de Carbón con Peso Extendido (ECWHRS) de Kentucky, ¿a qué peso bruto máximo puede operar un tractor-semirremolque de 5 o más ejes que transporta carbón?","options":["90,000 libras (con una tolerancia del 5 por ciento)","80,000 libras (sin tolerancia)","120,000 libras (con una tolerancia del 5 por ciento)","100,000 libras (con una tolerancia del 10 por ciento)"],"explanation":"En el Sistema de Carreteras de Transporte de Carbón con Peso Extendido, un tractor-semirremolque con cinco o más ejes que transporta carbón o subproductos del carbón puede operar hasta 120,000 libras brutas con una tolerancia del 5 por ciento. Fuente: KRS 177.9771."},"20":{"q":"En Kentucky, se requiere una CDL Clase A para operar cualquier combinación de vehículos con una clasificación de peso bruto combinado (GCWR) de 26,001 libras o más, siempre que el GVWR del vehículo o vehículos remolcados exceda qué peso?","options":["10,000 libras","26,001 libras","16,000 libras","1,000 libras"],"explanation":"Kentucky requiere una CDL Clase A para combinaciones con un GCWR de 26,001 lbs o más cuando la unidad o unidades remolcadas tienen un GVWR mayor a 10,000 lbs. Fuente: Manual CDL de Kentucky (KYTC, marzo de 2025), '¿Quién debe solicitarla? - CDL Clase A.'"},"21":{"q":"Según las reglas de Kentucky, se requiere una CDL Clase B para conducir cualquier vehículo individual con una clasificación de peso bruto vehicular (GVWR) de al menos cuántas libras?","options":["10,001 libras","26,001 libras","33,000 libras","16,001 libras"],"explanation":"Una CDL Clase B cubre cualquier vehículo individual con un GVWR de 26,001 lbs o más, incluyendo dicho vehículo cuando remolca una unidad con un GVWR de 10,000 lbs o menos. Fuente: Manual CDL de Kentucky (KYTC, marzo de 2025), 'CDL Clase B.'"},"22":{"q":"Según el Manual CDL de Kentucky, un vehículo con un GVWR menor a 26,001 libras requiere una CDL Clase C cuando está diseñado para transportar al menos cuántas personas, incluido el conductor?","options":["15","24","16","9"],"explanation":"Kentucky requiere una CDL Clase C para un vehículo con un GVWR menor a 26,001 lbs que transporte 16 o más pasajeros incluido el conductor, o que transporte materiales peligrosos que requieran rótulos (placards). Fuente: Manual CDL de Kentucky (KYTC, marzo de 2025), 'CDL Clase C.'"},"23":{"q":"En Kentucky, ¿qué clase de CDL aplica a un vehículo con un GVWR de menos de 26,001 libras que transporta materiales peligrosos en cantidades que requieren rótulos (placards)?","options":["Clase A","Clase B","Clase D","Clase C"],"explanation":"Una CDL Clase C cubre los vehículos con un GVWR menor a 26,001 lbs que transportan materiales peligrosos que requieren rótulos (placards) o 16 o más pasajeros (incluido el conductor). Fuente: Manual CDL de Kentucky (KYTC, marzo de 2025), 'CDL Clase C.'"},"24":{"q":"¿Cuál es la edad mínima a la que Kentucky puede emitir una CDL limitada al comercio intraestatal (con una restricción 'K')?","options":["21 años","18 años","19 años","16 años"],"explanation":"Kentucky puede emitir una CDL específica de clase con una restricción 'K' (solo intraestatal) a una persona de 18 a 20 años que cumpla con los requisitos de los exámenes y no conduzca un autobús escolar ni transporte materiales peligrosos. Fuente: Manual CDL de Kentucky (KYTC, marzo de 2025), 'Persona de Dieciocho (18) Años de Edad Conduciendo Intraestatalmente.'"},"25":{"q":"Un titular de CDL de Kentucky que quiere conducir un vehículo motorizado comercial en el comercio interestatal (cruzando líneas estatales, sin restricción) debe tener al menos qué edad?","options":["18 años","19 años","21 años","25 años"],"explanation":"Los conductores de 18 a 20 años están limitados al comercio intraestatal de Kentucky (restricción 'K'); un conductor debe tener 21 años para operar sin esa restricción en el comercio interestatal. Fuente: Manual CDL de Kentucky (KYTC, marzo de 2025), sección de edad intraestatal."},"26":{"q":"Después de que se emite un permiso de instrucción CDL (CLP) de Kentucky, ¿cuánto tiempo debe el solicitante conservar el permiso antes de que se pueda administrar un examen de habilidades?","options":["30 días","10 días","60 días","14 días"],"explanation":"El permiso debe conservarse durante 14 días antes de administrar un examen de habilidades, en concordancia con la regla federal del CLP. Fuente: Manual CDL de Kentucky (KYTC, marzo de 2025), 'Cómo Solicitar una CDL.'"},"27":{"q":"¿Por cuánto tiempo es válido un permiso de instrucción CDL (CLP) de Kentucky?","options":["6 meses","12 meses","30 días","180 días renovable indefinidamente"],"explanation":"Un permiso de instrucción CDL de Kentucky es válido por seis (6) meses. Solo puede renovarse una vez antes de que el solicitante deba volver a presentar la solicitud. Fuente: Manual CDL de Kentucky (KYTC, marzo de 2025), 'Cómo Solicitar una CDL' y sección de ELDT."},"28":{"q":"¿Cuántas veces se puede renovar un permiso de instrucción CDL de Kentucky antes de que el solicitante deba volver a presentar la solicitud (y pagar todas las tarifas y repetir los exámenes escritos)?","options":["Dos veces","No se puede renovar","Una vez","Veces ilimitadas"],"explanation":"Un permiso CDL de Kentucky solo puede renovarse una vez; si no se aprueba el examen de habilidades de manejo antes de que venza el permiso renovado, el solicitante debe volver a presentar la solicitud con todas las tarifas y exámenes escritos. Fuente: Manual CDL de Kentucky (KYTC, marzo de 2025), 'Capacitación de Conductores de Nivel Inicial (ELDT).'"},"29":{"q":"¿Qué endoso se requiere en una CDL de Kentucky para conducir un vehículo diseñado para transportar pasajeros, como un autobús de tránsito o de alquiler?","options":["S (Autobús Escolar)","N (Cisterna)","T (Dobles/Triples)","P (Pasajeros)"],"explanation":"El endoso P (Pasajeros) se requiere para transportar pasajeros; agregarlo requiere un examen de habilidades completo en un vehículo de pasajeros de la clase que se solicita. Fuente: Manual CDL de Kentucky (KYTC, marzo de 2025), 'Endosos' y 'Cómo agregar un endoso de Pasajeros.'"},"30":{"q":"Para conducir un autobús escolar en Kentucky, un titular de CDL debe obtener el endoso S (Autobús Escolar) además de cuál otro endoso?","options":["P (Pasajeros)","N (Cisterna)","H (HazMat)","T (Dobles/Triples)"],"explanation":"Los conductores de autobús escolar deben tener un endoso de Autobús Escolar (S) además de un endoso de Pasajeros (P), y deben aprobar un examen de conocimientos más las tres partes del examen de habilidades en la clase de autobús escolar que vayan a conducir. Fuente: Manual CDL de Kentucky (KYTC, marzo de 2025), sección de endoso de autobús escolar."},"31":{"q":"En los exámenes de conocimientos de la CDL de Kentucky, ¿cuántas preguntas contiene el examen del endoso de Materiales Peligrosos (H)?","options":["20 preguntas","30 preguntas","50 preguntas","25 preguntas"],"explanation":"El examen de conocimientos del endoso HazMat de Kentucky tiene 30 preguntas, mientras que los exámenes de los endosos de Dobles/Triples, Cisterna, Pasajeros y Autobús Escolar tienen 20 cada uno. Fuente: Manual CDL de Kentucky (KYTC, marzo de 2025), 'Se requieren endosos para los siguientes vehículos.'"},"32":{"q":"Antes de que se emita o renueve un endoso de Materiales Peligrosos (H) de Kentucky, un solicitante debe completar la toma de huellas dactilares y una verificación de antecedentes de seguridad procesada por el FBI y cuál agencia federal?","options":["Administración Federal de Seguridad de Autotransportes (FMCSA)","Guardia Costera del Departamento de Seguridad Nacional","Administración Federal de Carreteras (FHWA)","Administración de Seguridad en el Transporte (TSA)"],"explanation":"A los solicitantes de HazMat se les toman las huellas dactilares y la solicitud se envía al FBI y a la Administración de Seguridad en el Transporte (TSA) para una evaluación de amenazas de seguridad antes del examen. Una tarjeta TWIC puede servir como prueba de la evaluación. Fuente: Manual CDL de Kentucky (KYTC, marzo de 2025), sección de endoso HazMat."},"33":{"q":"¿Qué endoso de CDL de Kentucky se requiere para arrastrar remolques dobles o triples?","options":["T","N","H","X"],"explanation":"El endoso T (Dobles/Triples) se requiere para arrastrar remolques dobles o triples y requiere aprobar un examen de conocimientos de 20 preguntas. Fuente: Manual CDL de Kentucky (KYTC, marzo de 2025), 'Endosos.'"},"34":{"q":"¿Qué endoso necesita un conductor de CDL de Kentucky para transportar líquidos o gases en un vehículo cisterna a granel (un tanque)?","options":["T (Dobles/Triples)","N (Cisterna)","P (Pasajeros)","H (HazMat)"],"explanation":"El endoso N (Cisterna) se requiere para operar un vehículo cisterna que transporta carga a granel líquida o gaseosa, y requiere un examen de conocimientos de 20 preguntas. Fuente: Manual CDL de Kentucky (KYTC, marzo de 2025), 'Endosos.'"},"35":{"q":"A partir del 7 de febrero de 2022, la Capacitación Federal de Conductores de Nivel Inicial (ELDT) debe completarse en Kentucky antes de obtener una CDL Clase A o B por primera vez, y la capacitación debe provenir de un proveedor listado dónde?","options":["La lista de exámenes de la Policía Estatal de Kentucky","Cualquier lista de Oficina Regional de la KYTC","El Registro de Proveedores de Capacitación de la FMCSA","El centro de intercambio CDLIS"],"explanation":"La ELDT bajo 49 CFR parte 380 debe completarse antes de una CDL Clase A/B por primera vez, una mejora de categoría, o un primer endoso H, P o S, usando un proveedor listado en el Registro de Proveedores de Capacitación de la FMCSA. Fuente: Manual CDL de Kentucky (KYTC, marzo de 2025), 'Capacitación de Conductores de Nivel Inicial (ELDT).'"},"36":{"q":"¿Para cuál de las siguientes opciones Kentucky NO requiere la Capacitación de Conductores de Nivel Inicial (ELDT) antes de agregarla por primera vez?","options":["Endoso H (HazMat)","Endoso N (Cisterna)","Endoso P (Pasajeros)","Endoso S (Autobús Escolar)"],"explanation":"La ELDT se requiere para una CDL Clase A/B por primera vez, una mejora de categoría, y un primer endoso H, P o S; el endoso de Cisterna (N) no está en la lista de ELDT. Fuente: Manual CDL de Kentucky (KYTC, marzo de 2025), 'Capacitación de Conductores de Nivel Inicial (ELDT)'; 49 CFR parte 380."},"37":{"q":"¿Qué categoría de autocertificación médica debe elegir un solicitante de CDL de Kentucky si opera o espera operar solo dentro de Kentucky (intraestatal) y NO está exento de los requisitos médicos?","options":["Intraestatal Exento (EA)","Interestatal No Exento (NI)","Interestatal Exento (EI)","Intraestatal No Exento (NA)"],"explanation":"Un conductor que opera solo en Kentucky y que debe estar médicamente certificado selecciona Intraestatal No Exento (NA). La casilla Intraestatal Exento (EA) no se usa en Kentucky porque todos los titulares de CDL de KY deben estar médicamente certificados. Fuente: formulario de Autocertificación de Licencia de Conducir Comercial de la KYTC (TC 94-169); 601 KAR 1:005."},"38":{"q":"En el formulario de autocertificación de CDL de Kentucky, ¿qué categoría de certificación médica NO está disponible y nunca debe seleccionarse porque todos los titulares de CDL de Kentucky deben estar médicamente certificados?","options":["Intraestatal Exento (EA)","Interestatal No Exento (NI)","Interestatal Exento (EI)","Intraestatal No Exento (NA)"],"explanation":"Kentucky no permite la categoría Intraestatal Exento (EA); todo titular de CDL de KY debe estar médicamente certificado, por lo que EA nunca debe marcarse. Las otras tres (NI, EI, NA) son opciones válidas. Fuente: formulario de Autocertificación de Licencia de Conducir Comercial de la KYTC (TC 94-169); 601 KAR 1:005."},"39":{"q":"En una CDL de Kentucky, ¿qué indica el código de restricción 'K'?","options":["Ningún CMV equipado con frenos de aire","Ninguna carga en un vehículo cisterna","Operación intraestatal (solo Kentucky)","Ningún pasajero en un autobús CMV"],"explanation":"La restricción 'K' limita al titular al comercio intraestatal dentro de Kentucky y aplica a conductores menores de 21 años y a otros restringidos a la conducción intraestatal. (Como referencia, X = sin carga en cisterna, L = sin frenos de aire, P = sin pasajeros en un autobús CMV.) Fuente: Manual CDL de Kentucky (KYTC, marzo de 2025), 'Restricciones.'"},"40":{"q":"Al operar un vehículo motorizado comercial (CMV) en Kentucky, ¿cuál es la concentración de alcohol en la sangre (BAC) que constituye el umbral legal en el que se considera que un conductor está conduciendo bajo los efectos del alcohol y queda descalificado?","options":["0.04 o más","0.08 o más","0.02 o más","0.10 o más"],"explanation":"Kentucky establece el límite de BAC para CMV en 0.04 o más, la mitad del límite de 0.08 para conductores regulares. Operar un CMV con un nivel igual o superior a 0.04 es una infracción grave que activa la descalificación. Fuente: Manual CDL de Kentucky (KYTC), KRS 281A.190; 49 CFR 383.51."},"41":{"q":"En Kentucky, una primera condena por una infracción grave (como un DUI en un CMV) resulta en la descalificación de la CDL por cuánto tiempo?","options":["1 año","60 días","6 meses","3 años"],"explanation":"Una primera infracción grave descalifica al conductor por 1 año (3 años si transportaba materiales peligrosos con rótulos en ese momento). Fuente: Manual CDL de Kentucky (KYTC), KRS 281A.190; 49 CFR 383.51 Tabla 1."},"42":{"q":"Si un titular de CDL de Kentucky comete una primera infracción grave mientras transporta materiales peligrosos con rótulos (placards), ¿a cuánto aumenta el período de descalificación?","options":["3 años","1 año","5 años","2 años"],"explanation":"Una primera infracción grave mientras se transportan materiales peligrosos con rótulos eleva la descalificación de 1 año a 3 años. Fuente: Manual CDL de Kentucky (KYTC), KRS 281A.190; 49 CFR 383.51 Tabla 1."},"43":{"q":"Bajo la ley de consentimiento implícito de Kentucky, al operar un vehículo motorizado comercial, ¿se considera que un conductor ha dado su consentimiento para una prueba química de cuáles sustancias?","options":["Sangre, aliento u orina para detectar alcohol o drogas","Solo aliento para detectar alcohol","Solo sangre para detectar drogas","Solo orina para detectar sustancias controladas"],"explanation":"La ley de consentimiento implícito de Kentucky considera que todo operador de CMV ha dado su consentimiento para una prueba de sangre, aliento u orina para detectar alcohol o sustancias controladas cuando un oficial tiene causa razonable. Fuente: Manual CDL de Kentucky (KYTC), KRS 281A.150/281A.190."},"44":{"q":"En Kentucky, ¿qué le ocurre a un titular de CDL que se niega a someterse a una prueba química requerida de aliento, sangre u orina?","options":["Se trata como una infracción grave: descalificación de al menos 1 año","Solo una advertencia en la primera negativa","Una descalificación de 60 días","Una suspensión de 30 días y una multa"],"explanation":"Negarse a la prueba es en sí mismo una infracción grave, que conlleva la misma descalificación que una condena por DUI: al menos 1 año (3 años si transporta HazMat con rótulos). Fuente: Manual CDL de Kentucky (KYTC), KRS 281A.190; 49 CFR 383.51 Tabla 1."},"45":{"q":"Un titular de CDL de Kentucky es condenado por una segunda infracción grave en un incidente separado. ¿Cuál es el período de descalificación?","options":["Descalificación de por vida","10 años","5 años","3 años"],"explanation":"Una segunda infracción grave en un incidente separado resulta en la descalificación de por vida de la CDL. Fuente: Manual CDL de Kentucky (KYTC), KRS 281A.190; 49 CFR 383.51 Tabla 1."},"46":{"q":"¿Después de cuántos años puede un conductor de Kentucky descalificado de por vida ser potencialmente elegible para la reinstauración, siempre que se cumplan los requisitos de elegibilidad, como completar un programa de rehabilitación aprobado?","options":["10 años","5 años","7 años","15 años"],"explanation":"Un estado puede reinstaurar a un conductor descalificado de por vida después de un mínimo de 10 años si la persona completa un programa de rehabilitación aprobado; algunos delitos graves de drogas/tráfico nunca son elegibles. Fuente: Manual CDL de Kentucky (KYTC); 49 CFR 383.51."},"47":{"q":"Incluso por debajo del nivel descalificante de 0.04, ¿qué le ocurre a un conductor de CMV de Kentucky al que se le detecta cualquier cantidad perceptible de alcohol en su organismo?","options":["Es puesto fuera de servicio por 24 horas","Es descalificado de inmediato por 1 año","Es multado con $100 sin ninguna otra acción","Recibe una descalificación de 60 días"],"explanation":"Un conductor con cualquier cantidad medible de alcohol por debajo de 0.04 es puesto fuera de servicio por 24 horas. Alcanzar 0.04 o más es una infracción grave. Fuente: Manual CDL de Kentucky (KYTC); 49 CFR 392.5."},"48":{"q":"En Kentucky, la condena por dos infracciones de tránsito graves en un CMV dentro de un período de 3 años (incidentes separados) resulta en una descalificación por cuánto tiempo?","options":["60 días","30 días","120 días","90 días"],"explanation":"Dos infracciones de tránsito graves dentro de 3 años (incidentes separados) resultan en una descalificación de 60 días. Fuente: Manual CDL de Kentucky (KYTC), KRS 281A.190; 49 CFR 383.51 Tabla 2."},"49":{"q":"En Kentucky, la condena por tres infracciones de tránsito graves en un CMV dentro de un período de 3 años (incidentes separados) resulta en una descalificación por cuánto tiempo?","options":["120 días","60 días","180 días","1 año"],"explanation":"Tres infracciones de tránsito graves dentro de 3 años (incidentes separados) resultan en una descalificación de 120 días, cumplida de forma consecutiva a otras descalificaciones. Fuente: Manual CDL de Kentucky (KYTC), KRS 281A.190; 49 CFR 383.51 Tabla 2."},"50":{"q":"¿Cuál de las siguientes se clasifica como una infracción de tránsito grave para un titular de CDL de Kentucky?","options":["Exceder la velocidad en 15 mph o más por encima del límite señalizado","Exceder la velocidad en 5 mph por encima del límite señalizado","Una sola infracción de estacionamiento","Conducir con una calcomanía de registro vencida"],"explanation":"El exceso de velocidad excesivo (15 mph o más por encima del límite) es una infracción de tránsito grave, junto con la conducción imprudente, los cambios de carril indebidos, seguir demasiado de cerca, enviar mensajes de texto y el uso del teléfono de mano. Fuente: Manual CDL de Kentucky (KYTC), KRS 281A.190; 49 CFR 383.51 Tabla 2."},"51":{"q":"Para fines de la CDL de Kentucky, ¿cómo se trata enviar mensajes de texto mientras se conduce un CMV al contabilizarlo para la descalificación?","options":["Como una infracción de tránsito grave","Como una infracción grave","Como una infracción de fuera de servicio","No conlleva ninguna consecuencia para la CDL"],"explanation":"Enviar mensajes de texto mientras se conduce un CMV es una infracción de tránsito grave; dos dentro de 3 años conllevan una descalificación de 60 días y tres conllevan 120 días. Fuente: Manual CDL de Kentucky (KYTC); 49 CFR 383.51 y 49 CFR 392.80."},"52":{"q":"El uso de un teléfono móvil de mano mientras se conduce un CMV en Kentucky está prohibido y se contabiliza para la descalificación de la CDL como qué tipo de infracción?","options":["Una infracción de tránsito grave","Una infracción grave","Una infracción de cruce ferroviario","Una violación de una orden de fuera de servicio"],"explanation":"El uso del teléfono de mano mientras se conduce un CMV es una infracción de tránsito grave; dos dentro de 3 años conllevan una descalificación de 60 días, tres conllevan 120 días. Fuente: Manual CDL de Kentucky (KYTC); 49 CFR 383.51 y 49 CFR 392.82."},"53":{"q":"Una primera condena por una infracción de cruce a nivel ferrocarril-carretera en un CMV resulta en una descalificación de la CDL de Kentucky de al menos cuánto tiempo?","options":["60 días","30 días","120 días","1 año"],"explanation":"Una primera infracción de cruce a nivel ferroviario conlleva una descalificación de no menos de 60 días. Fuente: Manual CDL de Kentucky (KYTC), KRS 281A.190; 49 CFR 383.51 Tabla 3."},"54":{"q":"Una segunda infracción de cruce a nivel ferrocarril-carretera dentro de un período de 3 años resulta en una descalificación de la CDL de Kentucky de al menos cuánto tiempo?","options":["120 días","60 días","180 días","1 año"],"explanation":"Una segunda infracción de cruce a nivel dentro de 3 años conlleva una descalificación de no menos de 120 días. Fuente: Manual CDL de Kentucky (KYTC), KRS 281A.190; 49 CFR 383.51 Tabla 3."},"55":{"q":"Una tercera o subsiguiente infracción de cruce a nivel ferrocarril-carretera dentro de un período de 3 años resulta en una descalificación de la CDL de Kentucky de al menos cuánto tiempo?","options":["1 año","120 días","180 días","60 días"],"explanation":"Una tercera o subsiguiente infracción de cruce a nivel dentro de 3 años conlleva una descalificación de no menos de 1 año. Fuente: Manual CDL de Kentucky (KYTC), KRS 281A.190; 49 CFR 383.51 Tabla 3."},"56":{"q":"¿Cuál de las siguientes es una infracción de cruce a nivel ferroviario que puede descalificar a un titular de CDL de Kentucky?","options":["Entrar a un cruce sin espacio suficiente para librarlo por completo","Detenerse 50 pies antes de las vías para verificar si hay trenes","Reducir la velocidad y verificar que las vías estén despejadas","Ceder el paso a un tren que tiene el derecho de paso"],"explanation":"Cruzar sin espacio suficiente para librar las vías es una infracción, al igual que no reducir la velocidad/verificar, no detenerse cuando se requiere y no tener suficiente espacio libre en los bajos del vehículo. Fuente: Manual CDL de Kentucky (KYTC); 49 CFR 383.51 Tabla 3."},"57":{"q":"Un titular de CDL de Kentucky que viola una orden de fuera de servicio por primera vez (sin HazMat, sin pasajeros) es descalificado por un período de no menos de cuánto tiempo?","options":["180 días","60 días","90 días","1 año"],"explanation":"Una primera violación de una orden de fuera de servicio conlleva una descalificación de no menos de 180 días (hasta 1 año). Fuente: Manual CDL de Kentucky (KYTC), KRS 281A.190; 49 CFR 383.51 Tabla 4."},"58":{"q":"Por una segunda violación de una orden de fuera de servicio dentro de un período de 10 años, un titular de CDL de Kentucky es descalificado por no menos de cuánto tiempo?","options":["2 años","180 días","1 año","3 años"],"explanation":"Una segunda violación de una orden de fuera de servicio dentro de 10 años conlleva una descalificación de no menos de 2 años (hasta 5 años). Fuente: Manual CDL de Kentucky (KYTC), KRS 281A.190; 49 CFR 383.51 Tabla 4."},"59":{"q":"Una tercera o subsiguiente violación de una orden de fuera de servicio dentro de un período de 10 años resulta en una descalificación de la CDL de Kentucky de no menos de cuánto tiempo?","options":["3 años","2 años","1 año","5 años"],"explanation":"Una tercera o subsiguiente violación de una orden de fuera de servicio dentro de 10 años conlleva una descalificación de no menos de 3 años (hasta 5 años). Fuente: Manual CDL de Kentucky (KYTC), KRS 281A.190; 49 CFR 383.51 Tabla 4."},"60":{"q":"Según la ley 'Reduzca la velocidad, cámbiese de carril' (Slow Down, Move Over) de Kentucky, cuando un conductor de CDL se acerca a un vehículo de emergencia o de seguridad pública detenido con luces intermitentes encendidas en una autopista de varios carriles, ¿cuál es la PRIMERA obligación del conductor si puede hacerse de manera segura?","options":["Continuar a la velocidad indicada permaneciendo en el mismo carril","Detenerse por completo hasta que el vehículo de emergencia se retire","Desocupar el carril más cercano al vehículo detenido cambiándose un carril","Tocar la bocina para alertar a los socorristas de que el camión se aproxima"],"explanation":"La ley 'Move Over' de Kentucky (KRS 189.930) exige que un conductor en una vía con dos o más carriles en la misma dirección desocupe el carril más cercano a un vehículo de emergencia o de seguridad pública detenido con luces intermitentes cuando sea seguro hacerlo. Fuente: KRS 189.930; Manual de CDL de Kentucky."},"61":{"q":"En una carretera de dos carriles en Kentucky donde un conductor no puede cambiarse de carril de manera segura para un vehículo de emergencia detenido con luces intermitentes, ¿qué exige en su lugar la ley 'Move Over' que haga el conductor?","options":["Reducir la velocidad a un nivel seguro para la vía, el clima y las condiciones del tránsito","Detenerse por completo 500 feet antes del vehículo de emergencia","Activar las luces intermitentes de cuatro vías y mantener el límite de velocidad","Orillarse al acotamiento y esperar a que le hagan señas para pasar"],"explanation":"Según la KRS 189.930, si cambiar de carril es imposible o inseguro, el conductor debe reducir la velocidad a un nivel seguro para las condiciones existentes de la vía, el clima y el tránsito, y avanzar con precaución. Fuente: KRS 189.930."},"62":{"q":"Kentucky amplió su ley 'Move Over' en julio de 2024. Además de la policía, los bomberos y las ambulancias, ¿para cuál de los siguientes la ley ampliada ahora también exige que los conductores se cambien de carril o reduzcan la velocidad?","options":["Cualquier vehículo detenido que muestre luces de emergencia o señales de advertencia, incluidos vehículos averiados y grúas","Solo patrullas policiales debidamente identificadas","Solo vehículos que estén bloqueando activamente un carril de circulación","Solo vehículos propiedad del Kentucky Transportation Cabinet"],"explanation":"La ampliación de julio de 2024 de la KRS 189.930 extendió la protección a cualquier vehículo detenido que muestre luces intermitentes, luces de emergencia o dispositivos de advertencia, como grúas/remolques y automovilistas con vehículos averiados, no solo a los socorristas tradicionales. Fuente: KRS 189.930 (enmienda de 2024)."},"63":{"q":"Un conductor de CDL en Kentucky transporta una carga de materiales peligrosos con carteles (placards) y se acerca a un cruce de ferrocarril. ¿Dentro de qué distancia del riel más cercano debe detenerse el conductor?","options":["No menos de 5 feet y no más de 25 feet","No menos de 15 feet y no más de 50 feet","No menos de 25 feet y no más de 75 feet","No menos de 50 feet y no más de 100 feet"],"explanation":"Un conductor de un vehículo con carteles de materiales peligrosos (hazmat) debe detenerse dentro de los 50 feet, pero no más cerca de 15 feet, del riel más cercano antes de cruzar (la regla de '15 a 50 feet'). Fuente: 49 CFR 392.10, adoptada en Kentucky; Manual de CDL de Kentucky."},"64":{"q":"¿Cuál de estos vehículos comerciales DEBE detenerse en cada cruce de ferrocarril según las reglas que se enseñan en el Manual de CDL de Kentucky?","options":["Un tractocamión con remolque de plataforma vacío","Un autobús que transporta pasajeros","Un camión de caja que transporta carga general","Un camión de volteo que transporta grava"],"explanation":"Los autobuses que transportan pasajeros y los vehículos con carteles de materiales peligrosos deben detenerse en los cruces de ferrocarril, deteniéndose dentro de los 15 a 50 feet del riel más cercano. Los camiones de carga general no están obligados a detenerse a menos que las señales lo exijan. Fuente: 49 CFR 392.10; Manual de CDL de Kentucky."},"65":{"q":"Según la ley de autobuses escolares de Kentucky, en una autopista de cuatro carriles un autobús escolar se detiene con las luces rojas intermitentes encendidas y el brazo de alto extendido. ¿Cuáles conductores NO están obligados a detenerse?","options":["Los conductores en el carril contiguo al autobús que circulan en la misma dirección","Los conductores directamente detrás del autobús en el mismo carril","Todos los conductores deben detenerse sin importar la dirección o el número de carriles","Los conductores que se aproximan en sentido contrario en la autopista de cuatro o más carriles"],"explanation":"Según la KRS 189.370, en una autopista de cuatro o más carriles, los vehículos que se aproximan en sentido contrario a un autobús escolar detenido no están obligados a detenerse. El tránsito del lado del autobús sí debe detenerse. Fuente: KRS 189.370."},"66":{"q":"En una autopista común de dos carriles en Kentucky, un autobús escolar se detiene con las luces rojas intermitentes encendidas y el brazo de alto extendido para recoger niños. ¿Qué debe hacer el tránsito que se aproxima en sentido contrario?","options":["Reducir a 25 mph pero puede seguir avanzando al pasar junto al autobús","Detenerse y permanecer detenido hasta que el autobús reanude la marcha","Avanzar normalmente porque el autobús está al otro lado de la línea central","Detenerse solo si se ven niños cruzando la vía"],"explanation":"En una vía de dos carriles, la KRS 189.370 exige que los conductores de AMBAS direcciones se detengan ante un autobús escolar que recoge o deja niños con sus señales activadas, y que no avancen hasta que el autobús reanude la marcha. La excepción para el sentido contrario solo aplica a autopistas de cuatro o más carriles. Fuente: KRS 189.370."},"67":{"q":"El requisito de detención ante un autobús escolar en Kentucky (y su excepción para el sentido contrario) se basa en ¿qué característica específica de la vía?","options":["El número de carriles de la autopista (cuatro o más)","Si el límite de velocidad es de 55 mph o más","Si la autopista es una vía estatal designada (parkway)","Si una barrera física de concreto separa las direcciones"],"explanation":"La KRS 189.370 vincula la excepción para el sentido contrario específicamente a una autopista 'de cuatro (4) o más carriles', y no a la presencia de una barrera en el camellón ni a un umbral de velocidad. Fuente: KRS 189.370."},"68":{"q":"La ley de Kentucky restringe a ciertos vehículos grandes el uso del carril del extremo izquierdo. En una autopista con tres o más carriles que circulan en la misma dirección, ¿cuáles vehículos tienen prohibido el carril del extremo izquierdo salvo al rebasar, ingresar o salir?","options":["Motocicletas y ciclomotores","Vehículos recreativos y casas rodantes","Tractocamiones, remolques y semirremolques","Todos los automóviles de pasajeros y camionetas pickup"],"explanation":"La KRS 189.340 prohíbe que un tractocamión, remolque o semirremolque circule en el carril del extremo izquierdo de una autopista con tres o más carriles en la misma dirección, salvo al rebasar, ingresar o salir de la autopista, ceder el paso al tránsito que ingresa, o cuando los demás carriles sean inseguros. Fuente: KRS 189.340."},"69":{"q":"Según la regla de Kentucky sobre el carril izquierdo para camiones, ¿cuál de las siguientes es una razón válida para que un semirremolque circule legalmente en el carril del extremo izquierdo de una interestatal de tres carriles?","options":["Mantener una velocidad de crucero constante para ahorrar combustible","Mantenerse alejado de los vehículos que se incorporan desde las rampas de acceso durante todo el viaje","Rebasar a un vehículo más lento y luego regresar a la derecha tan pronto como sea posible","Circular un poco por debajo del límite de velocidad para cuidar los frenos"],"explanation":"La KRS 189.340 permite que un tractocamión/remolque/semirremolque use el carril del extremo izquierdo solo por motivos limitados, como rebasar (y luego regresar a la derecha tan pronto como sea posible), ingresar o salir de la autopista, ceder el paso al tránsito que ingresa, o cuando los carriles derecho/central sean inseguros. Fuente: KRS 189.340."},"70":{"q":"¿Cuál es el límite máximo de velocidad para camiones en los tramos rurales de las autopistas interestatales de Kentucky, como la I-64, la I-65 y la I-75?","options":["70 mph","65 mph","60 mph","75 mph"],"explanation":"Kentucky señaliza un máximo de 70 mph en la mayoría de los tramos interestatales rurales; esto aplica a los camiones a menos que se señalice un límite menor. Los tramos urbanos (por ejemplo, alrededor de Louisville y Lexington) suelen ser de 65 mph. Fuente: KRS 189.390; límites señalizados por KYTC."},"71":{"q":"A través de las zonas urbanas cercanas a Louisville y Lexington, el límite de velocidad en la interestatal que un conductor de CDL debe esperar es, con mayor frecuencia:","options":["70 mph","65 mph","45 mph","55 mph"],"explanation":"Si bien las interestatales rurales de Kentucky generalmente están señalizadas a 70 mph, los tramos interestatales urbanos alrededor de áreas metropolitanas como Louisville y Lexington suelen estar señalizados a 65 mph. Los conductores siempre deben obedecer el límite señalizado. Fuente: KRS 189.390; límites señalizados por KYTC."},"72":{"q":"El camión de un conductor de CDL se avería en el acotamiento de una autopista de dos carriles y doble sentido en Kentucky durante el día. Después de colocar los dispositivos de advertencia requeridos, ¿dónde deben colocarse los tres triángulos reflectantes?","options":["100 feet detrás, 100 feet adelante y uno junto a la cabina","10 feet detrás, 100 feet detrás y 100 feet adelante del vehículo","25 feet detrás, 200 feet detrás y 200 feet adelante del vehículo","10 feet detrás, 50 feet detrás y 50 feet adelante del vehículo"],"explanation":"En una vía de dos carriles y doble sentido, coloque un triángulo dentro de los 10 feet de la parte trasera, uno aproximadamente 100 feet detrás y uno aproximadamente 100 feet delante del vehículo. Fuente: 49 CFR 392.22, adoptada en Kentucky; Manual de CDL de Kentucky."},"73":{"q":"Cuando un vehículo comercial está detenido en una autopista de un solo sentido o dividida en Kentucky, ¿dónde se colocan los tres dispositivos de advertencia con respecto al tránsito que se aproxima?","options":["100 feet detrás y 100 feet adelante, más uno en la cabina","10 feet, 100 feet y 200 feet hacia el tránsito que se aproxima","200 feet, 200 feet y 500 feet hacia el tránsito que se aproxima","10 feet, 50 feet y 100 feet hacia el tránsito que se aproxima"],"explanation":"En una autopista de un solo sentido o dividida, coloque los dispositivos de advertencia a 10 feet, 100 feet y 200 feet hacia el tránsito que se aproxima, en el centro del carril o acotamiento ocupado por el vehículo. Fuente: 49 CFR 392.22; Manual de CDL de Kentucky."},"74":{"q":"Después de detener un vehículo comercial averiado en una vía de Kentucky, ¿dentro de cuántos minutos debe el conductor colocar los dispositivos de advertencia de emergencia requeridos?","options":["Dentro de 10 minutos","Dentro de 5 minutos","Dentro de 30 minutos","Dentro de 15 minutos"],"explanation":"El conductor debe colocar los tres dispositivos de advertencia requeridos dentro de los 10 minutos siguientes a detenerse. Fuente: 49 CFR 392.22, adoptada en Kentucky; Manual de CDL de Kentucky."},"75":{"q":"En una bajada larga como la de Pine Mountain en Kentucky (U.S. 119), ¿cuál es la técnica de frenado correcta que se enseña en el Manual de CDL de Kentucky?","options":["Aplicar el freno de estacionamiento de forma intermitente para reducir la velocidad del vehículo","Poner el vehículo en neutral para dejar enfriar el motor y rozar los frenos ligeramente","Seleccionar una marcha baja antes del descenso y usar un frenado ligero, constante o intermitente (snub)","Mantener la marcha más alta posible y bombear los frenos continuamente"],"explanation":"Los conductores deben elegir la marcha baja adecuada antes de comenzar a bajar una pendiente y depender principalmente del freno de motor, usando los frenos de servicio en aplicaciones ligeras e intermitentes (snub). Rozar los frenos provoca sobrecalentamiento y pérdida de eficacia del frenado (brake fade). Fuente: Manual de CDL de Kentucky (Control de la velocidad / Conducción en montaña)."},"76":{"q":"Sin un permiso de sobredimensión en Kentucky, ¿cuál es el ancho máximo legal permitido para un vehículo comercial y su carga en las autopistas designadas?","options":["10 feet 0 inches","9 feet 6 inches","8 feet 0 inches","8 feet 6 inches"],"explanation":"El ancho máximo legal de vehículo/carga en Kentucky, en interestatales y autopistas designadas, es de 8 feet 6 inches (102 inches); cualquier cosa más ancha requiere un permiso de sobredimensión de KYTC. Fuente: Capítulo 189 de los KRS; Permisos de Sobrepeso/Sobredimensión de KYTC."},"77":{"q":"Una carga en Kentucky mide 14 feet de alto. Sin un permiso, la altura máxima legal es de 13 feet 6 inches. ¿Qué debe obtener el transportista antes de mover esta carga?","options":["Permiso únicamente del alguacil (sheriff) del condado local","Nada, porque los límites de altura son solo orientativos en Kentucky","Un permiso de sobredimensión del Kentucky Transportation Cabinet","Únicamente un endoso de materiales peligrosos"],"explanation":"La altura máxima legal en Kentucky es de 13 feet 6 inches; una carga de 14 feet excede ese límite y requiere un permiso de sobredimensión emitido a través de la KYTC Division of Motor Carriers antes de viajar. Fuente: Capítulo 189 de los KRS; Permisos de Sobrepeso/Sobredimensión de KYTC."},"78":{"q":"Por lo general, Kentucky NO emitirá un permiso de sobredimensión/sobrepeso para ¿qué tipo de carga?","options":["Una sola pieza de maquinaria industrial que no puede desarmarse","Una carga que es razonablemente divisible y podría reconfigurarse para cumplir con los límites legales","Un transformador grande que excede el peso legal","Una sección prefabricada de edificio que excede el ancho legal"],"explanation":"Kentucky emite permisos OS/OW solo para cargas no divisibles; no autorizará una carga que sea razonablemente divisible (una que pudiera desarmarse o reconfigurarse para cumplir con los límites legales), salvo bajo una autoridad estatutaria específica. Fuente: Permisos de Sobrepeso/Sobredimensión de KYTC; Capítulo 189 de los KRS."},"79":{"q":"¿Cuál agencia de Kentucky realmente emite la credencial de Licencia de Conducir Comercial (CDL) a los solicitantes calificados?","options":["La Division of Driver Licensing del Kentucky Transportation Cabinet","La Kentucky State Police","La Federal Motor Carrier Safety Administration","La oficina de fianzas del Circuit Court Clerk del condado"],"explanation":"En Kentucky, la credencial de CDL es emitida por el Kentucky Transportation Cabinet (KYTC), Division of Driver Licensing. Fuente: página de CDL de KYTC en drive.ky.gov; Manual de CDL de Kentucky 2025."},"80":{"q":"¿Quién administra los exámenes de conocimientos de la CDL y la prueba de habilidades de manejo en carretera para los solicitantes en Kentucky?","options":["La Kentucky State Police","El Circuit Court Clerk del condado","Únicamente las escuelas privadas de manejo de camiones de terceros","El FMCSA National Registry"],"explanation":"La Kentucky State Police (KSP) es la responsable exclusiva de administrar todos los exámenes de conocimientos y de habilidades de la CDL en Kentucky, mientras que KYTC emite la licencia. Fuente: Manual de CDL de Kentucky 2025; Driver Testing de la Kentucky State Police."},"81":{"q":"¿Por cuántos días es válido un Permiso de Aprendizaje Comercial (CLP) de Kentucky?","options":["180 days","60 days","365 days","90 days"],"explanation":"Un CLP de Kentucky es válido por un máximo de 180 days. Fuente: KRS 281A.120; Manual de CDL de Kentucky 2025."},"82":{"q":"Después de que se emite un CLP, ¿cuánto tiempo debe esperar un solicitante antes de presentar la prueba de habilidades de la CDL en Kentucky?","options":["Al menos 14 days","Al menos 30 days","Al menos 7 days","Al menos 60 days"],"explanation":"Un solicitante debe tener el CLP durante al menos 14 days antes de ser elegible para presentar la prueba de habilidades de la CDL. Este es un estándar federal aplicado en Kentucky. Fuente: Manual de CDL de Kentucky 2025; 49 CFR 383.25."},"83":{"q":"¿Por cuánto tiempo es válida una Licencia de Conducir Comercial de Kentucky antes de que deba renovarse?","options":["8 years","4 years","5 years","10 years"],"explanation":"Una credencial de CDL de Kentucky es válida por 8 years. Fuente: KRS 281A.170; KYTC drive.ky.gov."},"84":{"q":"¿Cuál formulario es el Certificado del Examinador Médico del DOT que un solicitante de CDL de Kentucky debe obtener de un examinador médico certificado?","options":["Formulario MCSA-5876","Formulario TC 94-169","Únicamente el Formulario MCSA-5875","Formulario DOT-391"],"explanation":"El Certificado del Examinador Médico es el Formulario MCSA-5876, completado por un Examinador Médico Certificado del National Registry; debe estar archivado para el titular de la CDL. (El TC 94-169 es el formulario aparte de autocertificación.) Fuente: información de KYTC para solicitantes por primera vez; FMCSA."},"85":{"q":"En la autocertificación de CDL de Kentucky, ¿entre cuántas categorías de tipo de manejo debe elegir un solicitante?","options":["Cuatro","Dos","Tres","Cinco"],"explanation":"La autocertificación (Formulario TC 94-169) tiene cuatro categorías: interestatal no exceptuado, interestatal exceptuado, intraestatal no exceptuado e intraestatal exceptuado. Fuente: Formulario TC 94-169 de KYTC; 49 CFR 383.71."},"86":{"q":"Un conductor de Kentucky que opera cruzando líneas estatales y debe cumplir con las normas federales de calificación física debe autocertificarse en ¿cuál categoría?","options":["Interestatal no exceptuado","Interestatal exceptuado","Intraestatal no exceptuado","Intraestatal exceptuado"],"explanation":"Los conductores en comercio interestatal sujetos a las normas federales de calificación física se certifican como interestatal no exceptuado, lo cual requiere tener archivado un Certificado del Examinador Médico vigente. Fuente: Formulario TC 94-169 de KYTC; 49 CFR 383.71."},"87":{"q":"Antes de que un solicitante de Clase A o Clase B por primera vez pueda presentar la prueba de habilidades de la CDL en Kentucky, ¿qué requisito de capacitación debe cumplir?","options":["Entry-Level Driver Training (ELDT) de un proveedor registrado","Un aprendizaje estatal de 160 horas patrocinado por KYTC","Un curso de manejo defensivo en el Circuit Court Clerk","Dos años de manejo intraestatal documentado"],"explanation":"Se requiere la capacitación federal Entry-Level Driver Training (ELDT) de un proveedor del FMCSA Training Provider Registry antes de presentar el examen de Clase A/B por primera vez (y antes del examen del primer endoso P, S o H). Fuente: Manual de CDL de Kentucky 2025; 49 CFR Parte 380."},"88":{"q":"¿Cuál de los siguientes endosos requiere completar la ELDT antes del examen, además de los solicitantes de Clase A y Clase B por primera vez?","options":["Materiales peligrosos (H), pasajeros (P) y autobús escolar (S)","Vehículo cisterna (N) y dobles/triples (T)","Únicamente el endoso de autobús escolar (S)","Ningún endoso requiere ELDT"],"explanation":"La ELDT se requiere para los solicitantes por primera vez de los endosos de materiales peligrosos (H), pasajeros (P) y autobús escolar (S), así como para la emisión inicial de Clase A/B y los ascensos de Clase B a A. Fuente: Manual de CDL de Kentucky 2025; 49 CFR Parte 380."},"89":{"q":"La prueba de habilidades de la CDL de Kentucky se administra en tres partes. ¿Cuál conjunto enumera correctamente esas tres partes?","options":["Inspección previaje, control básico del vehículo y manejo en carretera","Examen escrito de conocimientos, examen de la vista y manejo en carretera","Inspección previaje, examen escrito de frenos de aire y maniobras de reversa","Control básico del vehículo, examen escrito de hazmat y manejo en carretera"],"explanation":"La prueba de habilidades de la CDL consta de tres partes: la inspección previaje, las habilidades de control básico del vehículo y la prueba de manejo en carretera. Fuente: Manual de CDL de Kentucky 2025; 49 CFR 383.113."},"90":{"q":"¿En qué tipo de vehículo debe un solicitante de Kentucky presentar la prueba de habilidades de la CDL?","options":["La clase/tipo de vehículo que el solicitante pretende estar autorizado a manejar","Cualquier vehículo comercial que pese más de 10,001 pounds","Un automóvil de pasajeros estándar proporcionado por la estación de pruebas","Un vehículo de Clase C sin importar la clase de licencia que se busque"],"explanation":"Los solicitantes deben presentar la prueba de habilidades en un vehículo representativo de la clase y tipo para el cual buscan obtener la licencia. Fuente: Manual de CDL de Kentucky 2025; 49 CFR 383.71."},"91":{"q":"¿Qué documentos debe tener archivados un solicitante de CDL de Kentucky por primera vez antes de que se emita el permiso o la licencia?","options":["La solicitud de CDL, el formulario de autocertificación y un Certificado del Examinador Médico del DOT legible","Únicamente una tarjeta del Seguro Social y un resultado del examen de la vista","Una carta del empleador y un registro del vehículo","Un pasaporte y una suscripción al FMCSA Clearinghouse"],"explanation":"Antes de que se emita un CLP o una CDL, Kentucky requiere la solicitud de CDL, la autocertificación (TC 94-169) y una copia legible del Certificado del Examinador Médico del DOT, todo enviado a KYTC (a través de mycdl.ky.gov). Fuente: información de KYTC para solicitantes por primera vez; drive.ky.gov."},"92":{"q":"Si un CLP de Kentucky vence antes de que el solicitante apruebe la prueba de habilidades, ¿qué sucede generalmente?","options":["El solicitante debe volver a presentar los exámenes de conocimientos requeridos para obtener un nuevo CLP","El CLP se extiende automáticamente por otros 180 days","Las calificaciones de la prueba de habilidades se conservan por dos años","El solicitante puede presentar la prueba de habilidades dentro de un período de gracia de 30 days"],"explanation":"Kentucky no extiende el CLP de 180 days; si vence antes de aprobar la prueba de habilidades, el solicitante debe volver a presentar el/los examen(es) de conocimientos para que se le emita un nuevo CLP. Fuente: Manual de CDL de Kentucky 2025; KRS 281A.120."},"93":{"q":"¿Cuál es la calificación mínima aprobatoria en el examen de conocimientos generales de la CDL de Kentucky?","options":["80 percent de respuestas correctas","70 percent de respuestas correctas","75 percent de respuestas correctas","90 percent de respuestas correctas"],"explanation":"Un solicitante debe obtener al menos 80 percent para aprobar cada examen de conocimientos de la CDL, el estándar federal aplicado en Kentucky. Fuente: Manual de CDL de Kentucky 2025; 49 CFR 383.135."},"94":{"q":"¿Cuál es la edad mínima para que se emita una CDL de Kentucky limitada al comercio intraestatal (dentro de Kentucky)?","options":["18 years old","21 years old","19 years old","16 years old"],"explanation":"Una persona debe tener al menos 18 años para tener una CDL para manejo intraestatal en Kentucky; se requieren 21 años para el manejo interestatal y para la operación de hazmat/autobús escolar. Fuente: KRS 281A; Manual de CDL de Kentucky 2025."},"95":{"q":"¿Cuál es la edad mínima requerida para operar un vehículo motorizado comercial en comercio interestatal con una CDL de Kentucky?","options":["21 years old","18 years old","19 years old","25 years old"],"explanation":"Los conductores deben tener al menos 21 años para operar en comercio interestatal; los de 18 a 20 años reciben una restricción intraestatal (solo Kentucky). Fuente: KRS 281A; Manual de CDL de Kentucky 2025; 49 CFR 391.11."},"96":{"q":"Cuando un titular de CDL de Kentucky se hace un nuevo examen médico del DOT, ¿qué debe hacer el conductor para mantener la CDL en estado 'certificado'?","options":["Enviar el Certificado del Examinador Médico actualizado a KYTC a través de mycdl.ky.gov para que el historial de manejo se mantenga al día","Conservar el certificado únicamente en la cabina y mostrarlo a la policía si se lo piden","Enviar el certificado por correo al FMCSA National Registry en lugar de al estado","Volver a presentar el examen de conocimientos para revalidar el certificado"],"explanation":"Para evitar ser degradado a estado 'no certificado', el conductor debe enviar cada nuevo Certificado del Examinador Médico a KYTC, normalmente a través del portal mycdl.ky.gov, para que se registre en el historial de manejo del CDLIS. Fuente: información de KYTC para solicitantes por primera vez; 49 CFR 383.71/383.73."},"97":{"q":"¿Cuál afirmación sobre la renovación de una CDL de Kentucky es correcta respecto al proceso por correo o en línea?","options":["Por lo general, una CDL no puede renovarse por correo y requiere una renovación en persona","Una CDL se renueva automáticamente y se envía por correo sin ninguna solicitud","Una CDL siempre puede renovarse en línea sin documentos","Una CDL nunca vence una vez que el conductor aprueba la prueba de habilidades"],"explanation":"Las credenciales de Clase A, B o C (CDL) por lo general no pueden renovarse por correo; se requiere una renovación en persona con la certificación médica vigente. Fuente: KRS 281A.170; KYTC drive.ky.gov."}},"hi":{"0":{"q":"केंटकी के इंटरस्टेट और निर्दिष्ट राजमार्गों पर, एक वाणिज्यिक वाहन की अधिकतम कानूनी चौड़ाई कितनी है (दर्पण जैसी स्वीकृत सुरक्षा सहायक वस्तुओं को छोड़कर)?","options":["8 फुट 3 इंच (99 इंच)","8 फुट 6 इंच (102 इंच)","8 फुट 0 इंच (96 इंच)","9 फुट 0 इंच (108 इंच)"],"explanation":"केंटकी इंटरस्टेट और निर्दिष्ट राजमार्गों पर वाहन की चौड़ाई 8 फुट 6 इंच (102 इंच) तक सीमित करता है, जो 23 CFR 658 के अनुरूप है। स्रोत: Kentucky DRIVE (KYTC) Legal Dimensions पृष्ठ; KRS 189.221/189.222।"},"1":{"q":"केंटकी के उन राज्य-अनुरक्षित राजमार्गों पर अधिकतम कानूनी वाहन चौड़ाई कितनी है जो इंटरस्टेट या अन्यथा निर्दिष्ट राजमार्ग नहीं हैं?","options":["8 फुट (96 इंच)","8 फुट 6 इंच (102 इंच)","7 फुट 6 इंच (90 इंच)","9 फुट (108 इंच)"],"explanation":"केंटकी की गैर-निर्दिष्ट राज्य-अनुरक्षित सड़कों पर कानूनी चौड़ाई घटकर 8 फुट (96 इंच) रह जाती है; 8'6\" की छूट केवल इंटरस्टेट और निर्दिष्ट राजमार्ग प्रणाली पर लागू होती है। स्रोत: Kentucky DRIVE (KYTC) Legal Dimensions पृष्ठ; KRS 189.221।"},"2":{"q":"ओवर-डाइमेंशनल परमिट की आवश्यकता पड़ने से पहले केंटकी के राजमार्गों पर अधिकतम कानूनी वाहन ऊँचाई कितनी है?","options":["14 फुट 0 इंच","14 फुट 6 इंच","13 फुट 0 इंच","13 फुट 6 इंच"],"explanation":"केंटकी कानूनी अधिकतम वाहन एवं भार की ऊँचाई 13 फुट 6 इंच निर्धारित करता है; इससे अधिक ऊँचाई के लिए ओवर-डाइमेंशनल परमिट आवश्यक है। स्रोत: Kentucky DRIVE (KYTC) Legal Dimensions पृष्ठ; KRS 189.222।"},"3":{"q":"केंटकी की इंटरस्टेट और निर्दिष्ट राजमार्ग प्रणाली पर संचालित एकल सेमीट्रेलर की अधिकतम कानूनी लंबाई कितनी है?","options":["45 फुट","57 फुट","53 फुट","48 फुट"],"explanation":"केंटकी की इंटरस्टेट और निर्दिष्ट राजमार्गों पर एकल सेमीट्रेलर 53 फुट तक लंबा हो सकता है। स्रोत: Kentucky DRIVE (KYTC) Legal Dimensions पृष्ठ; KRS 189.221/189.222।"},"4":{"q":"केंटकी में संचालित ट्विन-ट्रेलर (डबल) संयोजन में, प्रत्येक अलग-अलग ट्रेलर की अधिकतम कानूनी लंबाई कितनी है?","options":["प्रत्येक 26 फुट","प्रत्येक 28 फुट","प्रत्येक 30 फुट","प्रत्येक 32 फुट"],"explanation":"केंटकी प्रत्येक 28 फुट तक के ट्विन/डबल ट्रेलरों की अनुमति देता है, जो संघीय रूप से संरक्षित डबल आयाम के अनुरूप है। स्रोत: Kentucky DRIVE (KYTC) Legal Dimensions पृष्ठ; KRS 189.222।"},"5":{"q":"केंटकी के राजमार्गों पर एकल-इकाई मोटर ट्रक की अधिकतम कानूनी लंबाई कितनी है?","options":["45 फुट","53 फुट","48 फुट","40 फुट"],"explanation":"केंटकी के आयाम नियमों के तहत एकल-इकाई मोटर ट्रक की लंबाई 45 फुट तक सीमित है। स्रोत: Kentucky DRIVE (KYTC) Legal Dimensions पृष्ठ; KRS 189.221।"},"6":{"q":"केंटकी के उन राज्य-अनुरक्षित राजमार्गों पर जो निर्दिष्ट प्रणाली का हिस्सा नहीं हैं, ट्रक-ट्रैक्टर और ट्रेलर संयोजन की अधिकतम समग्र लंबाई कितनी है?","options":["75 फुट","70 फुट","60 फुट","65 फुट"],"explanation":"गैर-निर्दिष्ट राज्य-अनुरक्षित सड़कों पर समग्र संयोजन की लंबाई 65 फुट तक सीमित है, भले ही निर्दिष्ट राजमार्गों पर 53-फुट सेमीट्रेलर की अनुमति हो। स्रोत: Kentucky DRIVE (KYTC) Legal Dimensions पृष्ठ; KRS 189.221।"},"7":{"q":"ओवरवेट परमिट के बिना केंटकी के राजमार्गों पर वाणिज्यिक वाहन और भार के लिए अधिकतम कानूनी सकल वजन कितना है?","options":["84,000 पाउंड","88,000 पाउंड","80,000 पाउंड","73,280 पाउंड"],"explanation":"केंटकी कुल सकल वाहन वजन को 80,000 पाउंड तक सीमित करता है, जो संघीय इंटरस्टेट मानक के अनुरूप है। स्रोत: KRS 189.222; 603 KAR 5:066; Kentucky DRIVE (KYTC)।"},"8":{"q":"केंटकी में एकल एक्सल पर ढोया जा सकने वाला अधिकतम कानूनी वजन कितना है?","options":["22,400 पाउंड","20,000 पाउंड","18,000 पाउंड","24,000 पाउंड"],"explanation":"केंटकी में कोई भी एकल एक्सल 20,000 पाउंड से अधिक नहीं हो सकता (या समग्र टायर चौड़ाई के प्रति इंच 700 पाउंड, जो भी कम हो)। स्रोत: KRS 189.222; 603 KAR 5:066।"},"9":{"q":"केंटकी में टैंडम एक्सल समूह (42 से 96 इंच की दूरी पर स्थित एक्सल) पर अधिकतम कानूनी वजन कितना है?","options":["34,000 पाउंड","36,000 पाउंड","40,000 पाउंड","32,000 पाउंड"],"explanation":"केंटकी में 42 से 96 इंच की दूरी पर स्थित टैंडम एक्सल समूह 34,000 पाउंड तक सीमित है। स्रोत: KRS 189.222; 603 KAR 5:066; Kentucky DRIVE (KYTC) Legal Dimensions।"},"10":{"q":"केंटकी में, 42 से 120 इंच की दूरी पर स्थित ट्राइडेम (तीन-एक्सल) समूह पर अधिकतम कानूनी वजन कितना है?","options":["45,000 पाउंड","42,000 पाउंड","51,000 पाउंड","48,000 पाउंड"],"explanation":"केंटकी में 42 से 120 इंच के बीच की दूरी पर स्थित ट्राइडेम एक्सल समूह को 48,000 पाउंड तक की अनुमति है। स्रोत: KRS 189.222; Kentucky DRIVE (KYTC) Legal Dimensions पृष्ठ।"},"11":{"q":"केंटकी एक्सल वजन पर वजन सहिष्णुता की अनुमति देता है, लेकिन केवल कुछ सड़कों पर। 5 प्रतिशत एक्सल-वजन सहिष्णुता किन राजमार्गों पर लागू होती है?","options":["केवल काउंटी-अनुरक्षित सड़कों पर","इंटरस्टेट प्रणाली सहित सभी राजमार्गों पर","वे राज्य-अनुरक्षित राजमार्ग जो इंटरस्टेट प्रणाली का हिस्सा नहीं हैं","केवल इंटरस्टेट प्रणाली पर"],"explanation":"केंटकी उन राज्य-अनुरक्षित राजमार्गों पर एक्सल वजन पर 5 प्रतिशत से अधिक न होने वाली सहिष्णुता की अनुमति देता है जो इंटरस्टेट प्रणाली का हिस्सा नहीं हैं; इंटरस्टेट पर ऐसी कोई एक्सल सहिष्णुता लागू नहीं होती। स्रोत: KRS 189.222।"},"12":{"q":"केंटकी कानून के तहत, 5 प्रतिशत वजन सहिष्णुता सकल वाहन वजन पर कैसे लागू होती है?","options":["5 प्रतिशत सहिष्णुता केवल इंटरस्टेट पर लागू होती है","सकल वजन पर कोई सहिष्णुता अनुमत नहीं है","गैर-इंटरस्टेट सड़कों पर 10 प्रतिशत सहिष्णुता लागू होती है","5 प्रतिशत सहिष्णुता सभी सड़कों पर लागू होती है"],"explanation":"केंटकी स्पष्ट रूप से सकल वजन पर कोई सहिष्णुता अनुमत नहीं करता; 5 प्रतिशत सहिष्णुता केवल गैर-इंटरस्टेट राज्य-अनुरक्षित राजमार्गों पर एक्सल वजन पर लागू होती है। स्रोत: KRS 189.222।"},"13":{"q":"केंटकी लगातार एक्सल समूहों पर वजन को सीमित करने के लिए संघीय ब्रिज फॉर्मूला का उपयोग करता है। यह फॉर्मूला मुख्य रूप से सकल वजन को किससे संबंधित करता है?","options":["एक्सल की संख्या और उनके बीच की दूरी (अंतराल)","टायरों की संख्या और उनके वायु दाब","इंजन की अश्वशक्ति और सकल संयोजन वजन रेटिंग","ट्रेलर की लंबाई और कार्गो घनत्व"],"explanation":"संघीय ब्रिज फॉर्मूला, W=500(LN/(N-1)+12N+36), किसी भी दो या अधिक लगातार एक्सल के समूह पर वजन को एक्सल की संख्या (N) और समूह के अंतिम छोर के एक्सल के बीच की दूरी (L) के आधार पर सीमित करता है। केंटकी इसे 23 CFR Part 658 को अपनाकर लागू करता है। स्रोत: 23 CFR 658.17; KRS 189.222।"},"14":{"q":"केंटकी में उपयोग किए जाने वाले संघीय ब्रिज फॉर्मूला W = 500(LN/(N-1) + 12N + 36) में, चर 'L' किसका प्रतिनिधित्व करता है?","options":["टन में कानूनी भार वजन","सस्पेंशन की उठाने की क्षमता","फुट में ट्रेलर की लंबाई","समूह के अंतिम छोर के एक्सल के बीच फुट में दूरी"],"explanation":"ब्रिज फॉर्मूला में, L किसी भी दो या अधिक लगातार एक्सल के समूह के अंतिम छोरों के बीच फुट में दूरी है, जबकि N उस समूह में एक्सल की संख्या है। स्रोत: 23 CFR 658.17 (Bridge Formula), केंटकी में KRS 189.222 के तहत अपनाया गया।"},"15":{"q":"केंटकी में टैंडम एक्सल के दो लगातार सेट प्रत्येक पूरा 34,000 पाउंड तभी ढो सकते हैं जब उन टैंडमों के पहले और अंतिम एक्सल के बीच की दूरी कम से कम कितने फुट हो?","options":["28 फुट","40 फुट","36 फुट","30 फुट"],"explanation":"केंटकी द्वारा अपनाए गए ब्रिज फॉर्मूला अपवाद के तहत, टैंडम एक्सल के दो लगातार सेट प्रत्येक 34,000 पाउंड तभी ढो सकते हैं जब उन टैंडमों के पहले और अंतिम एक्सल के बीच की समग्र दूरी 36 फुट या अधिक हो। स्रोत: 23 CFR 658.17; KRS 189.222।"},"16":{"q":"केंटकी का ओवरसाइज़/ओवरवेट (OS/OW) परमिट कब आवश्यक होता है?","options":["केवल काउंटी सड़कों पर यात्रा करते समय","चौड़ाई, ऊँचाई, लंबाई, या वजन के लिए कानूनी सीमाओं से अधिक किसी भी वाहन या भार को चलाने से पहले","केवल जब सकल वजन 90,000 पाउंड से अधिक हो","केवल जब भार 10 फुट से अधिक चौड़ा हो"],"explanation":"चौड़ाई, ऊँचाई, लंबाई, या वजन के लिए वैधानिक कानूनी सीमाओं से अधिक किसी भी वाहन या भार को चलाने से पहले केंटकी परमिट प्राप्त किया जाना चाहिए। स्रोत: KYTC Division of Motor Carriers; 601 KAR 1:018।"},"17":{"q":"कौन सी केंटकी एजेंसी विशेष ओवरवेट/ओवर-डाइमेंशनल मोटर वाहन भार परमिट जारी करती है, और सामान्यतः किसे ऐसा परमिट नहीं मिल सकता?","options":["KYTC Division of Motor Carriers; उचित रूप से विभाज्य भारों को सामान्यतः परमिट नहीं दिया जा सकता","U.S. DOT; केवल इंटरस्टेट भारों को परमिट दिया जा सकता है","Kentucky State Police; केवल कृषि भारों को परमिट दिया जा सकता है","काउंटी राजकोषीय न्यायालय; केवल वन उत्पादों को परमिट दिया जा सकता है"],"explanation":"Kentucky Transportation Cabinet के Division of Motor Carriers 601 KAR 1:018 के तहत OS/OW परमिट जारी करते हैं, और सामान्यतः उन भारों के लिए परमिट जारी नहीं किए जाते जो उचित रूप से विभाज्य हों (जिन्हें कानूनी सीमाओं को पूरा करने के लिए अलग या विभाजित किया जा सके)। स्रोत: 601 KAR 1:018; KRS 189.270।"},"18":{"q":"केंटकी अविभाज्य कृषि उपकरणों के लिए एक विशेष छूट प्रदान करता है। यह किसकी अनुमति देता है?","options":["कृषि उपकरण दो-लेन सड़कों पर बिना परमिट के किसी भी चौड़ाई पर यात्रा कर सकते हैं","कृषि उपकरण इंटरस्टेट पर बिना परमिट के 120,000 पाउंड से अधिक हो सकते हैं","कृषि उपकरण राज्यव्यापी सभी परमिट और वजन नियमों से छूट प्राप्त हैं","कानूनी वजन या आयाम सीमाओं से अधिक अविभाज्य कृषि उपकरणों के लिए एकल-यात्रा परमिट जारी किया जा सकता है"],"explanation":"केंटकी उन अविभाज्य कृषि उपकरणों की आवाजाही के लिए ओवरवेट/ओवर-डाइमेंशनल एकल-यात्रा परमिट जारी करता है जो KRS 189.222 या 189.270 की सीमाओं से अधिक हैं; यह एक अनुमत छूट है, न कि एक व्यापक मुक्ति। स्रोत: 601 KAR 1:019; 601 KAR 1:018।"},"19":{"q":"केंटकी की Extended-Weight Coal Haul Road System (ECWHRS) के तहत, कोयला ढोने वाला 5-या-अधिक-एक्सल ट्रैक्टर-सेमीट्रेलर किस अधिकतम सकल वजन पर संचालित हो सकता है?","options":["90,000 पाउंड (5 प्रतिशत सहिष्णुता के साथ)","80,000 पाउंड (कोई सहिष्णुता नहीं के साथ)","120,000 पाउंड (5 प्रतिशत सहिष्णुता के साथ)","100,000 पाउंड (10 प्रतिशत सहिष्णुता के साथ)"],"explanation":"Extended-Weight Coal Haul Road System पर, पाँच या अधिक एक्सल वाला कोयला या कोयला उप-उत्पाद ढोने वाला ट्रैक्टर-सेमीट्रेलर 5 प्रतिशत सहिष्णुता के साथ 120,000 पाउंड सकल वजन तक संचालित हो सकता है। स्रोत: KRS 177.9771।"},"20":{"q":"केंटकी में, 26,001 पाउंड या अधिक की सकल संयोजन वजन रेटिंग (GCWR) वाले वाहनों के किसी भी संयोजन को संचालित करने के लिए Class A CDL आवश्यक है, बशर्ते कि खींचे जा रहे वाहन(नों) की GVWR किस वजन से अधिक हो?","options":["10,000 पाउंड","26,001 पाउंड","16,000 पाउंड","1,000 पाउंड"],"explanation":"केंटकी 26,001 lbs या अधिक की GCWR वाले संयोजनों के लिए Class A CDL की आवश्यकता रखता है जब खींची गई इकाई(यों) की GVWR 10,000 lbs से अधिक हो। स्रोत: Kentucky CDL Manual (KYTC, March 2025), 'Who Must Apply? - Class A CDL.'"},"21":{"q":"केंटकी नियमों के तहत, कम से कम कितने पाउंड की सकल वाहन वजन रेटिंग (GVWR) वाले किसी भी एकल वाहन को चलाने के लिए Class B CDL आवश्यक है?","options":["10,001 पाउंड","26,001 पाउंड","33,000 पाउंड","16,001 पाउंड"],"explanation":"Class B CDL 26,001 lbs या अधिक की GVWR वाले किसी भी एकल वाहन को कवर करता है, जिसमें ऐसा वाहन भी शामिल है जो 10,000 lbs या कम की GVWR वाली इकाई को खींच रहा हो। स्रोत: Kentucky CDL Manual (KYTC, March 2025), 'Class B CDL.'"},"22":{"q":"Kentucky CDL Manual के अनुसार, 26,001 पाउंड से कम GVWR वाले वाहन को Class C CDL की आवश्यकता तब होती है जब उसे चालक सहित कम से कम कितने लोगों को ले जाने के लिए डिज़ाइन किया गया हो?","options":["15","24","16","9"],"explanation":"केंटकी 26,001 lbs GVWR से कम वाले उस वाहन के लिए Class C CDL की आवश्यकता रखता है जो चालक सहित 16 या अधिक यात्रियों को ले जाता है, या जो प्लेकार्ड लगाने योग्य खतरनाक सामग्री ढोता है। स्रोत: Kentucky CDL Manual (KYTC, March 2025), 'Class C CDL.'"},"23":{"q":"केंटकी में, 26,001 पाउंड से कम GVWR वाले उस वाहन पर कौन सा CDL वर्ग लागू होता है जो प्लेकार्ड लगाने की आवश्यकता वाली मात्रा में खतरनाक सामग्री ढोता है?","options":["Class A","Class B","Class D","Class C"],"explanation":"Class C CDL उन वाहनों को कवर करता है जो 26,001 lbs GVWR से कम हैं और जो प्लेकार्ड लगाने योग्य खतरनाक सामग्री या 16+ यात्रियों (चालक सहित) को ढोते हैं। स्रोत: Kentucky CDL Manual (KYTC, March 2025), 'Class C CDL.'"},"24":{"q":"वह न्यूनतम आयु क्या है जिस पर केंटकी एक CDL जारी कर सकता है जो इंट्रास्टेट वाणिज्य तक सीमित हो ('K' प्रतिबंध के साथ)?","options":["21 वर्ष","18 वर्ष","19 वर्ष","16 वर्ष"],"explanation":"केंटकी 18 से 20 वर्ष की उस व्यक्ति को 'K' (केवल इंट्रास्टेट) प्रतिबंध के साथ वर्ग-विशिष्ट CDL जारी कर सकता है जो परीक्षण आवश्यकताओं को पूरा करता है और स्कूल बस नहीं चलाता या खतरनाक सामग्री नहीं ढोता। स्रोत: Kentucky CDL Manual (KYTC, March 2025), 'Individual Eighteen (18) Years of Age Driving Intrastate.'"},"25":{"q":"एक केंटकी CDL धारक जो इंटरस्टेट वाणिज्य में (राज्य की सीमाओं के पार, बिना प्रतिबंध के) एक वाणिज्यिक मोटर वाहन चलाना चाहता है, उसकी आयु कम से कम कितनी होनी चाहिए?","options":["18 वर्ष","19 वर्ष","21 वर्ष","25 वर्ष"],"explanation":"18-20 आयु के चालक केंटकी इंट्रास्टेट वाणिज्य तक सीमित हैं ('K' प्रतिबंध); इंटरस्टेट वाणिज्य में उस प्रतिबंध के बिना संचालन के लिए चालक की आयु 21 होनी चाहिए। स्रोत: Kentucky CDL Manual (KYTC, March 2025), इंट्रास्टेट आयु अनुभाग।"},"26":{"q":"केंटकी CDL निर्देश परमिट (CLP) जारी होने के बाद, स्किल्स टेस्ट दिए जाने से पहले आवेदक को परमिट कितने समय तक रखना आवश्यक है?","options":["30 दिन","10 दिन","60 दिन","14 दिन"],"explanation":"स्किल्स टेस्ट दिए जाने से पहले परमिट को 14 दिनों तक रखा जाना चाहिए, जो संघीय CLP नियम के अनुरूप है। स्रोत: Kentucky CDL Manual (KYTC, March 2025), 'How to Apply for a CDL.'"},"27":{"q":"एक केंटकी CDL निर्देश परमिट (CLP) कितने समय तक वैध रहता है?","options":["6 महीने","12 महीने","30 दिन","180 दिन, अनिश्चित काल तक नवीकरणीय"],"explanation":"एक केंटकी CDL निर्देश परमिट छह (6) महीने तक वैध रहता है। आवेदक को पुनः आवेदन करने से पहले इसे केवल एक बार नवीनीकृत किया जा सकता है। स्रोत: Kentucky CDL Manual (KYTC, March 2025), 'How to Apply for a CDL' और ELDT अनुभाग।"},"28":{"q":"आवेदक को पुनः आवेदन करने (और सभी शुल्क का भुगतान करने तथा लिखित परीक्षण फिर से देने) से पहले एक केंटकी CDL निर्देश परमिट को कितनी बार नवीनीकृत किया जा सकता है?","options":["दो बार","इसे नवीनीकृत नहीं किया जा सकता","एक बार","असीमित बार"],"explanation":"एक केंटकी CDL परमिट को केवल एक बार नवीनीकृत किया जा सकता है; यदि नवीनीकृत परमिट के समाप्त होने से पहले रोड स्किल्स टेस्ट पास नहीं किया जाता, तो आवेदक को सभी शुल्क और लिखित परीक्षणों के साथ पुनः आवेदन करना होगा। स्रोत: Kentucky CDL Manual (KYTC, March 2025), 'Entry Level Driver Training (ELDT).'"},"29":{"q":"केंटकी CDL पर यात्रियों को ले जाने के लिए डिज़ाइन किए गए वाहन, जैसे ट्रांजिट या चार्टर बस, को चलाने के लिए कौन सा एंडोर्समेंट आवश्यक है?","options":["S (School Bus)","N (Tank)","T (Doubles/Triples)","P (Passenger)"],"explanation":"यात्रियों को ले जाने के लिए P (Passenger) एंडोर्समेंट आवश्यक है; इसे जोड़ने के लिए आवेदित वर्ग के यात्री वाहन में पूर्ण स्किल्स टेस्ट आवश्यक है। स्रोत: Kentucky CDL Manual (KYTC, March 2025), 'Endorsements' और 'Adding a Passenger endorsement.'"},"30":{"q":"केंटकी में स्कूल बस चलाने के लिए, एक CDL धारक को किस अन्य एंडोर्समेंट के अतिरिक्त S (School Bus) एंडोर्समेंट प्राप्त करना होगा?","options":["P (Passenger)","N (Tank)","H (HazMat)","T (Doubles/Triples)"],"explanation":"स्कूल बस चालकों को Passenger (P) एंडोर्समेंट के अतिरिक्त School Bus (S) एंडोर्समेंट धारण करना होगा, और चलाई जाने वाली स्कूल बस के वर्ग में एक नॉलेज टेस्ट तथा तीनों स्किल्स-टेस्ट भाग पास करने होंगे। स्रोत: Kentucky CDL Manual (KYTC, March 2025), स्कूल बस एंडोर्समेंट अनुभाग।"},"31":{"q":"केंटकी CDL नॉलेज टेस्ट पर, Hazardous Materials (H) एंडोर्समेंट टेस्ट में कितने प्रश्न होते हैं?","options":["20 प्रश्न","30 प्रश्न","50 प्रश्न","25 प्रश्न"],"explanation":"केंटकी के HazMat एंडोर्समेंट नॉलेज टेस्ट में 30 प्रश्न होते हैं, जबकि Doubles/Triples, Tanker, Passenger, और School Bus एंडोर्समेंट टेस्ट में प्रत्येक में 20 होते हैं। स्रोत: Kentucky CDL Manual (KYTC, March 2025), 'Endorsements are required for the following vehicles.'"},"32":{"q":"केंटकी Hazardous Materials (H) एंडोर्समेंट जारी या नवीनीकृत किए जाने से पहले, एक आवेदक को फिंगरप्रिंटिंग और एक सुरक्षा पृष्ठभूमि जाँच पूरी करनी होगी जिसे FBI और किस संघीय एजेंसी द्वारा संसाधित किया जाता है?","options":["Federal Motor Carrier Safety Administration (FMCSA)","Department of Homeland Security Coast Guard","Federal Highway Administration (FHWA)","Transportation Security Administration (TSA)"],"explanation":"HazMat आवेदकों की फिंगरप्रिंटिंग की जाती है और परीक्षण से पहले सुरक्षा खतरा मूल्यांकन के लिए आवेदन FBI और Transportation Security Administration (TSA) को भेजा जाता है। एक TWIC कार्ड मूल्यांकन के प्रमाण के रूप में काम कर सकता है। स्रोत: Kentucky CDL Manual (KYTC, March 2025), HazMat एंडोर्समेंट अनुभाग।"},"33":{"q":"डबल या ट्रिपल ट्रेलर खींचने के लिए कौन सा केंटकी CDL एंडोर्समेंट आवश्यक है?","options":["T","N","H","X"],"explanation":"डबल या ट्रिपल ट्रेलर खींचने के लिए T एंडोर्समेंट (Doubles/Triples) आवश्यक है और इसके लिए 20-प्रश्न नॉलेज टेस्ट पास करना आवश्यक है। स्रोत: Kentucky CDL Manual (KYTC, March 2025), 'Endorsements.'"},"34":{"q":"एक बल्क टैंक वाहन (टैंकर) में तरल या गैसें ढोने के लिए एक केंटकी CDL चालक को कौन सा एंडोर्समेंट चाहिए?","options":["T (Doubles/Triples)","N (Tank)","P (Passenger)","H (HazMat)"],"explanation":"तरल या गैसीय बल्क कार्गो ढोने वाले टैंक वाहन को संचालित करने के लिए N (Tank) एंडोर्समेंट आवश्यक है, और इसके लिए 20-प्रश्न नॉलेज टेस्ट आवश्यक है। स्रोत: Kentucky CDL Manual (KYTC, March 2025), 'Endorsements.'"},"35":{"q":"February 7, 2022 से, पहली बार Class A या B CDL प्राप्त करने से पहले केंटकी में संघीय Entry-Level Driver Training (ELDT) पूरा किया जाना चाहिए, और प्रशिक्षण किस सूची में दर्ज प्रदाता से होना चाहिए?","options":["Kentucky State Police परीक्षण रोस्टर","कोई भी KYTC Regional Office सूची","FMCSA Training Provider Registry","CDLIS clearinghouse"],"explanation":"49 CFR part 380 के तहत ELDT को पहली बार Class A/B CDL, अपग्रेड, या पहले H, P, या S एंडोर्समेंट से पहले FMCSA Training Provider Registry में सूचीबद्ध प्रदाता का उपयोग करके पूरा किया जाना चाहिए। स्रोत: Kentucky CDL Manual (KYTC, March 2025), 'Entry Level Driver Training (ELDT).'"},"36":{"q":"निम्नलिखित में से किसके लिए केंटकी पहली बार जोड़े जाने से पहले Entry-Level Driver Training (ELDT) की आवश्यकता नहीं रखता?","options":["H (HazMat) एंडोर्समेंट","N (Tank) एंडोर्समेंट","P (Passenger) एंडोर्समेंट","S (School Bus) एंडोर्समेंट"],"explanation":"ELDT पहली बार Class A/B CDL, अपग्रेड, और पहले H, P, या S एंडोर्समेंट के लिए आवश्यक है; Tank (N) एंडोर्समेंट ELDT सूची में नहीं है। स्रोत: Kentucky CDL Manual (KYTC, March 2025), 'Entry Level Driver Training (ELDT)'; 49 CFR part 380।"},"37":{"q":"एक केंटकी CDL आवेदक को कौन सी चिकित्सा स्व-प्रमाणन श्रेणी चुननी चाहिए यदि वे केवल केंटकी के भीतर (इंट्रास्टेट) संचालन करते हैं या करने की अपेक्षा रखते हैं और चिकित्सा आवश्यकताओं से अपवादित नहीं हैं?","options":["Excepted Intrastate (EA)","Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)"],"explanation":"केवल केंटकी में संचालन करने वाला चालक जिसे चिकित्सकीय रूप से प्रमाणित होना आवश्यक है, Non-Excepted Intrastate (NA) चुनता है। केंटकी में Excepted Intrastate (EA) बॉक्स का उपयोग नहीं किया जाता क्योंकि सभी KY CDL धारकों को चिकित्सकीय रूप से प्रमाणित होना आवश्यक है। स्रोत: KYTC Commercial Driver License Self-Certification form (TC 94-169); 601 KAR 1:005।"},"38":{"q":"केंटकी CDL स्व-प्रमाणन फॉर्म पर, कौन सी चिकित्सा-प्रमाणन श्रेणी उपलब्ध नहीं है और कभी नहीं चुनी जानी चाहिए क्योंकि सभी केंटकी CDL धारकों को चिकित्सकीय रूप से प्रमाणित होना आवश्यक है?","options":["Excepted Intrastate (EA)","Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Non-Excepted Intrastate (NA)"],"explanation":"केंटकी Excepted Intrastate (EA) श्रेणी की अनुमति नहीं देता; हर KY CDL धारक को चिकित्सकीय रूप से प्रमाणित होना आवश्यक है, इसलिए EA को कभी चिह्नित नहीं किया जाना चाहिए। अन्य तीन (NI, EI, NA) वैध विकल्प हैं। स्रोत: KYTC Commercial Driver License Self-Certification form (TC 94-169); 601 KAR 1:005।"},"39":{"q":"एक केंटकी CDL पर, 'K' प्रतिबंध कोड क्या दर्शाता है?","options":["एयर-ब्रेक से सुसज्जित CMV नहीं","टैंक वाहन में कोई कार्गो नहीं","इंट्रास्टेट (केवल केंटकी) संचालन","CMV बस में कोई यात्री नहीं"],"explanation":"'K' प्रतिबंध धारक को केंटकी के भीतर इंट्रास्टेट वाणिज्य तक सीमित करता है और 21 वर्ष से कम आयु के चालकों तथा अन्य लोगों पर लागू होता है जो इंट्रास्टेट ड्राइविंग तक सीमित हैं। (संदर्भ के लिए, X = टैंक में कोई कार्गो नहीं, L = कोई एयर ब्रेक नहीं, P = CMV बस में कोई यात्री नहीं।) स्रोत: Kentucky CDL Manual (KYTC, March 2025), 'Restrictions.'"},"40":{"q":"केंटकी में एक वाणिज्यिक मोटर वाहन (CMV) संचालित करते समय, वह रक्त अल्कोहल सांद्रता (BAC) क्या है जो कानूनी सीमा है जिस पर एक चालक को नशे में गाड़ी चलाने वाला माना जाता है और अयोग्य घोषित किया जाता है?","options":["0.04 या अधिक","0.08 या अधिक","0.02 या अधिक","0.10 या अधिक"],"explanation":"केंटकी CMV BAC सीमा को 0.04 या अधिक निर्धारित करता है, जो सामान्य चालकों के लिए 0.08 सीमा की आधी है। 0.04 या उससे अधिक पर CMV संचालित करना एक प्रमुख अपराध है जो अयोग्यता को ट्रिगर करता है। स्रोत: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51।"},"41":{"q":"केंटकी में, किसी प्रमुख अपराध (जैसे CMV में DUI) की पहली दोषसिद्धि के परिणामस्वरूप CDL कितने समय के लिए अयोग्य घोषित होता है?","options":["1 वर्ष","60 दिन","6 महीने","3 वर्ष"],"explanation":"पहला प्रमुख अपराध चालक को 1 वर्ष के लिए अयोग्य घोषित करता है (यदि उस समय प्लेकार्ड लगी खतरनाक सामग्री ढोई जा रही हो तो 3 वर्ष)। स्रोत: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 1।"},"42":{"q":"यदि एक केंटकी CDL धारक प्लेकार्ड लगी खतरनाक सामग्री ढोते समय पहला प्रमुख अपराध करता है, तो अयोग्यता अवधि बढ़कर कितनी हो जाती है?","options":["3 वर्ष","1 वर्ष","5 वर्ष","2 वर्ष"],"explanation":"प्लेकार्ड लगी खतरनाक सामग्री ढोते समय पहला प्रमुख अपराध अयोग्यता को 1 वर्ष से बढ़ाकर 3 वर्ष कर देता है। स्रोत: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 1।"},"43":{"q":"केंटकी के निहित-सहमति कानून के तहत, एक वाणिज्यिक मोटर वाहन संचालित करके एक चालक को किन पदार्थों के रासायनिक परीक्षण के लिए सहमति दी हुई माना जाता है?","options":["अल्कोहल या ड्रग्स के लिए रक्त, साँस, या मूत्र","केवल अल्कोहल के लिए साँस","केवल ड्रग्स के लिए रक्त","केवल नियंत्रित पदार्थों के लिए मूत्र"],"explanation":"केंटकी का निहित-सहमति कानून हर CMV संचालक को सहमति दी हुई मानता है कि जब किसी अधिकारी के पास उचित कारण हो तो अल्कोहल या नियंत्रित पदार्थों का पता लगाने के लिए रक्त, साँस, या मूत्र का परीक्षण किया जाए। स्रोत: Kentucky CDL Manual (KYTC), KRS 281A.150/281A.190।"},"44":{"q":"केंटकी में, एक CDL धारक का क्या होता है जो साँस, रक्त, या मूत्र के आवश्यक रासायनिक परीक्षण से इनकार करता है?","options":["प्रमुख अपराध के रूप में माना जाता है — कम से कम 1-वर्ष की अयोग्यता","पहली बार इनकार पर केवल एक चेतावनी","60-दिन की अयोग्यता","30-दिन का निलंबन और जुर्माना"],"explanation":"परीक्षण से इनकार करना स्वयं एक प्रमुख अपराध है, जो DUI दोषसिद्धि के समान अयोग्यता रखता है: कम से कम 1 वर्ष (प्लेकार्ड लगी HazMat के लिए 3 वर्ष)। स्रोत: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 1।"},"45":{"q":"एक केंटकी CDL धारक एक अलग घटना में दूसरे प्रमुख अपराध के लिए दोषी ठहराया जाता है। अयोग्यता अवधि क्या है?","options":["आजीवन अयोग्यता","10 वर्ष","5 वर्ष","3 वर्ष"],"explanation":"एक अलग घटना में दूसरा प्रमुख अपराध CDL की आजीवन अयोग्यता का परिणाम होता है। स्रोत: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 1।"},"46":{"q":"आजीवन अयोग्य घोषित एक केंटकी चालक कितने वर्षों के बाद बहाली के लिए संभावित रूप से पात्र हो सकता है, बशर्ते कि एक स्वीकृत पुनर्वास कार्यक्रम पूरा करने जैसी पात्रता आवश्यकताएँ पूरी हों?","options":["10 वर्ष","5 वर्ष","7 वर्ष","15 वर्ष"],"explanation":"एक राज्य आजीवन-अयोग्य चालक को न्यूनतम 10 वर्षों के बाद बहाल कर सकता है यदि व्यक्ति एक स्वीकृत पुनर्वास कार्यक्रम पूरा करता है; कुछ ड्रग/तस्करी अपराध कभी पात्र नहीं होते। स्रोत: Kentucky CDL Manual (KYTC); 49 CFR 383.51।"},"47":{"q":"0.04 अयोग्य करने वाले स्तर से नीचे भी, अपने सिस्टम में किसी भी पता लगाने योग्य मात्रा में अल्कोहल पाए जाने वाले एक केंटकी CMV चालक का क्या होता है?","options":["24 घंटे के लिए आउट ऑफ सर्विस रखा जाता है","तुरंत 1 वर्ष के लिए अयोग्य घोषित","बिना किसी अन्य कार्रवाई के $100 का जुर्माना","60-दिन की अयोग्यता दी जाती है"],"explanation":"0.04 से नीचे किसी भी मापनीय मात्रा में अल्कोहल वाले चालक को 24 घंटे के लिए आउट ऑफ सर्विस रखा जाता है। 0.04 या उससे अधिक तक पहुँचना एक प्रमुख अपराध है। स्रोत: Kentucky CDL Manual (KYTC); 49 CFR 392.5।"},"48":{"q":"केंटकी में, 3-वर्ष की अवधि के भीतर (अलग घटनाओं में) CMV में दो गंभीर यातायात उल्लंघनों की दोषसिद्धि के परिणामस्वरूप कितने समय के लिए अयोग्यता होती है?","options":["60 दिन","30 दिन","120 दिन","90 दिन"],"explanation":"3 वर्षों के भीतर दो गंभीर यातायात उल्लंघन (अलग घटनाएँ) 60-दिन की अयोग्यता का परिणाम होते हैं। स्रोत: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 2।"},"49":{"q":"केंटकी में, 3-वर्ष की अवधि के भीतर (अलग घटनाओं में) CMV में तीन गंभीर यातायात उल्लंघनों की दोषसिद्धि के परिणामस्वरूप कितने समय के लिए अयोग्यता होती है?","options":["120 दिन","60 दिन","180 दिन","1 वर्ष"],"explanation":"3 वर्षों के भीतर तीन गंभीर यातायात उल्लंघन (अलग घटनाएँ) 120-दिन की अयोग्यता का परिणाम होते हैं, जो अन्य अयोग्यताओं के साथ क्रमिक रूप से लागू होती है। स्रोत: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 2।"},"50":{"q":"निम्नलिखित में से कौन सा एक केंटकी CDL धारक के लिए गंभीर यातायात उल्लंघन के रूप में वर्गीकृत है?","options":["निर्धारित सीमा से 15 mph या अधिक तेज़ गति","निर्धारित सीमा से 5 mph तेज़ गति","एक एकल पार्किंग उल्लंघन","समाप्त पंजीकरण स्टिकर के साथ गाड़ी चलाना"],"explanation":"अत्यधिक गति (सीमा से 15 mph या अधिक तेज़) एक गंभीर यातायात उल्लंघन है, साथ ही लापरवाह ड्राइविंग, अनुचित लेन परिवर्तन, बहुत करीब से पीछा करना, टेक्स्टिंग, और हाथ में फोन पकड़ कर उपयोग करना भी। स्रोत: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 2।"},"51":{"q":"केंटकी CDL उद्देश्यों के लिए, अयोग्यता की ओर गिनती करते समय CMV चलाते समय टेक्स्टिंग को कैसे माना जाता है?","options":["एक गंभीर यातायात उल्लंघन के रूप में","एक प्रमुख अपराध के रूप में","एक आउट-ऑफ-सर्विस उल्लंघन के रूप में","इसका कोई CDL परिणाम नहीं होता"],"explanation":"CMV चलाते समय टेक्स्टिंग एक गंभीर यातायात उल्लंघन है; 3 वर्षों के भीतर दो 60-दिन की अयोग्यता लाते हैं और तीन 120 दिन लाते हैं। स्रोत: Kentucky CDL Manual (KYTC); 49 CFR 383.51 और 49 CFR 392.80।"},"52":{"q":"केंटकी में CMV चलाते समय हाथ में पकड़ा हुआ मोबाइल टेलीफोन उपयोग करना निषिद्ध है और CDL अयोग्यता की ओर किस प्रकार के अपराध के रूप में गिना जाता है?","options":["एक गंभीर यातायात उल्लंघन","एक प्रमुख अपराध","एक रेलरोड-क्रॉसिंग उल्लंघन","एक आउट-ऑफ-सर्विस आदेश उल्लंघन"],"explanation":"CMV चलाते समय हाथ में फोन का उपयोग एक गंभीर यातायात उल्लंघन है; 3 वर्षों के भीतर दो 60-दिन की अयोग्यता देते हैं, तीन 120 दिन देते हैं। स्रोत: Kentucky CDL Manual (KYTC); 49 CFR 383.51 और 49 CFR 392.82।"},"53":{"q":"CMV में रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए पहली दोषसिद्धि के परिणामस्वरूप केंटकी CDL की कम से कम कितने समय की अयोग्यता होती है?","options":["60 दिन","30 दिन","120 दिन","1 वर्ष"],"explanation":"पहला रेलरोड ग्रेड क्रॉसिंग उल्लंघन 60 दिन से कम न होने की अयोग्यता रखता है। स्रोत: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 3।"},"54":{"q":"3-वर्ष की अवधि के भीतर दूसरा रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के परिणामस्वरूप केंटकी CDL की कम से कम कितने समय की अयोग्यता होती है?","options":["120 दिन","60 दिन","180 दिन","1 वर्ष"],"explanation":"3 वर्षों के भीतर दूसरा ग्रेड क्रॉसिंग उल्लंघन 120 दिन से कम न होने की अयोग्यता रखता है। स्रोत: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 3।"},"55":{"q":"3-वर्ष की अवधि के भीतर तीसरा या उसके बाद का रेलरोड-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के परिणामस्वरूप केंटकी CDL की कम से कम कितने समय की अयोग्यता होती है?","options":["1 वर्ष","120 दिन","180 दिन","60 दिन"],"explanation":"3 वर्षों के भीतर तीसरा या उसके बाद का ग्रेड क्रॉसिंग उल्लंघन 1 वर्ष से कम न होने की अयोग्यता रखता है। स्रोत: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 3।"},"56":{"q":"निम्नलिखित में से कौन सा एक रेलरोड ग्रेड-क्रॉसिंग उल्लंघन है जो एक केंटकी CDL धारक को अयोग्य घोषित कर सकता है?","options":["क्रॉसिंग को पूरी तरह से पार करने के लिए पर्याप्त जगह के बिना उस पर गाड़ी चलाना","ट्रेनों की जाँच के लिए पटरियों से 50 फुट पहले रुकना","गति धीमी करना और जाँचना कि पटरियाँ साफ हैं","रास्ते का अधिकार रखने वाली ट्रेन को रास्ता देना"],"explanation":"पटरियों को पार करने के लिए पर्याप्त जगह के बिना क्रॉस करना एक उल्लंघन है, साथ ही गति धीमी न करना/जाँच न करना, आवश्यक होने पर न रुकना, और पर्याप्त अंडरकैरिज क्लीयरेंस न होना भी। स्रोत: Kentucky CDL Manual (KYTC); 49 CFR 383.51 Table 3।"},"57":{"q":"एक केंटकी CDL धारक जो पहली बार (गैर-HazMat, गैर-यात्री) एक आउट-ऑफ-सर्विस आदेश का उल्लंघन करता है, उसे कम से कम कितने समय की अवधि के लिए अयोग्य घोषित किया जाता है?","options":["180 दिन","60 दिन","90 दिन","1 वर्ष"],"explanation":"पहला आउट-ऑफ-सर्विस आदेश उल्लंघन 180 दिन से कम न होने की (1 वर्ष तक) अयोग्यता रखता है। स्रोत: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 4।"},"58":{"q":"10-वर्ष की अवधि के भीतर दूसरे आउट-ऑफ-सर्विस आदेश उल्लंघन के लिए, एक केंटकी CDL धारक को कम से कम कितने समय के लिए अयोग्य घोषित किया जाता है?","options":["2 वर्ष","180 दिन","1 वर्ष","3 वर्ष"],"explanation":"10 वर्षों के भीतर दूसरा आउट-ऑफ-सर्विस आदेश उल्लंघन 2 वर्ष से कम न होने की (5 वर्ष तक) अयोग्यता रखता है। स्रोत: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 4।"},"59":{"q":"10-वर्ष की अवधि के भीतर तीसरे या उसके बाद के आउट-ऑफ-सर्विस आदेश उल्लंघन के परिणामस्वरूप केंटकी CDL की कम से कम कितने समय की अयोग्यता होती है?","options":["3 वर्ष","2 वर्ष","1 वर्ष","5 वर्ष"],"explanation":"10 वर्षों के भीतर तीसरा या उसके बाद का आउट-ऑफ-सर्विस आदेश उल्लंघन 3 वर्ष से कम न होने की (5 वर्ष तक) अयोग्यता रखता है। स्रोत: Kentucky CDL Manual (KYTC), KRS 281A.190; 49 CFR 383.51 Table 4।"},"60":{"q":"केंटकी के 'Slow Down, Move Over' कानून के तहत, जब कोई CDL चालक एक बहु-लेन वाले राजमार्ग पर चमकती हुई लाइटों के साथ खड़े आपातकालीन या सार्वजनिक सुरक्षा वाहन के पास पहुँचता है, तो यदि सुरक्षित रूप से किया जा सके तो चालक की सबसे पहली ज़िम्मेदारी क्या है?","options":["उसी लेन में रहते हुए निर्धारित गति पर चलते रहना","आपातकालीन वाहन के चले जाने तक पूरी तरह रुक जाना","एक लेन हटकर खड़े वाहन के सबसे नज़दीकी लेन को खाली कर देना","ट्रक के आने के बारे में सचेत करने के लिए प्रतिक्रियाकर्ताओं को हॉर्न बजाना"],"explanation":"केंटकी का Move Over कानून (KRS 189.930) यह आवश्यक करता है कि एक ही दिशा में दो या अधिक लेन वाली सड़क पर चालक, जब सुरक्षित हो, चमकती हुई लाइटें दिखाने वाले खड़े आपातकालीन/सार्वजनिक सुरक्षा वाहन के सबसे नज़दीकी लेन को खाली कर दे। स्रोत: KRS 189.930; Kentucky CDL Manual।"},"61":{"q":"एक दो-लेन वाली केंटकी सड़क पर, जहाँ कोई चालक चमकती लाइटों के साथ खड़े आपातकालीन वाहन के लिए सुरक्षित रूप से लेन नहीं बदल सकता, वहाँ Move Over कानून के बजाय चालक से क्या करने की आवश्यकता है?","options":["गति को ऐसे स्तर तक कम करना जो सड़क, मौसम और यातायात की परिस्थितियों के लिए सुरक्षित हो","आपातकालीन वाहन से 500 feet पहले पूरी तरह रुक जाना","चारों दिशा के फ्लैशर चालू करना और गति सीमा बनाए रखना","शोल्डर पर रुककर हाथ के इशारे से आगे जाने की प्रतीक्षा करना"],"explanation":"KRS 189.930 के तहत, यदि लेन बदलना असंभव या असुरक्षित हो, तो चालक को मौजूदा सड़क, मौसम और यातायात की परिस्थितियों के लिए सुरक्षित गति तक धीमा होकर सावधानी से आगे बढ़ना चाहिए। स्रोत: KRS 189.930।"},"62":{"q":"केंटकी ने जुलाई 2024 में अपने Move Over कानून का विस्तार किया। पुलिस, अग्निशमन और एम्बुलेंस के अलावा, विस्तारित कानून अब चालकों से निम्नलिखित में से किसके लिए लेन बदलने या धीमा होने की भी आवश्यकता करता है?","options":["खतरे की लाइटें या चेतावनी संकेत दिखाने वाला कोई भी स्थिर वाहन, जिसमें खराब हो चुके वाहन और टो ट्रक शामिल हैं","केवल चिह्नित कानून प्रवर्तन क्रूज़र","केवल वे वाहन जो सक्रिय रूप से किसी यातायात लेन को अवरुद्ध कर रहे हों","केवल Kentucky Transportation Cabinet के स्वामित्व वाले वाहन"],"explanation":"KRS 189.930 के जुलाई 2024 के विस्तार ने सुरक्षा को व्यापक करके चमकती लाइटें, खतरे की लाइटें, या चेतावनी उपकरण दिखाने वाले किसी भी स्थिर वाहन तक बढ़ा दिया, जैसे टो/रेकर वाहन और खराब हो चुके मोटर चालक, न कि केवल पारंपरिक प्रथम प्रतिक्रियाकर्ता। स्रोत: KRS 189.930 (2024 संशोधन)।"},"63":{"q":"केंटकी में एक CDL चालक खतरनाक सामग्रियों का प्लेकार्ड वाला भार ढो रहा है और एक रेलवे क्रॉसिंग के पास पहुँचता है। चालक को सबसे नज़दीकी रेल से कितनी दूरी के भीतर रुकना चाहिए?","options":["5 feet से कम नहीं और 25 feet से अधिक नहीं","15 feet से कम नहीं और 50 feet से अधिक नहीं","25 feet से कम नहीं और 75 feet से अधिक नहीं","50 feet से कम नहीं और 100 feet से अधिक नहीं"],"explanation":"प्लेकार्ड वाले हैज़मैट वाहन के चालक को पार करने से पहले सबसे नज़दीकी रेल से 50 feet के भीतर रुकना चाहिए, पर 15 feet से अधिक नज़दीक नहीं (यह '15-से-50-foot' नियम है)। स्रोत: 49 CFR 392.10, केंटकी में अपनाया गया; Kentucky CDL Manual।"},"64":{"q":"Kentucky CDL Manual में सिखाए गए नियमों के तहत इनमें से किस वाणिज्यिक वाहन को हर रेलवे क्रॉसिंग पर रुकना आवश्यक है?","options":["एक खाली फ्लैटबेड ट्रैक्टर-ट्रेलर","यात्रियों को ढोने वाली एक बस","सामान्य माल ढोने वाला एक बॉक्स ट्रक","बजरी ढोने वाला एक डंप ट्रक"],"explanation":"यात्रियों को ढोने वाली बसों और खतरनाक-सामग्री प्लेकार्ड दिखाने वाले वाहनों को रेलवे क्रॉसिंग पर रुकना चाहिए, सबसे नज़दीकी रेल से 15 से 50 feet के भीतर रुकते हुए। सामान्य-माल ट्रकों को तब तक रुकने की आवश्यकता नहीं है जब तक कि संकेत ऐसा न कहें। स्रोत: 49 CFR 392.10; Kentucky CDL Manual।"},"65":{"q":"केंटकी के स्कूल बस कानून के तहत, एक चार-लेन राजमार्ग पर एक स्कूल बस लाल लाइटें चमकाते हुए और स्टॉप आर्म बाहर निकालकर रुकती है। किन चालकों को रुकने की आवश्यकता नहीं है?","options":["बस के बगल वाली लेन में उसी दिशा में जा रहे चालक","उसी लेन में बस के ठीक पीछे चल रहे चालक","दिशा या लेन की संख्या की परवाह किए बिना सभी चालकों को रुकना चाहिए","चार-या-अधिक-लेन वाले राजमार्ग पर विपरीत दिशा से आ रहे चालक"],"explanation":"KRS 189.370 के तहत, चार या अधिक लेन वाले राजमार्ग पर, खड़ी स्कूल बस की विपरीत दिशा से आ रहे वाहनों को रुकने की आवश्यकता नहीं है। बस की ओर वाले यातायात को फिर भी रुकना चाहिए। स्रोत: KRS 189.370।"},"66":{"q":"एक मानक दो-लेन वाले केंटकी राजमार्ग पर, एक स्कूल बस बच्चों को चढ़ाने के लिए अपनी लाल लाइटें चमकाते हुए और स्टॉप आर्म बाहर निकालकर रुकती है। सामने से आ रहे यातायात को क्या करना चाहिए?","options":["25 mph तक धीमा करना पर बस के पास से चलते रहना जारी रख सकते हैं","रुकना और तब तक रुके रहना जब तक बस फिर से चलना शुरू न कर दे","सामान्य रूप से आगे बढ़ना क्योंकि बस केंद्र रेखा के दूसरी ओर है","केवल तभी रुकना जब बच्चे सड़क पार करते हुए दिखाई दें"],"explanation":"एक दो-लेन सड़क पर, KRS 189.370 के अनुसार दोनों दिशाओं के चालकों को अपने संकेत सक्रिय किए हुए बच्चों को चढ़ाने या उतारने वाली स्कूल बस के लिए रुकना चाहिए, और तब तक आगे नहीं बढ़ना चाहिए जब तक बस फिर से न चले। विपरीत-दिशा का अपवाद केवल चार या अधिक लेन वाले राजमार्गों पर लागू होता है। स्रोत: KRS 189.370।"},"67":{"q":"केंटकी की स्कूल बस रुकने की आवश्यकता (और इसका विपरीत-दिशा अपवाद) किस विशिष्ट सड़क विशेषता पर आधारित है?","options":["राजमार्ग पर लेन की संख्या (चार या अधिक)","क्या गति सीमा 55 mph या उससे अधिक है","क्या राजमार्ग एक नामित राज्य पार्कवे है","क्या एक भौतिक कंक्रीट अवरोध दिशाओं को अलग करता है"],"explanation":"KRS 189.370 विपरीत-दिशा अपवाद को विशेष रूप से 'चार (4) या अधिक लेन' वाले राजमार्ग से जोड़ता है, न कि किसी मध्य अवरोध की उपस्थिति या गति सीमा से। स्रोत: KRS 189.370।"},"68":{"q":"केंटकी का कानून कुछ बड़े वाहनों को सबसे बाईं लेन से प्रतिबंधित करता है। एक ही दिशा में तीन या अधिक लेन वाले राजमार्ग पर, ओवरटेक करने, प्रवेश करने या छोड़ने के अलावा किन वाहनों को सबसे बाईं लेन से प्रतिबंधित किया गया है?","options":["मोटरसाइकिल और मोपेड","मनोरंजक वाहन और मोटरहोम","ट्रक ट्रैक्टर, ट्रेलर और सेमीट्रेलर","सभी यात्री कारें और पिकअप"],"explanation":"KRS 189.340 एक ही दिशा में तीन या अधिक लेन वाले राजमार्ग की सबसे बाईं लेन में ट्रक ट्रैक्टर, ट्रेलर, या सेमीट्रेलर के संचालन को प्रतिबंधित करता है, सिवाय ओवरटेक करने, राजमार्ग में प्रवेश करने या छोड़ने, प्रवेश करने वाले यातायात को रास्ता देने, या जब अन्य लेन असुरक्षित हों। स्रोत: KRS 189.340।"},"69":{"q":"केंटकी के बाईं-लेन ट्रक नियम के तहत, निम्नलिखित में से कौन-सा एक सेमीट्रेलर के लिए तीन-लेन वाले इंटरस्टेट की सबसे बाईं लेन में वैध रूप से रहने का मान्य कारण है?","options":["ईंधन की किफ़ायत के लिए एक स्थिर क्रूज़िंग गति बनाए रखना","पूरी यात्रा के लिए ऑन-रैंप से विलय करने वाले वाहनों से दूर रहना","एक धीमे वाहन को ओवरटेक करना, फिर जितनी जल्दी व्यावहारिक हो दाईं ओर लौटना","ब्रेक बचाने के लिए गति सीमा से थोड़ा कम चलना"],"explanation":"KRS 189.340 ट्रक ट्रैक्टर/ट्रेलर/सेमीट्रेलर को सबसे बाईं लेन का उपयोग केवल सीमित कारणों से करने की अनुमति देता है जैसे ओवरटेक करना (फिर जितनी जल्दी व्यावहारिक हो दाईं ओर लौटना), राजमार्ग में प्रवेश/छोड़ना, प्रवेश करने वाले यातायात को रास्ता देना, या जब दाईं/मध्य लेन असुरक्षित हों। स्रोत: KRS 189.340।"},"70":{"q":"I-64, I-65, और I-75 जैसे केंटकी के इंटरस्टेट राजमार्गों के ग्रामीण हिस्सों पर ट्रकों के लिए अधिकतम गति सीमा क्या है?","options":["70 mph","65 mph","60 mph","75 mph"],"explanation":"केंटकी अधिकांश ग्रामीण इंटरस्टेट खंडों पर अधिकतम 70 mph पोस्ट करता है; यह ट्रकों पर लागू होता है जब तक कि कोई कम सीमा पोस्ट न हो। शहरी हिस्से (जैसे Louisville और Lexington के आसपास) आमतौर पर 65 mph होते हैं। स्रोत: KRS 189.390; KYTC पोस्ट की गई सीमाएँ।"},"71":{"q":"Louisville और Lexington के पास शहरी क्षेत्रों से होकर, एक CDL चालक को जिस इंटरस्टेट गति सीमा की उम्मीद करनी चाहिए वह सबसे आमतौर पर है:","options":["70 mph","65 mph","45 mph","55 mph"],"explanation":"जबकि ग्रामीण केंटकी इंटरस्टेट आमतौर पर 70 mph पर पोस्ट किए जाते हैं, Louisville और Lexington जैसे महानगरीय क्षेत्रों के आसपास के शहरी इंटरस्टेट खंड आमतौर पर 65 mph पर पोस्ट किए जाते हैं। चालकों को हमेशा पोस्ट की गई सीमा का पालन करना चाहिए। स्रोत: KRS 189.390; KYTC पोस्ट की गई सीमाएँ।"},"72":{"q":"एक CDL चालक का ट्रक दिन के उजाले में एक दो-लेन, दो-तरफ़ा केंटकी राजमार्ग के शोल्डर पर खराब हो जाता है। आवश्यक चेतावनी उपकरण लगाने के बाद, तीन परावर्तक त्रिकोणों को कहाँ रखा जाना चाहिए?","options":["100 feet पीछे, 100 feet आगे, और एक केबिन के बगल में","वाहन से 10 feet पीछे, 100 feet पीछे, और 100 feet आगे","वाहन से 25 feet पीछे, 200 feet पीछे, और 200 feet आगे","वाहन से 10 feet पीछे, 50 feet पीछे, और 50 feet आगे"],"explanation":"एक दो-लेन, दो-तरफ़ा सड़क पर, एक त्रिकोण को पिछले हिस्से से 10 feet के भीतर, एक लगभग 100 feet पीछे, और एक वाहन से लगभग 100 feet आगे रखें। स्रोत: 49 CFR 392.22, केंटकी में अपनाया गया; Kentucky CDL Manual।"},"73":{"q":"जब कोई वाणिज्यिक वाहन एक-तरफ़ा या विभाजित केंटकी राजमार्ग पर रुका होता है, तो तीन चेतावनी उपकरण आ रहे यातायात के सापेक्ष कहाँ रखे जाते हैं?","options":["100 feet पीछे और 100 feet आगे, साथ ही एक केबिन पर","आ रहे यातायात की ओर 10 feet, 100 feet, और 200 feet","आ रहे यातायात की ओर 200 feet, 200 feet, और 500 feet","आ रहे यातायात की ओर 10 feet, 50 feet, और 100 feet"],"explanation":"एक-तरफ़ा या विभाजित राजमार्ग पर, वाहन द्वारा उपयोग की जा रही लेन या शोल्डर के केंद्र में आ रहे यातायात की ओर 10 feet, 100 feet, और 200 feet पर चेतावनी उपकरण रखें। स्रोत: 49 CFR 392.22; Kentucky CDL Manual।"},"74":{"q":"एक केंटकी सड़क पर एक खराब वाणिज्यिक वाहन को रोकने के बाद, चालक को आवश्यक आपातकालीन चेतावनी उपकरण कितने मिनटों के भीतर लगाने चाहिए?","options":["10 मिनट के भीतर","5 मिनट के भीतर","30 मिनट के भीतर","15 मिनट के भीतर"],"explanation":"चालक को रुकने के 10 मिनट के भीतर तीन आवश्यक चेतावनी उपकरण रखने चाहिए। स्रोत: 49 CFR 392.22, केंटकी में अपनाया गया; Kentucky CDL Manual।"},"75":{"q":"केंटकी के Pine Mountain (U.S. 119) जैसी लंबी उतराई पर, Kentucky CDL Manual में सिखाई गई उचित ब्रेकिंग तकनीक क्या है?","options":["वाहन को धीमा करने के लिए पार्किंग ब्रेक को रुक-रुक कर लगाना","इंजन को ठंडा होने देने के लिए न्यूट्रल में डालना और हल्के से ब्रेक पर सवार रहना","उतराई से पहले एक कम गियर चुनना और हल्की, स्थिर या स्नब ब्रेकिंग का उपयोग करना","जितना संभव हो सबसे ऊँचा गियर रखना और लगातार ब्रेक पंप करना"],"explanation":"चालकों को ढलान से उतरना शुरू करने से पहले उचित कम गियर चुनना चाहिए और मुख्य रूप से इंजन ब्रेकिंग पर निर्भर रहना चाहिए, सेवा ब्रेकों का उपयोग हल्के, रुक-रुक कर (स्नब) लगाने में करते हुए। ब्रेक पर सवार रहने से अधिक गर्मी और ब्रेक फेड होता है। स्रोत: Kentucky CDL Manual (गति नियंत्रण / पहाड़ी ड्राइविंग)।"},"76":{"q":"केंटकी में ओवरसाइज़ परमिट के बिना, नामित राजमार्गों पर एक वाणिज्यिक वाहन और भार के लिए अनुमत अधिकतम कानूनी चौड़ाई क्या है?","options":["10 feet 0 inches","9 feet 6 inches","8 feet 0 inches","8 feet 6 inches"],"explanation":"केंटकी की इंटरस्टेट और नामित राजमार्गों पर कानूनी अधिकतम वाहन/भार चौड़ाई 8 feet 6 inches (102 inches) है; इससे अधिक चौड़ी किसी भी चीज़ के लिए KYTC से एक ओवरसाइज़ परमिट की आवश्यकता होती है। स्रोत: KRS Chapter 189; KYTC Overweight/Over-Dimensional Permits।"},"77":{"q":"केंटकी में एक भार की ऊँचाई 14 feet है। परमिट के बिना, कानूनी अधिकतम ऊँचाई 13 feet 6 inches है। इस भार को ले जाने से पहले वाहक को क्या प्राप्त करना होगा?","options":["केवल स्थानीय काउंटी शेरिफ से अनुमति","कुछ नहीं, क्योंकि केंटकी में ऊँचाई सीमाएँ केवल सलाहकारी हैं","Kentucky Transportation Cabinet से एक ओवरसाइज़/ओवर-डायमेंशनल परमिट","केवल एक खतरनाक-सामग्री एंडोर्समेंट"],"explanation":"केंटकी की कानूनी अधिकतम ऊँचाई 13 feet 6 inches है; 14 feet का भार इससे अधिक है और यात्रा से पहले KYTC Division of Motor Carriers के माध्यम से जारी एक ओवर-डायमेंशनल परमिट की आवश्यकता है। स्रोत: KRS Chapter 189; KYTC Overweight/Over-Dimensional Permits।"},"78":{"q":"केंटकी आमतौर पर किस प्रकार के भार के लिए एक ओवरसाइज़/ओवरवेट परमिट जारी नहीं करेगा?","options":["औद्योगिक मशीनरी का एक एकल टुकड़ा जिसे अलग नहीं किया जा सकता","एक ऐसा भार जो उचित रूप से विभाज्य है और जिसे कानूनी सीमाओं को पूरा करने के लिए पुनर्व्यवस्थित किया जा सकता है","एक बड़ा ट्रांसफॉर्मर जो कानूनी वज़न से अधिक है","एक पूर्व-निर्मित भवन खंड जो कानूनी चौड़ाई से अधिक है"],"explanation":"केंटकी OS/OW परमिट केवल अविभाज्य भारों के लिए जारी करता है; यह एक ऐसे भार की अनुमति नहीं देगा जो उचित रूप से विभाज्य है (जिसे कानूनी सीमाओं का पालन करने के लिए अलग या पुनर्व्यवस्थित किया जा सके), सिवाय विशिष्ट वैधानिक प्राधिकार के तहत। स्रोत: KYTC Overweight/Over-Dimensional Permits; KRS Chapter 189।"},"79":{"q":"केंटकी की कौन-सी एजेंसी वास्तव में योग्य आवेदकों को Commercial Driver License (CDL) क्रेडेंशियल जारी करती है?","options":["Kentucky Transportation Cabinet का Division of Driver Licensing","Kentucky State Police","Federal Motor Carrier Safety Administration","काउंटी Circuit Court Clerk का बॉन्डिंग कार्यालय"],"explanation":"केंटकी में CDL क्रेडेंशियल Kentucky Transportation Cabinet (KYTC), Division of Driver Licensing द्वारा जारी किया जाता है। स्रोत: KYTC drive.ky.gov CDL पेज; 2025 Kentucky CDL Manual।"},"80":{"q":"केंटकी में आवेदकों के लिए CDL ज्ञान परीक्षण और रोड स्किल्स परीक्षण कौन आयोजित करता है?","options":["Kentucky State Police","काउंटी Circuit Court Clerk","केवल निजी तृतीय-पक्ष ट्रक ड्राइविंग स्कूल","FMCSA National Registry"],"explanation":"Kentucky State Police (KSP) केंटकी में सभी CDL ज्ञान और स्किल्स परीक्षण आयोजित करने के लिए विशेष रूप से ज़िम्मेदार है, जबकि KYTC लाइसेंस जारी करता है। स्रोत: 2025 Kentucky CDL Manual; Kentucky State Police Driver Testing।"},"81":{"q":"एक केंटकी Commercial Learner's Permit (CLP) कितने दिनों के लिए वैध होता है?","options":["180 days","60 days","365 days","90 days"],"explanation":"एक केंटकी CLP अधिकतम 180 days के लिए वैध होता है। स्रोत: KRS 281A.120; 2025 Kentucky CDL Manual।"},"82":{"q":"CLP जारी होने के बाद, केंटकी में CDL स्किल्स परीक्षण लेने से पहले एक आवेदक को कितनी प्रतीक्षा करनी होगी?","options":["कम से कम 14 days","कम से कम 30 days","कम से कम 7 days","कम से कम 60 days"],"explanation":"एक आवेदक को CDL स्किल्स परीक्षण लेने के लिए पात्र होने से पहले कम से कम 14 days तक CLP रखना होगा। यह एक संघीय मानक है जो केंटकी में लागू होता है। स्रोत: 2025 Kentucky CDL Manual; 49 CFR 383.25।"},"83":{"q":"नवीनीकरण की आवश्यकता होने से पहले एक केंटकी Commercial Driver License कितने समय तक वैध रहता है?","options":["8 years","4 years","5 years","10 years"],"explanation":"एक केंटकी CDL क्रेडेंशियल 8 years के लिए वैध होता है। स्रोत: KRS 281A.170; KYTC drive.ky.gov।"},"84":{"q":"कौन-सा फ़ॉर्म DOT Medical Examiner's Certificate है जिसे एक केंटकी CDL आवेदक को एक प्रमाणित चिकित्सा परीक्षक से प्राप्त करना होगा?","options":["Form MCSA-5876","Form TC 94-169","केवल Form MCSA-5875","Form DOT-391"],"explanation":"Medical Examiner's Certificate, Form MCSA-5876 है, जिसे एक National Registry Certified Medical Examiner द्वारा पूरा किया जाता है; यह CDL धारक के लिए फ़ाइल पर होना चाहिए। (TC 94-169 अलग स्व-प्रमाणन फ़ॉर्म है।) स्रोत: KYTC प्रथम-बार आवेदक जानकारी; FMCSA।"},"85":{"q":"केंटकी CDL स्व-प्रमाणन पर, एक आवेदक को कितनी ड्राइविंग-प्रकार श्रेणियों में से चुनना होगा?","options":["चार","दो","तीन","पाँच"],"explanation":"स्व-प्रमाणन (Form TC 94-169) में चार श्रेणियाँ हैं: non-excepted interstate, excepted interstate, non-excepted intrastate, और excepted intrastate। स्रोत: KYTC Form TC 94-169; 49 CFR 383.71।"},"86":{"q":"एक केंटकी चालक जो राज्य की सीमाओं के पार संचालन करता है और जिसे संघीय शारीरिक योग्यता मानकों को पूरा करना होगा, उसे किस श्रेणी के रूप में स्व-प्रमाणन करना चाहिए?","options":["Non-excepted interstate","Excepted interstate","Non-excepted intrastate","Excepted intrastate"],"explanation":"इंटरस्टेट वाणिज्य में संघीय शारीरिक योग्यता नियमों के अधीन चालक non-excepted interstate के रूप में प्रमाणन करते हैं, जिसके लिए फ़ाइल पर एक वर्तमान Medical Examiner's Certificate की आवश्यकता होती है। स्रोत: KYTC Form TC 94-169; 49 CFR 383.71।"},"87":{"q":"केंटकी में एक प्रथम-बार Class A या Class B आवेदक के CDL स्किल्स परीक्षण लेने से पहले, कौन-सी प्रशिक्षण आवश्यकता पूरी की जानी चाहिए?","options":["एक पंजीकृत प्रदाता से Entry-Level Driver Training (ELDT)","KYTC द्वारा प्रायोजित 160-घंटे की राज्य प्रशिक्षुता","Circuit Court Clerk पर एक रक्षात्मक ड्राइविंग पाठ्यक्रम","दो वर्षों का प्रलेखित इंट्रास्टेट ड्राइविंग"],"explanation":"प्रथम-बार Class A/B परीक्षण से पहले (और प्रथम P, S, या H एंडोर्समेंट परीक्षण से पहले) एक FMCSA Training Provider Registry प्रदाता से संघीय Entry-Level Driver Training (ELDT) आवश्यक है। स्रोत: 2025 Kentucky CDL Manual; 49 CFR Part 380।"},"88":{"q":"प्रथम-बार Class A और Class B आवेदकों के अतिरिक्त, निम्नलिखित में से किस एंडोर्समेंट के लिए परीक्षण से पहले ELDT पूरा करना आवश्यक है?","options":["Hazardous materials (H), passenger (P), और school bus (S)","Tank vehicle (N) और doubles/triples (T)","केवल school bus (S) एंडोर्समेंट","किसी भी एंडोर्समेंट के लिए ELDT आवश्यक नहीं है"],"explanation":"ELDT, hazardous materials (H), passenger (P), और school bus (S) एंडोर्समेंट के लिए प्रथम-बार आवेदकों के लिए आवश्यक है, साथ ही प्रारंभिक Class A/B जारी करने और Class B-से-A अपग्रेड के लिए भी। स्रोत: 2025 Kentucky CDL Manual; 49 CFR Part 380।"},"89":{"q":"केंटकी CDL स्किल्स परीक्षण तीन भागों में आयोजित किया जाता है। कौन-सा समूह उन तीन भागों को सही ढंग से सूचीबद्ध करता है?","options":["प्री-ट्रिप निरीक्षण, बुनियादी वाहन नियंत्रण, और ऑन-रोड ड्राइविंग","लिखित ज्ञान, दृष्टि जाँच, और ऑन-रोड ड्राइविंग","प्री-ट्रिप निरीक्षण, एयर-ब्रेक लिखित परीक्षण, और बैकिंग","बुनियादी वाहन नियंत्रण, हैज़मैट लिखित परीक्षण, और ऑन-रोड ड्राइविंग"],"explanation":"CDL स्किल्स परीक्षण में तीन भाग होते हैं: प्री-ट्रिप निरीक्षण, बुनियादी वाहन नियंत्रण कौशल, और ऑन-रोड ड्राइविंग परीक्षण। स्रोत: 2025 Kentucky CDL Manual; 49 CFR 383.113।"},"90":{"q":"एक केंटकी आवेदक को CDL स्किल्स परीक्षण किस प्रकार के वाहन में लेना होगा?","options":["उस वर्ग/प्रकार के वाहन में जिसे चलाने के लिए आवेदक लाइसेंस प्राप्त करना चाहता है","10,001 pounds से अधिक वज़न वाला कोई भी वाणिज्यिक वाहन","परीक्षण स्टेशन द्वारा प्रदान की गई एक मानक यात्री कार","मांगे गए लाइसेंस वर्ग की परवाह किए बिना एक Class C वाहन"],"explanation":"आवेदकों को स्किल्स परीक्षण उस वर्ग और प्रकार के प्रतिनिधि वाहन में लेना होगा जिसके लिए वे लाइसेंस प्राप्त करना चाहते हैं। स्रोत: 2025 Kentucky CDL Manual; 49 CFR 383.71।"},"91":{"q":"परमिट या लाइसेंस जारी होने से पहले एक प्रथम-बार केंटकी CDL आवेदक के पास कौन-से दस्तावेज़ फ़ाइल पर होने चाहिए?","options":["CDL आवेदन, स्व-प्रमाणन फ़ॉर्म, और एक सुपाठ्य DOT Medical Examiner's Certificate","केवल एक Social Security card और एक दृष्टि जाँच परिणाम","एक नियोक्ता पत्र और एक वाहन पंजीकरण","एक पासपोर्ट और एक FMCSA clearinghouse सदस्यता"],"explanation":"CLP या CDL जारी होने से पहले, केंटकी को CDL आवेदन, स्व-प्रमाणन (TC 94-169), और DOT Medical Examiner's Certificate की एक सुपाठ्य प्रति की आवश्यकता होती है, ये सभी KYTC को जमा किए जाते हैं (mycdl.ky.gov के माध्यम से)। स्रोत: KYTC प्रथम-बार आवेदक जानकारी; drive.ky.gov।"},"92":{"q":"यदि आवेदक के स्किल्स परीक्षण पास करने से पहले एक केंटकी CLP की समय-सीमा समाप्त हो जाती है, तो आमतौर पर क्या होता है?","options":["आवेदक को एक नया CLP प्राप्त करने के लिए आवश्यक ज्ञान परीक्षण फिर से लेने होंगे","CLP स्वचालित रूप से अगले 180 days के लिए बढ़ा दिया जाता है","स्किल्स परीक्षण के अंक दो वर्षों तक आगे बढ़ते रहते हैं","आवेदक 30-दिन की छूट अवधि के भीतर स्किल्स परीक्षण ले सकता है"],"explanation":"केंटकी 180-day CLP को नहीं बढ़ाता; यदि स्किल्स परीक्षण पास होने से पहले इसकी समय-सीमा समाप्त हो जाती है, तो आवेदक को एक नया CLP जारी कराने के लिए ज्ञान परीक्षण फिर से लेने होंगे। स्रोत: 2025 Kentucky CDL Manual; KRS 281A.120।"},"93":{"q":"केंटकी CDL सामान्य ज्ञान परीक्षण पर न्यूनतम उत्तीर्ण अंक क्या है?","options":["80 प्रतिशत सही","70 प्रतिशत सही","75 प्रतिशत सही","90 प्रतिशत सही"],"explanation":"एक आवेदक को प्रत्येक CDL ज्ञान परीक्षण पास करने के लिए कम से कम 80 प्रतिशत अंक प्राप्त करने होंगे, यह संघीय मानक है जो केंटकी में लागू होता है। स्रोत: 2025 Kentucky CDL Manual; 49 CFR 383.135।"},"94":{"q":"इंट्रास्टेट (केंटकी के भीतर) वाणिज्य तक सीमित एक केंटकी CDL जारी करने के लिए न्यूनतम आयु क्या है?","options":["18 वर्ष","21 वर्ष","19 वर्ष","16 वर्ष"],"explanation":"केंटकी में इंट्रास्टेट ड्राइविंग के लिए CDL रखने हेतु व्यक्ति की आयु कम से कम 18 वर्ष होनी चाहिए; इंटरस्टेट ड्राइविंग और हैज़मैट/स्कूल बस संचालन के लिए 21 वर्ष आवश्यक है। स्रोत: KRS 281A; 2025 Kentucky CDL Manual।"},"95":{"q":"एक केंटकी CDL पर इंटरस्टेट वाणिज्य में एक वाणिज्यिक मोटर वाहन संचालित करने के लिए आवश्यक न्यूनतम आयु क्या है?","options":["21 वर्ष","18 वर्ष","19 वर्ष","25 वर्ष"],"explanation":"इंटरस्टेट वाणिज्य में संचालन के लिए चालकों की आयु कम से कम 21 वर्ष होनी चाहिए; 18 से 20 वर्ष के लोगों को एक इंट्रास्टेट (केवल-केंटकी) प्रतिबंध मिलता है। स्रोत: KRS 281A; 2025 Kentucky CDL Manual; 49 CFR 391.11।"},"96":{"q":"जब एक केंटकी CDL धारक एक नई DOT चिकित्सा परीक्षा कराता है, तो CDL को 'certified' स्थिति में बनाए रखने के लिए चालक को क्या करना होगा?","options":["अद्यतन Medical Examiner's Certificate को mycdl.ky.gov के माध्यम से KYTC को जमा करना ताकि ड्राइविंग रिकॉर्ड वर्तमान बना रहे","प्रमाणपत्र को केवल केबिन में रखना और पूछे जाने पर पुलिस को दिखाना","प्रमाणपत्र को राज्य के बजाय FMCSA National Registry को डाक से भेजना","प्रमाणपत्र को फिर से वैध करने के लिए ज्ञान परीक्षण दोबारा लेना"],"explanation":"'not certified' में डाउनग्रेड होने से बचने के लिए, चालक को प्रत्येक नया Medical Examiner's Certificate KYTC को जमा करना होगा, आमतौर पर mycdl.ky.gov पोर्टल के माध्यम से, ताकि यह CDLIS ड्राइविंग रिकॉर्ड में पोस्ट हो जाए। स्रोत: KYTC प्रथम-बार आवेदक जानकारी; 49 CFR 383.71/383.73।"},"97":{"q":"एक केंटकी CDL के नवीनीकरण के बारे में मेल/ऑनलाइन प्रक्रिया के संबंध में कौन-सा कथन सही है?","options":["एक CDL को आमतौर पर मेल द्वारा नवीनीकृत नहीं किया जा सकता और इसके लिए व्यक्तिगत रूप से नवीनीकरण की आवश्यकता होती है","एक CDL स्वचालित रूप से नवीनीकृत होता है और बिना किसी आवेदन के मेल किया जाता है","एक CDL को हमेशा बिना किसी दस्तावेज़ के ऑनलाइन नवीनीकृत किया जा सकता है","चालक के स्किल्स परीक्षण पास करने के बाद CDL की समय-सीमा कभी समाप्त नहीं होती"],"explanation":"Class A, B, या C (CDL) क्रेडेंशियल को आमतौर पर मेल द्वारा नवीनीकृत नहीं किया जा सकता; वर्तमान चिकित्सा प्रमाणन के साथ व्यक्तिगत रूप से नवीनीकरण की आवश्यकता होती है। स्रोत: KRS 281A.170; KYTC drive.ky.gov।"}},"ar":{"0":{"q":"على الطرق السريعة بين الولايات والطرق السريعة المحددة في كنتاكي، ما هو الحد الأقصى القانوني لعرض المركبة التجارية (باستثناء ملحقات السلامة المعتمدة مثل المرايا)؟","options":["8 أقدام و3 بوصات (99 بوصة)","8 أقدام و6 بوصات (102 بوصة)","8 أقدام و0 بوصة (96 بوصة)","9 أقدام و0 بوصة (108 بوصة)"],"explanation":"تحدّ كنتاكي عرض المركبة عند 8 أقدام و6 بوصات (102 بوصة) على الطرق السريعة بين الولايات والطرق السريعة المحددة، بما يتوافق مع 23 CFR 658. المصدر: صفحة الأبعاد القانونية لدى Kentucky DRIVE (KYTC)؛ KRS 189.221/189.222."},"1":{"q":"ما هو الحد الأقصى القانوني لعرض المركبة على الطرق السريعة في كنتاكي التي تتولى الولاية صيانتها والتي ليست طرقاً سريعة بين الولايات أو طرقاً سريعة محددة بخلاف ذلك؟","options":["8 أقدام (96 بوصة)","8 أقدام و6 بوصات (102 بوصة)","7 أقدام و6 بوصات (90 بوصة)","9 أقدام (108 بوصة)"],"explanation":"على الطرق غير المحددة التي تتولى الولاية صيانتها في كنتاكي ينخفض العرض القانوني إلى 8 أقدام (96 بوصة)؛ ولا ينطبق السماح بـ 8 أقدام و6 بوصات إلا على نظام الطرق السريعة بين الولايات والطرق السريعة المحددة. المصدر: صفحة الأبعاد القانونية لدى Kentucky DRIVE (KYTC)؛ KRS 189.221."},"2":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة على الطرق السريعة في كنتاكي قبل اشتراط الحصول على تصريح للأبعاد الزائدة؟","options":["14 قدماً و0 بوصة","14 قدماً و6 بوصات","13 قدماً و0 بوصة","13 قدماً و6 بوصات"],"explanation":"تحدّد كنتاكي الحد الأقصى القانوني لارتفاع المركبة والحمولة عند 13 قدماً و6 بوصات؛ وأي ارتفاع أعلى من ذلك يتطلب تصريحاً للأبعاد الزائدة. المصدر: صفحة الأبعاد القانونية لدى Kentucky DRIVE (KYTC)؛ KRS 189.222."},"3":{"q":"ما هو الحد الأقصى القانوني لطول المقطورة النصفية الواحدة التي تعمل على نظام الطرق السريعة بين الولايات والطرق السريعة المحددة في كنتاكي؟","options":["45 قدماً","57 قدماً","53 قدماً","48 قدماً"],"explanation":"يجوز أن يصل طول المقطورة النصفية الواحدة إلى 53 قدماً على الطرق السريعة بين الولايات والطرق السريعة المحددة في كنتاكي. المصدر: صفحة الأبعاد القانونية لدى Kentucky DRIVE (KYTC)؛ KRS 189.221/189.222."},"4":{"q":"في تركيبة المقطورتين التوأم (المزدوجة) العاملة في كنتاكي، ما هو الحد الأقصى القانوني لطول كل مقطورة على حدة؟","options":["26 قدماً لكل منها","28 قدماً لكل منها","30 قدماً لكل منها","32 قدماً لكل منها"],"explanation":"تسمح كنتاكي بمقطورتين توأم/مزدوجتين بطول يصل إلى 28 قدماً لكل منها، بما يتوافق مع البُعد المزدوج المحمي اتحادياً. المصدر: صفحة الأبعاد القانونية لدى Kentucky DRIVE (KYTC)؛ KRS 189.222."},"5":{"q":"ما هو الحد الأقصى القانوني لطول الشاحنة الآلية أحادية الوحدة على الطرق السريعة في كنتاكي؟","options":["45 قدماً","53 قدماً","48 قدماً","40 قدماً"],"explanation":"تقتصر الشاحنة الآلية أحادية الوحدة على طول 45 قدماً بموجب قواعد الأبعاد في كنتاكي. المصدر: صفحة الأبعاد القانونية لدى Kentucky DRIVE (KYTC)؛ KRS 189.221."},"6":{"q":"على الطرق السريعة في كنتاكي التي تتولى الولاية صيانتها والتي ليست جزءاً من النظام المحدد، ما هو الحد الأقصى للطول الإجمالي لتركيبة جرّار الشاحنة والمقطورة؟","options":["75 قدماً","70 قدماً","60 قدماً","65 قدماً"],"explanation":"على الطرق غير المحددة التي تتولى الولاية صيانتها يُحدّ الطول الإجمالي للتركيبة عند 65 قدماً، رغم أن المقطورة النصفية بطول 53 قدماً مسموح بها على الطرق السريعة المحددة. المصدر: صفحة الأبعاد القانونية لدى Kentucky DRIVE (KYTC)؛ KRS 189.221."},"7":{"q":"ما هو الحد الأقصى القانوني للوزن الإجمالي للمركبة التجارية وحمولتها على الطرق السريعة في كنتاكي دون تصريح للوزن الزائد؟","options":["84,000 رطل","88,000 رطل","80,000 رطل","73,280 رطلاً"],"explanation":"تحدّ كنتاكي الوزن الإجمالي الكلي للمركبة عند 80,000 رطل، بما يتوافق مع المعيار الاتحادي للطرق بين الولايات. المصدر: KRS 189.222؛ 603 KAR 5:066؛ Kentucky DRIVE (KYTC)."},"8":{"q":"ما هو الحد الأقصى القانوني للوزن الذي يمكن حمله على محور واحد في كنتاكي؟","options":["22,400 رطل","20,000 رطل","18,000 رطل","24,000 رطل"],"explanation":"لا يجوز أن يتجاوز أي محور واحد 20,000 رطل في كنتاكي (أو 700 رطل لكل بوصة من العرض الإجمالي للإطارات، أيهما أقل). المصدر: KRS 189.222؛ 603 KAR 5:066."},"9":{"q":"ما هو الحد الأقصى القانوني للوزن على مجموعة المحاور المزدوجة (المحاور المتباعدة من 42 إلى 96 بوصة) في كنتاكي؟","options":["34,000 رطل","36,000 رطل","40,000 رطل","32,000 رطل"],"explanation":"تقتصر مجموعة المحاور المزدوجة المتباعدة من 42 إلى 96 بوصة على 34,000 رطل في كنتاكي. المصدر: KRS 189.222؛ 603 KAR 5:066؛ الأبعاد القانونية لدى Kentucky DRIVE (KYTC)."},"10":{"q":"في كنتاكي، ما هو الحد الأقصى القانوني للوزن على مجموعة ثلاثية (ثلاثة محاور) متباعدة من 42 إلى 120 بوصة؟","options":["45,000 رطل","42,000 رطل","51,000 رطل","48,000 رطل"],"explanation":"يُسمح لمجموعة المحاور الثلاثية المتباعدة بين 42 و120 بوصة بما يصل إلى 48,000 رطل في كنتاكي. المصدر: KRS 189.222؛ صفحة الأبعاد القانونية لدى Kentucky DRIVE (KYTC)."},"11":{"q":"تسمح كنتاكي بهامش سماح في أوزان المحاور، لكن فقط على طرق معينة. على أي طرق سريعة ينطبق هامش السماح في وزن المحور البالغ 5 بالمئة؟","options":["الطرق التي تتولى المقاطعة صيانتها فقط","جميع الطرق السريعة بما في ذلك نظام الطرق بين الولايات","الطرق السريعة التي تتولى الولاية صيانتها والتي ليست جزءاً من نظام الطرق بين الولايات","نظام الطرق بين الولايات فقط"],"explanation":"تسمح كنتاكي بهامش سماح لا يزيد عن 5 بالمئة في وزن المحور على الطرق السريعة التي تتولى الولاية صيانتها والتي ليست جزءاً من نظام الطرق بين الولايات؛ ولا ينطبق أي هامش سماح للمحور على الطرق بين الولايات. المصدر: KRS 189.222."},"12":{"q":"بموجب قانون كنتاكي، كيف ينطبق هامش السماح في الوزن البالغ 5 بالمئة على الوزن الإجمالي للمركبة؟","options":["ينطبق هامش سماح بنسبة 5 بالمئة على الطرق بين الولايات فقط","لا يُسمح بأي هامش سماح في الوزن الإجمالي","ينطبق هامش سماح بنسبة 10 بالمئة على الطرق غير الواقعة بين الولايات","ينطبق هامش سماح بنسبة 5 بالمئة على جميع الطرق"],"explanation":"تسمح كنتاكي صراحةً بعدم وجود أي هامش سماح في الوزن الإجمالي؛ وينطبق هامش السماح البالغ 5 بالمئة فقط على أوزان المحاور على الطرق السريعة غير الواقعة بين الولايات التي تتولى الولاية صيانتها. المصدر: KRS 189.222."},"13":{"q":"تستخدم كنتاكي صيغة الجسر الاتحادية للحدّ من الوزن على مجموعات المحاور المتتالية. ما الذي تربط الصيغة الوزن الإجمالي به بشكل أساسي؟","options":["عدد المحاور والمسافة (البُعد) بينها","عدد الإطارات وضغط الهواء فيها","قدرة المحرك الحصانية ومعدّل الوزن الإجمالي للتركيبة","طول المقطورة وكثافة الحمولة"],"explanation":"تحدّ صيغة الجسر الاتحادية W=500(LN/(N-1)+12N+36) من الوزن على أي مجموعة من محورين متتاليين أو أكثر بناءً على عدد المحاور (N) والمسافة (L) بين المحاور القصوى للمجموعة. وتطبّقها كنتاكي عبر اعتماد 23 CFR Part 658. المصدر: 23 CFR 658.17؛ KRS 189.222."},"14":{"q":"في صيغة الجسر الاتحادية W = 500(LN/(N-1) + 12N + 36) المستخدمة في كنتاكي، ماذا يمثّل المتغير 'L'؟","options":["الوزن القانوني للحمولة بالأطنان","قدرة الرفع للتعليق","طول المقطورة بالأقدام","المسافة بالأقدام بين المحاور القصوى للمجموعة"],"explanation":"في صيغة الجسر، L هي المسافة بالأقدام بين أقصى محورين في أي مجموعة من محورين متتاليين أو أكثر، بينما N هي عدد المحاور في تلك المجموعة. المصدر: 23 CFR 658.17 (صيغة الجسر)، المعتمدة في كنتاكي بموجب KRS 189.222."},"15":{"q":"يجوز لمجموعتين متتاليتين من المحاور المزدوجة أن تحمل كل منهما الوزن الكامل البالغ 34,000 رطل في كنتاكي فقط إذا كانت المسافة بين المحور الأول والأخير من تلك المحاور المزدوجة لا تقل عن كم قدماً؟","options":["28 قدماً","40 قدماً","36 قدماً","30 قدماً"],"explanation":"بموجب استثناء صيغة الجسر الذي اعتمدته كنتاكي، يجوز لمجموعتين متتاليتين من المحاور المزدوجة أن تحمل كل منهما 34,000 رطل فقط عندما تكون المسافة الإجمالية بين المحور الأول والأخير لتلك المحاور المزدوجة 36 قدماً أو أكثر. المصدر: 23 CFR 658.17؛ KRS 189.222."},"16":{"q":"متى يُشترط الحصول على تصريح كنتاكي للحجم الزائد/الوزن الزائد (OS/OW)؟","options":["فقط عند السفر على طرق المقاطعات","قبل تحريك أي مركبة أو حمولة تتجاوز الحدود القانونية للعرض أو الارتفاع أو الطول أو الوزن","فقط عندما يتجاوز الوزن الإجمالي 90,000 رطل","فقط عندما يكون عرض الحمولة أكثر من 10 أقدام"],"explanation":"يجب الحصول على تصريح كنتاكي قبل تحريك أي مركبة أو حمولة تتجاوز الحدود القانونية النظامية للعرض أو الارتفاع أو الطول أو الوزن. المصدر: KYTC Division of Motor Carriers؛ 601 KAR 1:018."},"17":{"q":"أي جهة في كنتاكي تصدر تصاريح خاصة لحمولات المركبات الآلية ذات الوزن الزائد/الأبعاد الزائدة، وما الذي لا يمكن عموماً أن يحصل على مثل هذا التصريح؟","options":["KYTC Division of Motor Carriers؛ الحمولات القابلة للتجزئة بشكل معقول لا يمكن عادةً منحها تصريحاً","U.S. DOT؛ يمكن منح التصريح للحمولات بين الولايات فقط","شرطة ولاية كنتاكي؛ يمكن منح التصريح للحمولات الزراعية فقط","محاكم المقاطعات المالية؛ يمكن منح التصريح لمنتجات الغابات فقط"],"explanation":"تصدر Division of Motor Carriers التابعة لـ Kentucky Transportation Cabinet تصاريح OS/OW بموجب 601 KAR 1:018، ولا تُصدر التصاريح عموماً للحمولات القابلة للتجزئة بشكل معقول (التي يمكن تفكيكها أو تقسيمها لتلبية الحدود القانونية). المصدر: 601 KAR 1:018؛ KRS 189.270."},"18":{"q":"توفّر كنتاكي تنازلاً خاصاً للمعدات الزراعية غير القابلة للتجزئة. ماذا يتيح هذا؟","options":["يجوز للمعدات الزراعية السفر بأي عرض دون تصريح على الطرق ذات المسارين","يجوز للمعدات الزراعية تجاوز 120,000 رطل على الطرق بين الولايات دون تصريح","تُعفى المعدات الزراعية من جميع قواعد التصريح والوزن على مستوى الولاية","يجوز إصدار تصريح لرحلة واحدة للمعدات الزراعية غير القابلة للتجزئة التي تتجاوز حدود الوزن أو الأبعاد القانونية"],"explanation":"تصدر كنتاكي تصريحاً لرحلة واحدة للوزن الزائد/الأبعاد الزائدة لنقل المعدات الزراعية غير القابلة للتجزئة التي تتجاوز الحدود الواردة في KRS 189.222 أو 189.270؛ وهو تنازل مرخّص وليس إعفاءً شاملاً. المصدر: 601 KAR 1:019؛ 601 KAR 1:018."},"19":{"q":"بموجب نظام طرق نقل الفحم ذي الوزن الممتد في كنتاكي (ECWHRS)، ما هو الحد الأقصى للوزن الإجمالي الذي يمكن أن يعمل به جرّار-مقطورة نصفية بخمسة محاور أو أكثر ينقل الفحم؟","options":["90,000 رطل (مع هامش سماح 5 بالمئة)","80,000 رطل (دون هامش سماح)","120,000 رطل (مع هامش سماح 5 بالمئة)","100,000 رطل (مع هامش سماح 10 بالمئة)"],"explanation":"على نظام طرق نقل الفحم ذي الوزن الممتد، يجوز لجرّار-مقطورة نصفية بخمسة محاور أو أكثر ينقل الفحم أو منتجاته الثانوية أن يعمل بوزن إجمالي يصل إلى 120,000 رطل مع هامش سماح 5 بالمئة. المصدر: KRS 177.9771."},"20":{"q":"في كنتاكي، يُشترط الحصول على رخصة CDL من الفئة A لتشغيل أي تركيبة من المركبات بمعدّل وزن إجمالي للتركيبة (GCWR) يبلغ 26,001 رطل أو أكثر، شريطة أن يتجاوز معدّل الوزن الإجمالي (GVWR) للمركبة (المركبات) المقطورة أي وزن؟","options":["10,000 رطل","26,001 رطل","16,000 رطل","1,000 رطل"],"explanation":"تشترط كنتاكي رخصة CDL من الفئة A للتركيبات بمعدّل GCWR يبلغ 26,001 رطل أو أكثر عندما يكون معدّل GVWR للوحدة (الوحدات) المقطورة أكثر من 10,000 رطل. المصدر: دليل CDL في كنتاكي (KYTC، مارس 2025)، 'Who Must Apply? - Class A CDL.'"},"21":{"q":"بموجب قواعد كنتاكي، يُشترط الحصول على رخصة CDL من الفئة B لقيادة أي مركبة واحدة بمعدّل وزن إجمالي للمركبة (GVWR) لا يقل عن كم رطلاً؟","options":["10,001 رطل","26,001 رطل","33,000 رطل","16,001 رطل"],"explanation":"تشمل رخصة CDL من الفئة B أي مركبة واحدة بمعدّل GVWR يبلغ 26,001 رطل أو أكثر، بما في ذلك مثل هذه المركبة وهي تقطر وحدة بمعدّل GVWR يبلغ 10,000 رطل أو أقل. المصدر: دليل CDL في كنتاكي (KYTC، مارس 2025)، 'Class B CDL.'"},"22":{"q":"وفقاً لدليل CDL في كنتاكي، تتطلب المركبة بمعدّل GVWR أقل من 26,001 رطل رخصة CDL من الفئة C عندما تكون مصممة لنقل ما لا يقل عن كم شخصاً، بما في ذلك السائق؟","options":["15","24","16","9"],"explanation":"تشترط كنتاكي رخصة CDL من الفئة C لمركبة بمعدّل GVWR أقل من 26,001 رطل تنقل 16 راكباً أو أكثر بما في ذلك السائق، أو تنقل مواد خطرة تستوجب وضع لافتات. المصدر: دليل CDL في كنتاكي (KYTC، مارس 2025)، 'Class C CDL.'"},"23":{"q":"في كنتاكي، أي فئة من رخصة CDL تنطبق على مركبة بمعدّل GVWR أقل من 26,001 رطل تنقل مواد خطرة بكميات تستوجب وضع لافتات؟","options":["الفئة A","الفئة B","الفئة D","الفئة C"],"explanation":"تشمل رخصة CDL من الفئة C المركبات بمعدّل GVWR أقل من 26,001 رطل التي تنقل مواد خطرة تستوجب وضع لافتات أو 16 راكباً فأكثر (بما في ذلك السائق). المصدر: دليل CDL في كنتاكي (KYTC، مارس 2025)، 'Class C CDL.'"},"24":{"q":"ما هو الحد الأدنى للعمر الذي يجوز عنده لكنتاكي إصدار رخصة CDL مقصورة على التجارة داخل الولاية (مع قيد 'K')؟","options":["21 عاماً","18 عاماً","19 عاماً","16 عاماً"],"explanation":"يجوز لكنتاكي إصدار رخصة CDL خاصة بفئة معينة مع قيد 'K' (داخل الولاية فقط) لشخص يتراوح عمره بين 18 و20 عاماً يستوفي متطلبات الاختبار ولا يقود حافلة مدرسية أو ينقل مواد خطرة. المصدر: دليل CDL في كنتاكي (KYTC، مارس 2025)، 'Individual Eighteen (18) Years of Age Driving Intrastate.'"},"25":{"q":"يجب أن يبلغ حامل رخصة CDL في كنتاكي الذي يرغب في قيادة مركبة آلية تجارية في التجارة بين الولايات (عبر حدود الولايات، دون قيد) من العمر على الأقل كم عاماً؟","options":["18 عاماً","19 عاماً","21 عاماً","25 عاماً"],"explanation":"يقتصر السائقون من سن 18 إلى 20 على التجارة داخل ولاية كنتاكي (قيد 'K')؛ ويجب أن يبلغ السائق 21 عاماً للعمل دون ذلك القيد في التجارة بين الولايات. المصدر: دليل CDL في كنتاكي (KYTC، مارس 2025)، قسم العمر للتجارة داخل الولاية."},"26":{"q":"بعد إصدار تصريح تعليم CDL في كنتاكي (CLP)، كم من الوقت يجب أن يحتفظ مقدّم الطلب بالتصريح قبل إجراء اختبار المهارات؟","options":["30 يوماً","10 أيام","60 يوماً","14 يوماً"],"explanation":"يجب الاحتفاظ بالتصريح لمدة 14 يوماً قبل إجراء اختبار المهارات، بما يتوافق مع قاعدة CLP الاتحادية. المصدر: دليل CDL في كنتاكي (KYTC، مارس 2025)، 'How to Apply for a CDL.'"},"27":{"q":"ما هي مدة صلاحية تصريح تعليم CDL في كنتاكي (CLP)؟","options":["6 أشهر","12 شهراً","30 يوماً","180 يوماً قابلة للتجديد إلى ما لا نهاية"],"explanation":"يكون تصريح تعليم CDL في كنتاكي صالحاً لمدة ستة (6) أشهر. ويجوز تجديده مرة واحدة فقط قبل أن يضطر مقدّم الطلب إلى إعادة التقديم. المصدر: دليل CDL في كنتاكي (KYTC، مارس 2025)، 'How to Apply for a CDL' وقسم ELDT."},"28":{"q":"كم مرة يجوز تجديد تصريح تعليم CDL في كنتاكي قبل أن يضطر مقدّم الطلب إلى إعادة التقديم (ودفع جميع الرسوم وإعادة الاختبارات الكتابية)؟","options":["مرتين","لا يمكن تجديده","مرة واحدة","مرات غير محدودة"],"explanation":"يجوز تجديد تصريح CDL في كنتاكي مرة واحدة فقط؛ وإذا لم يُجتَز اختبار المهارات على الطريق قبل انتهاء صلاحية التصريح المجدّد، يجب على مقدّم الطلب إعادة التقديم مع جميع الرسوم والاختبارات الكتابية. المصدر: دليل CDL في كنتاكي (KYTC، مارس 2025)، 'Entry Level Driver Training (ELDT).'"},"29":{"q":"أي تظهير يُشترط على رخصة CDL في كنتاكي لقيادة مركبة مصممة لنقل الركاب، مثل حافلة النقل العام أو حافلة الرحلات؟","options":["S (حافلة مدرسية)","N (صهريج)","T (مزدوجة/ثلاثية)","P (ركاب)"],"explanation":"يُشترط تظهير P (ركاب) لنقل الركاب؛ ويتطلب إضافته اجتياز اختبار مهارات كامل في مركبة ركاب من الفئة المطلوبة. المصدر: دليل CDL في كنتاكي (KYTC، مارس 2025)، 'Endorsements' و'Adding a Passenger endorsement.'"},"30":{"q":"لقيادة حافلة مدرسية في كنتاكي، يجب على حامل رخصة CDL الحصول على تظهير S (حافلة مدرسية) بالإضافة إلى أي تظهير آخر؟","options":["P (ركاب)","N (صهريج)","H (مواد خطرة)","T (مزدوجة/ثلاثية)"],"explanation":"يجب أن يحمل سائقو الحافلات المدرسية تظهير الحافلة المدرسية (S) بالإضافة إلى تظهير الركاب (P)، ويجب أن يجتازوا اختباراً للمعرفة إضافةً إلى جميع أجزاء اختبار المهارات الثلاثة في فئة الحافلة المدرسية التي ستُقاد. المصدر: دليل CDL في كنتاكي (KYTC، مارس 2025)، قسم تظهير الحافلة المدرسية."},"31":{"q":"في اختبارات معرفة CDL في كنتاكي، كم سؤالاً يحتوي اختبار تظهير المواد الخطرة (H)؟","options":["20 سؤالاً","30 سؤالاً","50 سؤالاً","25 سؤالاً"],"explanation":"يحتوي اختبار معرفة تظهير المواد الخطرة في كنتاكي على 30 سؤالاً، بينما تحتوي اختبارات تظهير المزدوجة/الثلاثية والصهريج والركاب والحافلة المدرسية على 20 سؤالاً لكل منها. المصدر: دليل CDL في كنتاكي (KYTC، مارس 2025)، 'Endorsements are required for the following vehicles.'"},"32":{"q":"قبل إصدار أو تجديد تظهير المواد الخطرة (H) في كنتاكي، يجب على مقدّم الطلب إكمال أخذ البصمات وفحص خلفية أمني تعالجه FBI وأي وكالة اتحادية؟","options":["Federal Motor Carrier Safety Administration (FMCSA)","Department of Homeland Security Coast Guard","Federal Highway Administration (FHWA)","Transportation Security Administration (TSA)"],"explanation":"تؤخذ بصمات مقدّمي طلبات المواد الخطرة ويُرسَل الطلب إلى FBI وإلى Transportation Security Administration (TSA) لإجراء تقييم للتهديد الأمني قبل الاختبار. ويمكن أن تكون بطاقة TWIC إثباتاً على التقييم. المصدر: دليل CDL في كنتاكي (KYTC، مارس 2025)، قسم تظهير المواد الخطرة."},"33":{"q":"أي تظهير CDL في كنتاكي يُشترط لقطر مقطورات مزدوجة أو ثلاثية؟","options":["T","N","H","X"],"explanation":"يُشترط تظهير T (مزدوجة/ثلاثية) لقطر المقطورات المزدوجة أو الثلاثية ويتطلب اجتياز اختبار معرفة من 20 سؤالاً. المصدر: دليل CDL في كنتاكي (KYTC، مارس 2025)، 'Endorsements.'"},"34":{"q":"أي تظهير يحتاجه سائق CDL في كنتاكي لنقل السوائل أو الغازات في مركبة صهريج سائبة (ناقلة صهريج)؟","options":["T (مزدوجة/ثلاثية)","N (صهريج)","P (ركاب)","H (مواد خطرة)"],"explanation":"يُشترط تظهير N (صهريج) لتشغيل مركبة صهريج تنقل حمولة سائبة سائلة أو غازية، ويتطلب اختبار معرفة من 20 سؤالاً. المصدر: دليل CDL في كنتاكي (KYTC، مارس 2025)، 'Endorsements.'"},"35":{"q":"اعتباراً من 7 فبراير 2022، يجب إكمال تدريب السائق المبتدئ الاتحادي (ELDT) في كنتاكي قبل الحصول على رخصة CDL من الفئة A أو B لأول مرة، ويجب أن يأتي التدريب من مزوّد مدرج أين؟","options":["قائمة اختبار شرطة ولاية كنتاكي","أي قائمة لمكتب KYTC الإقليمي","FMCSA Training Provider Registry","غرفة مقاصة CDLIS"],"explanation":"يجب إكمال ELDT بموجب 49 CFR part 380 قبل الحصول على رخصة CDL من الفئة A/B لأول مرة، أو الترقية، أو أول تظهير H أو P أو S، باستخدام مزوّد مدرج على FMCSA Training Provider Registry. المصدر: دليل CDL في كنتاكي (KYTC، مارس 2025)، 'Entry Level Driver Training (ELDT).'"},"36":{"q":"لأي مما يلي لا تشترط كنتاكي تدريب السائق المبتدئ (ELDT) قبل إضافته لأول مرة؟","options":["تظهير H (مواد خطرة)","تظهير N (صهريج)","تظهير P (ركاب)","تظهير S (حافلة مدرسية)"],"explanation":"يُشترط ELDT للحصول على رخصة CDL من الفئة A/B لأول مرة، وللترقية، ولأول تظهير H أو P أو S؛ وتظهير الصهريج (N) ليس مدرجاً في قائمة ELDT. المصدر: دليل CDL في كنتاكي (KYTC، مارس 2025)، 'Entry Level Driver Training (ELDT)'؛ 49 CFR part 380."},"37":{"q":"أي فئة من فئات التصديق الذاتي الطبي ينبغي أن يختارها مقدّم طلب CDL في كنتاكي إذا كان يعمل أو يتوقع العمل داخل كنتاكي فقط (داخل الولاية) ولا يُستثنى من المتطلبات الطبية؟","options":["مستثنى داخل الولاية (EA)","غير مستثنى بين الولايات (NI)","مستثنى بين الولايات (EI)","غير مستثنى داخل الولاية (NA)"],"explanation":"يختار السائق الذي يعمل في كنتاكي فقط ويجب أن يكون معتمداً طبياً فئة غير مستثنى داخل الولاية (NA). ولا تُستخدم خانة مستثنى داخل الولاية (EA) في كنتاكي لأن جميع حاملي رخص CDL في كنتاكي يجب أن يكونوا معتمدين طبياً. المصدر: نموذج التصديق الذاتي لرخصة السائق التجارية لدى KYTC (TC 94-169)؛ 601 KAR 1:005."},"38":{"q":"في نموذج التصديق الذاتي لرخصة CDL في كنتاكي، أي فئة تصديق طبي غير متاحة وينبغي ألا تُختار أبداً لأن جميع حاملي رخص CDL في كنتاكي يجب أن يكونوا معتمدين طبياً؟","options":["مستثنى داخل الولاية (EA)","غير مستثنى بين الولايات (NI)","مستثنى بين الولايات (EI)","غير مستثنى داخل الولاية (NA)"],"explanation":"لا تسمح كنتاكي بفئة مستثنى داخل الولاية (EA)؛ فكل حامل رخصة CDL في كنتاكي يجب أن يكون معتمداً طبياً، لذا يجب ألا تُؤشَّر EA أبداً. أما الفئات الثلاث الأخرى (NI، EI، NA) فهي خيارات صحيحة. المصدر: نموذج التصديق الذاتي لرخصة السائق التجارية لدى KYTC (TC 94-169)؛ 601 KAR 1:005."},"39":{"q":"على رخصة CDL في كنتاكي، ماذا يشير رمز القيد 'K'؟","options":["ممنوع تشغيل مركبة آلية تجارية مزوّدة بمكابح هوائية","ممنوع نقل حمولة في مركبة صهريج","التشغيل داخل الولاية (كنتاكي فقط)","ممنوع نقل ركاب في حافلة مركبة آلية تجارية"],"explanation":"يقصر القيد 'K' حامل الرخصة على التجارة داخل ولاية كنتاكي وينطبق على السائقين دون 21 عاماً وغيرهم ممن يقتصرون على القيادة داخل الولاية. (للمرجع، X = ممنوع نقل حمولة في صهريج، L = ممنوع مكابح هوائية، P = ممنوع نقل ركاب في حافلة مركبة آلية تجارية.) المصدر: دليل CDL في كنتاكي (KYTC، مارس 2025)، 'Restrictions.'"},"40":{"q":"أثناء تشغيل مركبة آلية تجارية (CMV) في كنتاكي، ما هو تركيز الكحول في الدم (BAC) الذي يمثّل العتبة القانونية التي يُعتبر عندها السائق قائداً تحت التأثير ويُجرَّد من أهليته؟","options":["0.04 أو أكثر","0.08 أو أكثر","0.02 أو أكثر","0.10 أو أكثر"],"explanation":"تحدّد كنتاكي حد BAC للمركبة الآلية التجارية عند 0.04 أو أكثر، أي نصف حد 0.08 للسائقين العاديين. وتشغيل مركبة آلية تجارية عند 0.04 أو أعلى هو مخالفة كبرى تستوجب التجريد من الأهلية. المصدر: دليل CDL في كنتاكي (KYTC)، KRS 281A.190؛ 49 CFR 383.51."},"41":{"q":"في كنتاكي، تؤدي أول إدانة بمخالفة كبرى (مثل القيادة تحت التأثير في مركبة آلية تجارية) إلى تجريد رخصة CDL من الأهلية لأي مدة؟","options":["سنة واحدة","60 يوماً","6 أشهر","3 سنوات"],"explanation":"تجرّد أول مخالفة كبرى السائق من الأهلية لمدة سنة واحدة (3 سنوات إذا كان ينقل مواد خطرة موضوعة عليها لافتات في ذلك الوقت). المصدر: دليل CDL في كنتاكي (KYTC)، KRS 281A.190؛ 49 CFR 383.51 Table 1."},"42":{"q":"إذا ارتكب حامل رخصة CDL في كنتاكي أول مخالفة كبرى أثناء نقل مواد خطرة موضوعة عليها لافتات، فإن مدة التجريد من الأهلية تزداد إلى أي مدة؟","options":["3 سنوات","سنة واحدة","5 سنوات","سنتان"],"explanation":"ترفع أول مخالفة كبرى أثناء نقل مواد خطرة موضوعة عليها لافتات مدة التجريد من الأهلية من سنة واحدة إلى 3 سنوات. المصدر: دليل CDL في كنتاكي (KYTC)، KRS 281A.190؛ 49 CFR 383.51 Table 1."},"43":{"q":"بموجب قانون الموافقة الضمنية في كنتاكي، يُعتبر السائق بتشغيله مركبة آلية تجارية قد وافق على فحص كيميائي لأي مواد؟","options":["الدم أو النَّفَس أو البول للكشف عن الكحول أو المخدرات","النَّفَس فقط للكشف عن الكحول","الدم فقط للكشف عن المخدرات","البول فقط للكشف عن المواد الخاضعة للرقابة"],"explanation":"يعتبر قانون الموافقة الضمنية في كنتاكي كل مشغّل لمركبة آلية تجارية موافقاً على فحص الدم أو النَّفَس أو البول للكشف عن الكحول أو المواد الخاضعة للرقابة عندما يكون لدى الضابط سبب معقول. المصدر: دليل CDL في كنتاكي (KYTC)، KRS 281A.150/281A.190."},"44":{"q":"في كنتاكي، ماذا يحدث لحامل رخصة CDL الذي يرفض الخضوع لفحص كيميائي مطلوب للنَّفَس أو الدم أو البول؟","options":["يُعامَل كمخالفة كبرى — تجريد من الأهلية لمدة سنة واحدة على الأقل","تحذير فقط عند الرفض الأول","تجريد من الأهلية لمدة 60 يوماً","تعليق لمدة 30 يوماً وغرامة"],"explanation":"يُعدّ رفض الفحص بحد ذاته مخالفة كبرى، ويحمل نفس التجريد من الأهلية الخاص بإدانة القيادة تحت التأثير: سنة واحدة على الأقل (3 سنوات إذا كانت مواد خطرة موضوعة عليها لافتات). المصدر: دليل CDL في كنتاكي (KYTC)، KRS 281A.190؛ 49 CFR 383.51 Table 1."},"45":{"q":"يُدان حامل رخصة CDL في كنتاكي بمخالفة كبرى ثانية في حادثة منفصلة. ما هي مدة التجريد من الأهلية؟","options":["تجريد من الأهلية مدى الحياة","10 سنوات","5 سنوات","3 سنوات"],"explanation":"تؤدي المخالفة الكبرى الثانية في حادثة منفصلة إلى تجريد رخصة CDL من الأهلية مدى الحياة. المصدر: دليل CDL في كنتاكي (KYTC)، KRS 281A.190؛ 49 CFR 383.51 Table 1."},"46":{"q":"بعد كم سنة قد يصبح السائق المجرَّد من الأهلية مدى الحياة في كنتاكي مؤهلاً محتملاً لإعادة الترخيص، شريطة استيفاء متطلبات الأهلية مثل إكمال برنامج تأهيل معتمد؟","options":["10 سنوات","5 سنوات","7 سنوات","15 سنة"],"explanation":"يجوز للولاية إعادة ترخيص سائق مجرَّد من الأهلية مدى الحياة بعد ما لا يقل عن 10 سنوات إذا أكمل الشخص برنامج تأهيل معتمد؛ وبعض جنايات المخدرات/الاتجار لا تكون مؤهلة أبداً. المصدر: دليل CDL في كنتاكي (KYTC)؛ 49 CFR 383.51."},"47":{"q":"حتى دون مستوى التجريد من الأهلية البالغ 0.04، ماذا يحدث لسائق مركبة آلية تجارية في كنتاكي يُكتشف وجود أي كمية قابلة للكشف من الكحول في جسمه؟","options":["يُوضَع خارج الخدمة لمدة 24 ساعة","يُجرَّد من الأهلية فوراً لمدة سنة واحدة","يُغرَّم 100 دولار دون أي إجراء آخر","يُمنَح تجريداً من الأهلية لمدة 60 يوماً"],"explanation":"يُوضَع السائق الذي لديه أي كمية قابلة للقياس من الكحول دون 0.04 خارج الخدمة لمدة 24 ساعة. والوصول إلى 0.04 أو أعلى هو مخالفة كبرى. المصدر: دليل CDL في كنتاكي (KYTC)؛ 49 CFR 392.5."},"48":{"q":"في كنتاكي، تؤدي الإدانة بمخالفتين مروريتين خطيرتين في مركبة آلية تجارية خلال فترة 3 سنوات (حادثتان منفصلتان) إلى تجريد من الأهلية لأي مدة؟","options":["60 يوماً","30 يوماً","120 يوماً","90 يوماً"],"explanation":"تؤدي مخالفتان مروريتان خطيرتان خلال 3 سنوات (حادثتان منفصلتان) إلى تجريد من الأهلية لمدة 60 يوماً. المصدر: دليل CDL في كنتاكي (KYTC)، KRS 281A.190؛ 49 CFR 383.51 Table 2."},"49":{"q":"في كنتاكي، تؤدي الإدانة بثلاث مخالفات مرورية خطيرة في مركبة آلية تجارية خلال فترة 3 سنوات (حوادث منفصلة) إلى تجريد من الأهلية لأي مدة؟","options":["120 يوماً","60 يوماً","180 يوماً","سنة واحدة"],"explanation":"تؤدي ثلاث مخالفات مرورية خطيرة خلال 3 سنوات (حوادث منفصلة) إلى تجريد من الأهلية لمدة 120 يوماً، يُنفَّذ بالتتابع مع حالات التجريد الأخرى. المصدر: دليل CDL في كنتاكي (KYTC)، KRS 281A.190؛ 49 CFR 383.51 Table 2."},"50":{"q":"أي مما يلي يُصنَّف كمخالفة مرورية خطيرة لحامل رخصة CDL في كنتاكي؟","options":["تجاوز السرعة بمقدار 15 mph أو أكثر فوق الحد المُعلَن","تجاوز السرعة بمقدار 5 mph فوق الحد المُعلَن","مخالفة وقوف واحدة","القيادة بملصق تسجيل منتهي الصلاحية"],"explanation":"يُعدّ تجاوز السرعة المفرط (15 mph أو أكثر فوق الحد) مخالفة مرورية خطيرة، إلى جانب القيادة المتهورة وتغيير المسارات بشكل غير سليم والاقتراب الشديد والرسائل النصية واستخدام الهاتف المحمول باليد. المصدر: دليل CDL في كنتاكي (KYTC)، KRS 281A.190؛ 49 CFR 383.51 Table 2."},"51":{"q":"لأغراض CDL في كنتاكي، كيف تُعامَل الرسائل النصية أثناء قيادة مركبة آلية تجارية عند الاحتساب لأغراض التجريد من الأهلية؟","options":["كمخالفة مرورية خطيرة","كمخالفة كبرى","كمخالفة خارج الخدمة","لا تترتب عليها أي عاقبة على رخصة CDL"],"explanation":"تُعدّ الرسائل النصية أثناء قيادة مركبة آلية تجارية مخالفة مرورية خطيرة؛ واثنتان منها خلال 3 سنوات تجلبان تجريداً من الأهلية لمدة 60 يوماً وثلاث تجلب 120 يوماً. المصدر: دليل CDL في كنتاكي (KYTC)؛ 49 CFR 383.51 و49 CFR 392.80."},"52":{"q":"استخدام هاتف محمول يُمسك باليد أثناء قيادة مركبة آلية تجارية في كنتاكي محظور ويُحتسب لأغراض التجريد من أهلية رخصة CDL على أنه أي نوع من المخالفات؟","options":["مخالفة مرورية خطيرة","مخالفة كبرى","مخالفة معبر سكة حديد","مخالفة أمر خارج الخدمة"],"explanation":"يُعدّ استخدام الهاتف المُمسك باليد أثناء قيادة مركبة آلية تجارية مخالفة مرورية خطيرة؛ واثنتان منها خلال 3 سنوات تؤديان إلى تجريد من الأهلية لمدة 60 يوماً، وثلاث تؤدي إلى 120 يوماً. المصدر: دليل CDL في كنتاكي (KYTC)؛ 49 CFR 383.51 و49 CFR 392.82."},"53":{"q":"تؤدي أول إدانة بمخالفة معبر سكة الحديد مع الطريق السريع في مركبة آلية تجارية إلى تجريد رخصة CDL في كنتاكي من الأهلية لمدة لا تقل عن كم؟","options":["60 يوماً","30 يوماً","120 يوماً","سنة واحدة"],"explanation":"تحمل أول مخالفة لمعبر سكة الحديد تجريداً من الأهلية لا يقل عن 60 يوماً. المصدر: دليل CDL في كنتاكي (KYTC)، KRS 281A.190؛ 49 CFR 383.51 Table 3."},"54":{"q":"تؤدي مخالفة ثانية لمعبر سكة الحديد مع الطريق السريع خلال فترة 3 سنوات إلى تجريد رخصة CDL في كنتاكي من الأهلية لمدة لا تقل عن كم؟","options":["120 يوماً","60 يوماً","180 يوماً","سنة واحدة"],"explanation":"تحمل المخالفة الثانية لمعبر سكة الحديد خلال 3 سنوات تجريداً من الأهلية لا يقل عن 120 يوماً. المصدر: دليل CDL في كنتاكي (KYTC)، KRS 281A.190؛ 49 CFR 383.51 Table 3."},"55":{"q":"تؤدي مخالفة ثالثة أو لاحقة لمعبر سكة الحديد مع الطريق السريع خلال فترة 3 سنوات إلى تجريد رخصة CDL في كنتاكي من الأهلية لمدة لا تقل عن كم؟","options":["سنة واحدة","120 يوماً","180 يوماً","60 يوماً"],"explanation":"تحمل المخالفة الثالثة أو اللاحقة لمعبر سكة الحديد خلال 3 سنوات تجريداً من الأهلية لا يقل عن سنة واحدة. المصدر: دليل CDL في كنتاكي (KYTC)، KRS 281A.190؛ 49 CFR 383.51 Table 3."},"56":{"q":"أي مما يلي يُعدّ مخالفة معبر سكة حديد يمكن أن تجرّد حامل رخصة CDL في كنتاكي من الأهلية؟","options":["القيادة إلى معبر دون مساحة كافية لاجتيازه بالكامل","التوقف على بُعد 50 قدماً قبل القضبان للتحقق من القطارات","إبطاء السرعة والتحقق من خلوّ القضبان","إفساح الطريق لقطار له حق الأولوية"],"explanation":"يُعدّ العبور دون مساحة كافية لاجتياز القضبان مخالفة، وكذلك عدم الإبطاء/التحقق، وعدم التوقف عند الاقتضاء، وعدم وجود خلوص كافٍ أسفل المركبة. المصدر: دليل CDL في كنتاكي (KYTC)؛ 49 CFR 383.51 Table 3."},"57":{"q":"حامل رخصة CDL في كنتاكي الذي يخالف أمر إخراج من الخدمة للمرة الأولى (دون مواد خطرة، دون ركاب) يُجرَّد من الأهلية لمدة لا تقل عن كم؟","options":["180 يوماً","60 يوماً","90 يوماً","سنة واحدة"],"explanation":"تحمل أول مخالفة لأمر الإخراج من الخدمة تجريداً من الأهلية لا يقل عن 180 يوماً (حتى سنة واحدة). المصدر: دليل CDL في كنتاكي (KYTC)، KRS 281A.190؛ 49 CFR 383.51 Table 4."},"58":{"q":"بالنسبة لمخالفة ثانية لأمر الإخراج من الخدمة خلال فترة 10 سنوات، يُجرَّد حامل رخصة CDL في كنتاكي من الأهلية لمدة لا تقل عن كم؟","options":["سنتان","180 يوماً","سنة واحدة","3 سنوات"],"explanation":"تحمل المخالفة الثانية لأمر الإخراج من الخدمة خلال 10 سنوات تجريداً من الأهلية لا يقل عن سنتين (حتى 5 سنوات). المصدر: دليل CDL في كنتاكي (KYTC)، KRS 281A.190؛ 49 CFR 383.51 Table 4."},"59":{"q":"تؤدي مخالفة ثالثة أو لاحقة لأمر الإخراج من الخدمة خلال فترة 10 سنوات إلى تجريد رخصة CDL في كنتاكي من الأهلية لمدة لا تقل عن كم؟","options":["3 سنوات","سنتان","سنة واحدة","5 سنوات"],"explanation":"تحمل المخالفة الثالثة أو اللاحقة لأمر الإخراج من الخدمة خلال 10 سنوات تجريداً من الأهلية لا يقل عن 3 سنوات (حتى 5 سنوات). المصدر: دليل CDL في كنتاكي (KYTC)، KRS 281A.190؛ 49 CFR 383.51 Table 4."},"60":{"q":"بموجب قانون كنتاكي 'خفّف السرعة، وانتقل جانبًا' (Slow Down, Move Over)، عندما يقترب سائق حاصل على CDL من مركبة طوارئ أو مركبة سلامة عامة متوقفة وتعرض أضواءً وامضة على طريق سريع متعدد المسارات، فما هو الالتزام الأول للسائق إذا أمكن القيام به بأمان؟","options":["الاستمرار بالسرعة المعلنة مع البقاء في المسار نفسه","التوقف توقفًا تامًا حتى تغادر مركبة الطوارئ","إخلاء المسار الأقرب إلى المركبة المتوقفة بالانتقال مسارًا واحدًا","إطلاق المنبه لتنبيه المستجيبين إلى أن الشاحنة تقترب"],"explanation":"يُلزم قانون كنتاكي للانتقال جانبًا (KRS 189.930) السائق على طريق به مساران أو أكثر في الاتجاه نفسه بإخلاء المسار الأقرب إلى مركبة طوارئ/سلامة عامة متوقفة تعرض أضواءً وامضة عندما يكون ذلك آمنًا. المصدر: KRS 189.930؛ دليل CDL لولاية كنتاكي."},"61":{"q":"على طريق سريع في كنتاكي ذي مسارين حيث لا يستطيع السائق الانتقال جانبًا بأمان لإفساح الطريق لمركبة طوارئ متوقفة بأضواء وامضة، ماذا يُلزم قانون الانتقال جانبًا السائق بفعله بدلًا من ذلك؟","options":["تخفيض السرعة إلى مستوى آمن بالنسبة للطريق والطقس وظروف المرور","التوقف توقفًا تامًا على بُعد 500 قدم قبل مركبة الطوارئ","تشغيل الأضواء الوامضة الرباعية والحفاظ على حد السرعة","الانحراف إلى الكتف والانتظار حتى تتم الإشارة بالمرور"],"explanation":"بموجب KRS 189.930، إذا كان تغيير المسارات مستحيلًا أو غير آمن، فيجب على السائق أن يخفّف السرعة إلى سرعة آمنة بالنسبة لظروف الطريق والطقس والمرور القائمة وأن يتابع بحذر. المصدر: KRS 189.930."},"62":{"q":"وسّعت كنتاكي قانون الانتقال جانبًا في يوليو 2024. إلى جانب الشرطة والإطفاء وسيارات الإسعاف، أصبح القانون الموسّع الآن يُلزم السائقين أيضًا بالانتقال جانبًا أو تخفيف السرعة من أجل أيٍّ مما يلي؟","options":["أي مركبة ثابتة تعرض أضواء التحذير أو إشارات التحذير، بما في ذلك المركبات المعطّلة وشاحنات القطر","فقط دوريات إنفاذ القانون المميّزة بعلامات","فقط المركبات التي تسدّ بشكل فعلي مسار سير","فقط المركبات المملوكة لهيئة النقل في كنتاكي (KYTC)"],"explanation":"وسّع تعديل يوليو 2024 لقانون KRS 189.930 الحماية لتشمل أي مركبة ثابتة تعرض أضواءً وامضة أو أضواء تحذير أو أجهزة تحذير، مثل مركبات القطر/الونش والسائقين الذين تعطّلت مركباتهم، وليس فقط المستجيبين الأوائل التقليديين. المصدر: KRS 189.930 (تعديل 2024)."},"63":{"q":"سائق حاصل على CDL في كنتاكي ينقل حمولة من المواد الخطرة تحمل لوحات تحذير ويقترب من معبر سكة حديد. ضمن أي مسافة من أقرب قضيب سكة يجب على السائق أن يتوقف؟","options":["ليس أقل من 5 أقدام وليس أكثر من 25 قدمًا","ليس أقل من 15 قدمًا وليس أكثر من 50 قدمًا","ليس أقل من 25 قدمًا وليس أكثر من 75 قدمًا","ليس أقل من 50 قدمًا وليس أكثر من 100 قدم"],"explanation":"يجب على سائق مركبة تحمل لوحات تحذير للمواد الخطرة أن يتوقف ضمن 50 قدمًا من أقرب قضيب سكة، ولكن ليس أقرب من 15 قدمًا، قبل العبور (قاعدة '15 إلى 50 قدمًا'). المصدر: 49 CFR 392.10، المعتمدة في كنتاكي؛ دليل CDL لولاية كنتاكي."},"64":{"q":"أيٌّ من هذه المركبات التجارية مُلزَمة بالتوقف عند كل معبر سكة حديد بموجب القواعد المعلَّمة في دليل CDL لولاية كنتاكي؟","options":["مقطورة جرّار مسطحة فارغة","حافلة تقل ركابًا","شاحنة صندوقية تنقل بضائع عامة","شاحنة قلّابة تنقل الحصى"],"explanation":"يجب على الحافلات التي تقل ركابًا والمركبات التي تعرض لوحات تحذير للمواد الخطرة أن تتوقف عند معابر السكك الحديدية، بالتوقف ضمن 15 إلى 50 قدمًا من أقرب قضيب سكة. شاحنات البضائع العامة ليست مُلزَمة بالتوقف إلا إذا اقتضت الإشارات ذلك. المصدر: 49 CFR 392.10؛ دليل CDL لولاية كنتاكي."},"65":{"q":"بموجب قانون حافلات المدارس في كنتاكي، على طريق سريع رباعي المسارات تتوقف حافلة مدرسية وأضواؤها الحمراء وامضة وذراع التوقف ممتدة. أي السائقين غير مُلزَمين بالتوقف؟","options":["السائقون في المسار المجاور للحافلة المتجهون في الاتجاه نفسه","السائقون خلف الحافلة مباشرة في المسار نفسه","جميع السائقين مُلزَمون بالتوقف بغض النظر عن الاتجاه أو عدد المسارات","السائقون القادمون من الاتجاه المعاكس على الطريق السريع ذي الأربعة مسارات أو أكثر"],"explanation":"بموجب KRS 189.370، على طريق سريع من أربعة مسارات أو أكثر، فإن المركبات القادمة من الاتجاه المعاكس لحافلة مدرسية متوقفة ليست مُلزَمة بالتوقف. أما حركة المرور على جانب الحافلة فيجب أن تتوقف. المصدر: KRS 189.370."},"66":{"q":"على طريق سريع قياسي في كنتاكي ذي مسارين، تتوقف حافلة مدرسية وأضواؤها الحمراء وامضة وذراع التوقف ممتدة لتحميل الأطفال. ماذا يجب أن تفعل حركة المرور القادمة من الاتجاه المعاكس؟","options":["تخفيف السرعة إلى 25 ميلًا في الساعة مع إمكانية الاستمرار بالمرور بجوار الحافلة","التوقف والبقاء متوقفة حتى تستأنف الحافلة حركتها","المتابعة بشكل طبيعي لأن الحافلة على الجانب الآخر من خط المنتصف","التوقف فقط إذا كان الأطفال ظاهرين وهم يعبرون الطريق"],"explanation":"على طريق ذي مسارين، يُلزم KRS 189.370 السائقين من كلا الاتجاهين بالتوقف لحافلة مدرسية تقوم بتحميل أو إنزال الركاب مع تشغيل إشاراتها، وبعدم المتابعة حتى تتحرك الحافلة مجددًا. ينطبق استثناء الاتجاه المعاكس فقط على الطرق السريعة من أربعة مسارات أو أكثر. المصدر: KRS 189.370."},"67":{"q":"يستند شرط التوقف لحافلة المدرسة في كنتاكي (واستثناء الاتجاه المعاكس الخاص به) إلى أي خاصية محددة من خصائص الطريق؟","options":["عدد المسارات على الطريق السريع (أربعة أو أكثر)","ما إذا كان حد السرعة 55 ميلًا في الساعة أو أعلى","ما إذا كان الطريق السريع منتزهًا حكوميًا مخصصًا","ما إذا كان حاجز خرساني مادي يفصل بين الاتجاهين"],"explanation":"يربط KRS 189.370 استثناء الاتجاه المعاكس تحديدًا بطريق سريع 'من أربعة (4) مسارات أو أكثر' بدلًا من ربطه بوجود حاجز فاصل أوسطي أو بحد سرعة معين. المصدر: KRS 189.370."},"68":{"q":"يقيّد قانون كنتاكي بعض المركبات الكبيرة من المسار الأقصى يسارًا. على طريق سريع به ثلاثة مسارات أو أكثر تسير في الاتجاه نفسه، أي المركبات يُحظر عليها استخدام المسار الأقصى يسارًا إلا عند التجاوز أو الدخول أو الخروج؟","options":["الدراجات النارية والدراجات الآلية","المركبات الترفيهية والبيوت المتنقلة","جرّارات الشاحنات والمقطورات وأنصاف المقطورات","جميع سيارات الركاب والشاحنات الصغيرة (البيك أب)"],"explanation":"يحظر KRS 189.340 على جرّار الشاحنة أو المقطورة أو نصف المقطورة السير في المسار الأقصى يسارًا على طريق سريع به ثلاثة مسارات أو أكثر في الاتجاه نفسه، إلا عند التجاوز أو الدخول إلى الطريق السريع أو مغادرته أو إفساح الطريق لحركة المرور الداخلة أو عندما تكون المسارات الأخرى غير آمنة. المصدر: KRS 189.340."},"69":{"q":"بموجب قاعدة كنتاكي للمسار الأيسر للشاحنات، أيٌّ مما يلي يُعدّ سببًا صحيحًا لوجود نصف مقطورة قانونيًا في المسار الأقصى يسارًا على طريق سريع بين الولايات ذي ثلاثة مسارات؟","options":["الحفاظ على سرعة انطلاق ثابتة من أجل توفير الوقود","البقاء بعيدًا عن المركبات المندمجة من مداخل الطريق طوال الرحلة","تجاوز مركبة أبطأ، ثم العودة إلى اليمين في أقرب وقت ممكن عمليًا","السير بسرعة أقل قليلًا من حد السرعة للحفاظ على المكابح"],"explanation":"يسمح KRS 189.340 لجرّار الشاحنة/المقطورة/نصف المقطورة باستخدام المسار الأقصى يسارًا فقط لأسباب محدودة مثل التجاوز (ثم العودة إلى اليمين في أقرب وقت ممكن عمليًا) أو الدخول إلى الطريق السريع/مغادرته أو إفساح الطريق لحركة المرور الداخلة أو عندما يكون المسار الأيمن/الأوسط غير آمن. المصدر: KRS 189.340."},"70":{"q":"ما هو الحد الأقصى لسرعة الشاحنات على المقاطع الريفية من الطرق السريعة بين الولايات في كنتاكي مثل I-64 وI-65 وI-75؟","options":["70 ميلًا في الساعة","65 ميلًا في الساعة","60 ميلًا في الساعة","75 ميلًا في الساعة"],"explanation":"تعلن كنتاكي حدًا أقصى قدره 70 ميلًا في الساعة على معظم المقاطع الريفية من الطرق السريعة بين الولايات؛ وينطبق هذا على الشاحنات ما لم يُعلن حد أدنى. أما المقاطع الحضرية (مثل المناطق حول لويزفيل وليكسينغتون) فعادةً ما تكون 65 ميلًا في الساعة. المصدر: KRS 189.390؛ الحدود المعلنة من KYTC."},"71":{"q":"عبر المناطق الحضرية القريبة من لويزفيل وليكسينغتون، فإن حد السرعة على الطريق السريع بين الولايات الذي ينبغي لسائق CDL أن يتوقعه هو الأكثر شيوعًا:","options":["70 ميلًا في الساعة","65 ميلًا في الساعة","45 ميلًا في الساعة","55 ميلًا في الساعة"],"explanation":"في حين أن الطرق السريعة الريفية بين الولايات في كنتاكي تُعلن عمومًا عند 70 ميلًا في الساعة، فإن المقاطع الحضرية من الطرق السريعة بين الولايات حول المناطق الحضرية الكبرى مثل لويزفيل وليكسينغتون تُعلن عادةً عند 65 ميلًا في الساعة. يجب على السائقين دائمًا الالتزام بالحد المعلن. المصدر: KRS 189.390؛ الحدود المعلنة من KYTC."},"72":{"q":"تتعطّل شاحنة سائق حاصل على CDL على كتف طريق سريع في كنتاكي ذي مسارين وباتجاهين خلال النهار. بعد وضع أجهزة التحذير المطلوبة، أين ينبغي وضع المثلثات العاكسة الثلاثة؟","options":["100 قدم خلف المركبة، و100 قدم أمامها، وواحد بجوار المقصورة","10 أقدام خلف المركبة، و100 قدم خلفها، و100 قدم أمامها","25 قدمًا خلف المركبة، و200 قدم خلفها، و200 قدم أمامها","10 أقدام خلف المركبة، و50 قدمًا خلفها، و50 قدمًا أمامها"],"explanation":"على طريق ذي مسارين وباتجاهين، ضع مثلثًا واحدًا ضمن 10 أقدام من المؤخرة، وواحدًا على بُعد نحو 100 قدم خلف المركبة، وواحدًا على بُعد نحو 100 قدم أمامها. المصدر: 49 CFR 392.22، المعتمدة في كنتاكي؛ دليل CDL لولاية كنتاكي."},"73":{"q":"عندما تتوقف مركبة تجارية على طريق سريع ذي اتجاه واحد أو مقسّم في كنتاكي، أين تُوضع أجهزة التحذير الثلاثة بالنسبة إلى حركة المرور القادمة؟","options":["100 قدم خلف المركبة و100 قدم أمامها، بالإضافة إلى واحد عند المقصورة","10 أقدام و100 قدم و200 قدم باتجاه حركة المرور القادمة","200 قدم و200 قدم و500 قدم باتجاه حركة المرور القادمة","10 أقدام و50 قدمًا و100 قدم باتجاه حركة المرور القادمة"],"explanation":"على طريق سريع ذي اتجاه واحد أو مقسّم، ضع أجهزة التحذير على بُعد 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور القادمة في وسط المسار أو الكتف الذي تشغله المركبة. المصدر: 49 CFR 392.22؛ دليل CDL لولاية كنتاكي."},"74":{"q":"بعد توقّف مركبة تجارية معطّلة على طريق في كنتاكي، خلال كم دقيقة يجب على السائق أن يضع أجهزة التحذير الطارئة المطلوبة؟","options":["خلال 10 دقائق","خلال 5 دقائق","خلال 30 دقيقة","خلال 15 دقيقة"],"explanation":"يجب على السائق وضع أجهزة التحذير الثلاثة المطلوبة خلال 10 دقائق من التوقف. المصدر: 49 CFR 392.22، المعتمدة في كنتاكي؛ دليل CDL لولاية كنتاكي."},"75":{"q":"على منحدر طويل مثل جبل باين في كنتاكي (الطريق U.S. 119)، ما هي تقنية الكبح الصحيحة المعلَّمة في دليل CDL لولاية كنتاكي؟","options":["استخدام مكبح الانتظار بشكل متقطع لإبطاء المركبة","النقل إلى وضع الحياد لترك المحرك يبرد والضغط على المكابح بخفة","اختيار ترس منخفض قبل النزول واستخدام كبح خفيف وثابت أو متقطع (snub)","إبقاء أعلى ترس ممكن والضغط المتكرر على المكابح باستمرار"],"explanation":"ينبغي على السائقين اختيار الترس المنخفض المناسب قبل بدء النزول على المنحدر والاعتماد بشكل أساسي على كبح المحرك، مع استخدام مكابح الخدمة بتطبيقات خفيفة ومتقطعة (snub). يؤدي الضغط المستمر على المكابح إلى ارتفاع درجة حرارتها وفقدان فعاليتها. المصدر: دليل CDL لولاية كنتاكي (التحكم في السرعة / القيادة في الجبال)."},"76":{"q":"بدون تصريح للحمولات الكبيرة الحجم في كنتاكي، ما هو الحد الأقصى القانوني للعرض المسموح به لمركبة تجارية وحمولتها على الطرق السريعة المخصصة؟","options":["10 أقدام و0 بوصة","9 أقدام و6 بوصات","8 أقدام و0 بوصة","8 أقدام و6 بوصات"],"explanation":"الحد الأقصى القانوني لعرض المركبة/الحمولة في كنتاكي على الطرق السريعة بين الولايات والطرق المخصصة هو 8 أقدام و6 بوصات (102 بوصة)؛ وأي شيء أعرض من ذلك يتطلب تصريحًا للحمولات الكبيرة الحجم من KYTC. المصدر: KRS الفصل 189؛ تصاريح KYTC للحمولات الزائدة الوزن/الأبعاد."},"77":{"q":"حمولة في كنتاكي يبلغ ارتفاعها 14 قدمًا. بدون تصريح، فإن الحد الأقصى القانوني للارتفاع هو 13 قدمًا و6 بوصات. ما الذي يجب على الناقل الحصول عليه قبل نقل هذه الحمولة؟","options":["إذن من مأمور المقاطعة المحلي فقط","لا شيء، لأن حدود الارتفاع مجرد إرشادية في كنتاكي","تصريح للحمولات الكبيرة الحجم/الزائدة الأبعاد من هيئة النقل في كنتاكي (KYTC)","تصديق المواد الخطرة فقط"],"explanation":"الحد الأقصى القانوني للارتفاع في كنتاكي هو 13 قدمًا و6 بوصات؛ وحمولة بارتفاع 14 قدمًا تتجاوز ذلك وتتطلب تصريحًا للأبعاد الزائدة صادرًا عن قسم الناقلين الآليين في KYTC قبل السفر. المصدر: KRS الفصل 189؛ تصاريح KYTC للحمولات الزائدة الوزن/الأبعاد."},"78":{"q":"لن تصدر كنتاكي عمومًا تصريحًا للحمولات الكبيرة الحجم/الزائدة الوزن لأي نوع من الحمولات؟","options":["قطعة واحدة من الآلات الصناعية لا يمكن تفكيكها","حمولة قابلة للتقسيم بشكل معقول ويمكن إعادة ترتيبها لتتوافق مع الحدود القانونية","محوّل كهربائي كبير يتجاوز الوزن القانوني","قسم مبنى مُسبَق الصنع يتجاوز العرض القانوني"],"explanation":"تصدر كنتاكي تصاريح الحمولات الكبيرة الحجم/الزائدة الوزن (OS/OW) فقط للحمولات غير القابلة للتقسيم؛ ولن تصرّح بحمولة قابلة للتقسيم بشكل معقول (أي يمكن تفكيكها أو إعادة ترتيبها للتوافق مع الحدود القانونية)، إلا بموجب سلطة قانونية محددة. المصدر: تصاريح KYTC للحمولات الزائدة الوزن/الأبعاد؛ KRS الفصل 189."},"79":{"q":"أي جهة في كنتاكي تصدر فعليًا رخصة القيادة التجارية (CDL) للمتقدمين المؤهلين؟","options":["قسم ترخيص السائقين التابع لهيئة النقل في كنتاكي (Kentucky Transportation Cabinet)","شرطة ولاية كنتاكي (Kentucky State Police)","الإدارة الفيدرالية لسلامة الناقلين الآليين (FMCSA)","مكتب الكفالة لكاتب المحكمة الدائرية في المقاطعة"],"explanation":"في كنتاكي تصدر رخصة CDL عن طريق هيئة النقل في كنتاكي (KYTC)، قسم ترخيص السائقين. المصدر: صفحة CDL على KYTC drive.ky.gov؛ دليل CDL لولاية كنتاكي 2025."},"80":{"q":"من الذي يُجري اختبارات المعرفة الخاصة بـ CDL واختبار المهارات على الطريق للمتقدمين في كنتاكي؟","options":["شرطة ولاية كنتاكي (Kentucky State Police)","كاتب المحكمة الدائرية في المقاطعة","مدارس قيادة الشاحنات الخاصة التابعة لطرف ثالث فقط","السجل الوطني لـ FMCSA"],"explanation":"تتولّى شرطة ولاية كنتاكي (KSP) حصريًا مسؤولية إجراء جميع اختبارات المعرفة والمهارات الخاصة بـ CDL في كنتاكي، بينما تصدر KYTC الرخصة. المصدر: دليل CDL لولاية كنتاكي 2025؛ اختبار السائقين لدى شرطة ولاية كنتاكي."},"81":{"q":"لكم يومًا يكون تصريح المتعلم التجاري (CLP) في كنتاكي صالحًا؟","options":["180 يومًا","60 يومًا","365 يومًا","90 يومًا"],"explanation":"يكون CLP في كنتاكي صالحًا لمدة أقصاها 180 يومًا. المصدر: KRS 281A.120؛ دليل CDL لولاية كنتاكي 2025."},"82":{"q":"بعد إصدار CLP، كم يجب أن ينتظر المتقدم قبل أن يخوض اختبار مهارات CDL في كنتاكي؟","options":["14 يومًا على الأقل","30 يومًا على الأقل","7 أيام على الأقل","60 يومًا على الأقل"],"explanation":"يجب على المتقدم أن يحتفظ بـ CLP لمدة 14 يومًا على الأقل قبل أن يصبح مؤهلًا لخوض اختبار مهارات CDL. وهذا معيار فيدرالي مطبّق في كنتاكي. المصدر: دليل CDL لولاية كنتاكي 2025؛ 49 CFR 383.25."},"83":{"q":"كم تبلغ مدة صلاحية رخصة القيادة التجارية في كنتاكي قبل أن يجب تجديدها؟","options":["8 سنوات","4 سنوات","5 سنوات","10 سنوات"],"explanation":"تكون رخصة CDL في كنتاكي صالحة لمدة 8 سنوات. المصدر: KRS 281A.170؛ KYTC drive.ky.gov."},"84":{"q":"أي نموذج هو شهادة الفاحص الطبي التابع لـ DOT التي يجب على المتقدم لـ CDL في كنتاكي الحصول عليها من فاحص طبي معتمد؟","options":["النموذج MCSA-5876","النموذج TC 94-169","النموذج MCSA-5875 فقط","النموذج DOT-391"],"explanation":"شهادة الفاحص الطبي هي النموذج MCSA-5876، الذي يكمله فاحص طبي معتمد من السجل الوطني؛ ويجب أن يكون مسجلًا في ملف حامل CDL. (النموذج TC 94-169 هو نموذج التصديق الذاتي المنفصل.) المصدر: معلومات المتقدم لأول مرة لدى KYTC؛ FMCSA."},"85":{"q":"في التصديق الذاتي لـ CDL في كنتاكي، من بين كم فئة من فئات نوع القيادة يجب على المتقدم أن يختار؟","options":["أربع","اثنتان","ثلاث","خمس"],"explanation":"يحتوي التصديق الذاتي (النموذج TC 94-169) على أربع فئات: بين الولايات غير معفاة، وبين الولايات معفاة، وداخل الولاية غير معفاة، وداخل الولاية معفاة. المصدر: نموذج KYTC TC 94-169؛ 49 CFR 383.71."},"86":{"q":"السائق في كنتاكي الذي يعمل عبر حدود الولايات ويجب أن يستوفي معايير التأهيل البدني الفيدرالية ينبغي أن يصدّق ذاتيًا تحت أي فئة؟","options":["بين الولايات غير معفاة","بين الولايات معفاة","داخل الولاية غير معفاة","داخل الولاية معفاة"],"explanation":"السائقون في التجارة بين الولايات الخاضعون لقواعد التأهيل البدني الفيدرالية يصدّقون كـ 'بين الولايات غير معفاة'، وهو ما يتطلب وجود شهادة فاحص طبي سارية في الملف. المصدر: نموذج KYTC TC 94-169؛ 49 CFR 383.71."},"87":{"q":"قبل أن يتمكن متقدم لأول مرة للفئة A أو الفئة B من خوض اختبار مهارات CDL في كنتاكي، ما هو شرط التدريب الذي يجب استيفاؤه؟","options":["تدريب السائقين المبتدئين (ELDT) من مزوّد مسجّل","تدريب مهني حكومي مدته 160 ساعة برعاية KYTC","دورة قيادة دفاعية لدى كاتب المحكمة الدائرية","سنتان من القيادة الموثّقة داخل الولاية"],"explanation":"يُشترط تدريب السائقين المبتدئين الفيدرالي (ELDT) من مزوّد مدرج في سجل مزوّدي التدريب التابع لـ FMCSA قبل اختبار الفئة A/B لأول مرة (وقبل اختبار تصديق P أو S أو H لأول مرة). المصدر: دليل CDL لولاية كنتاكي 2025؛ 49 CFR الجزء 380."},"88":{"q":"أيٌّ من التصديقات التالية يتطلب إكمال ELDT قبل الاختبار، بالإضافة إلى المتقدمين لأول مرة للفئة A والفئة B؟","options":["المواد الخطرة (H)، والركاب (P)، والحافلة المدرسية (S)","مركبة الصهريج (N) والمزدوجة/الثلاثية (T)","تصديق الحافلة المدرسية (S) فقط","لا يتطلب أي تصديق ELDT"],"explanation":"يُشترط ELDT للمتقدمين لأول مرة لتصديقات المواد الخطرة (H) والركاب (P) والحافلة المدرسية (S)، وكذلك لإصدار الفئة A/B لأول مرة وللترقية من الفئة B إلى A. المصدر: دليل CDL لولاية كنتاكي 2025؛ 49 CFR الجزء 380."},"89":{"q":"يُجرى اختبار مهارات CDL في كنتاكي على ثلاثة أجزاء. أي مجموعة تسرد بشكل صحيح هذه الأجزاء الثلاثة؟","options":["فحص ما قبل الرحلة، والتحكم الأساسي بالمركبة، والقيادة على الطريق","المعرفة الكتابية، وفحص النظر، والقيادة على الطريق","فحص ما قبل الرحلة، والاختبار الكتابي لمكابح الهواء، والرجوع للخلف","التحكم الأساسي بالمركبة، والاختبار الكتابي للمواد الخطرة، والقيادة على الطريق"],"explanation":"يتكوّن اختبار مهارات CDL من ثلاثة أجزاء: فحص ما قبل الرحلة، ومهارات التحكم الأساسي بالمركبة، واختبار القيادة على الطريق. المصدر: دليل CDL لولاية كنتاكي 2025؛ 49 CFR 383.113."},"90":{"q":"في أي نوع من المركبات يجب على المتقدم في كنتاكي أن يخوض اختبار مهارات CDL؟","options":["فئة/نوع المركبة التي ينوي المتقدم الحصول على ترخيص لقيادتها","أي مركبة تجارية يزيد وزنها عن 10,001 رطل","سيارة ركاب قياسية توفّرها محطة الاختبار","مركبة من الفئة C بغض النظر عن فئة الرخصة المطلوبة"],"explanation":"يجب على المتقدمين خوض اختبار المهارات في مركبة تمثيلية من الفئة والنوع اللذين يسعون للترخيص فيهما. المصدر: دليل CDL لولاية كنتاكي 2025؛ 49 CFR 383.71."},"91":{"q":"ما هي المستندات التي يجب أن تكون لدى المتقدم لأول مرة لـ CDL في كنتاكي مسجّلة في الملف قبل إصدار التصريح أو الرخصة؟","options":["طلب CDL، ونموذج التصديق الذاتي، ونسخة واضحة من شهادة الفاحص الطبي التابع لـ DOT","فقط بطاقة الضمان الاجتماعي ونتيجة فحص النظر","خطاب من صاحب العمل وتسجيل المركبة","جواز سفر واشتراك في مقاصة FMCSA"],"explanation":"قبل إصدار CLP أو CDL، تشترط كنتاكي طلب CDL، والتصديق الذاتي (TC 94-169)، ونسخة واضحة من شهادة الفاحص الطبي التابع لـ DOT، وكلها مقدَّمة إلى KYTC (عبر mycdl.ky.gov). المصدر: معلومات المتقدم لأول مرة لدى KYTC؛ drive.ky.gov."},"92":{"q":"إذا انتهت صلاحية CLP في كنتاكي قبل أن يجتاز المتقدم اختبار المهارات، فماذا يحدث عمومًا؟","options":["يجب على المتقدم إعادة خوض اختبارات المعرفة المطلوبة للحصول على CLP جديد","يُمدَّد CLP تلقائيًا لمدة 180 يومًا أخرى","تُرحَّل درجات اختبار المهارات لمدة سنتين","يجوز للمتقدم خوض اختبار المهارات خلال فترة سماح مدتها 30 يومًا"],"explanation":"لا تمدّد كنتاكي مدة CLP البالغة 180 يومًا؛ فإذا انتهت صلاحيته قبل اجتياز اختبار المهارات، فيجب على المتقدم إعادة خوض اختبار(ات) المعرفة للحصول على CLP جديد. المصدر: دليل CDL لولاية كنتاكي 2025؛ KRS 281A.120."},"93":{"q":"ما هي الدرجة الدنيا للنجاح في اختبار المعرفة العامة لـ CDL في كنتاكي؟","options":["80 بالمئة من الإجابات الصحيحة","70 بالمئة من الإجابات الصحيحة","75 بالمئة من الإجابات الصحيحة","90 بالمئة من الإجابات الصحيحة"],"explanation":"يجب على المتقدم الحصول على 80 بالمئة على الأقل لاجتياز كل اختبار معرفة لـ CDL، وهو المعيار الفيدرالي المطبّق في كنتاكي. المصدر: دليل CDL لولاية كنتاكي 2025؛ 49 CFR 383.135."},"94":{"q":"ما هو الحد الأدنى للسن لإصدار CDL في كنتاكي مقتصرة على التجارة داخل الولاية (داخل كنتاكي)؟","options":["18 عامًا","21 عامًا","19 عامًا","16 عامًا"],"explanation":"يجب أن يكون الشخص في الثامنة عشرة من عمره على الأقل لحمل CDL للقيادة داخل الولاية في كنتاكي؛ ويُشترط أن يكون عمره 21 عامًا للقيادة بين الولايات ولتشغيل مركبات المواد الخطرة/الحافلات المدرسية. المصدر: KRS 281A؛ دليل CDL لولاية كنتاكي 2025."},"95":{"q":"ما هو الحد الأدنى للسن المطلوب لتشغيل مركبة آلية تجارية في التجارة بين الولايات بموجب CDL في كنتاكي؟","options":["21 عامًا","18 عامًا","19 عامًا","25 عامًا"],"explanation":"يجب أن يكون عمر السائقين 21 عامًا على الأقل للعمل في التجارة بين الولايات؛ أما من تتراوح أعمارهم بين 18 و20 عامًا فيحصلون على قيد القيادة داخل الولاية (كنتاكي فقط). المصدر: KRS 281A؛ دليل CDL لولاية كنتاكي 2025؛ 49 CFR 391.11."},"96":{"q":"عندما يخضع حامل CDL في كنتاكي لفحص طبي جديد تابع لـ DOT، ماذا يجب على السائق أن يفعل للحفاظ على CDL في حالة 'مصدّقة'؟","options":["تقديم شهادة الفاحص الطبي المحدَّثة إلى KYTC عبر mycdl.ky.gov ليبقى سجل القيادة محدّثًا","الاحتفاظ بالشهادة في المقصورة فقط وإظهارها للشرطة عند الطلب","إرسال الشهادة بالبريد إلى السجل الوطني لـ FMCSA بدلًا من الولاية","إعادة خوض اختبار المعرفة لإعادة التحقق من صحة الشهادة"],"explanation":"لتجنّب خفض الحالة إلى 'غير مصدّقة'، يجب على السائق تقديم كل شهادة فاحص طبي جديدة إلى KYTC، عادةً عبر بوابة mycdl.ky.gov، لتُسجَّل في سجل القيادة لدى CDLIS. المصدر: معلومات المتقدم لأول مرة لدى KYTC؛ 49 CFR 383.71/383.73."},"97":{"q":"أي عبارة بشأن تجديد CDL في كنتاكي صحيحة فيما يتعلق بعملية البريد/الإنترنت؟","options":["لا يمكن عمومًا تجديد CDL بالبريد ويتطلب تجديدًا شخصيًا","يُجدَّد CDL تلقائيًا ويُرسَل بالبريد دون أي طلب","يمكن دائمًا تجديد CDL عبر الإنترنت دون أي مستندات","لا تنتهي صلاحية CDL أبدًا بمجرد أن يجتاز السائق اختبار المهارات"],"explanation":"لا يمكن عمومًا تجديد رخص الفئة A أو B أو C (CDL) بالبريد؛ بل يُشترط تجديد شخصي مع تصديق طبي ساري. المصدر: KRS 281A.170؛ KYTC drive.ky.gov."}}};
